import type { SdEntity, CreateSdEntityInput, UpdateSdEntityInput } from './types';
import type { SdEntityAdapter, PaginatedResult } from './adapter';

// --- Inlined helpers (no external dependencies) ---

function encodeCursor(values: Record<string, unknown>): string {
  return Buffer.from(JSON.stringify(values)).toString('base64url');
}

function decodeCursor(cursor: string): Record<string, unknown> {
  return JSON.parse(Buffer.from(cursor, 'base64url').toString('utf-8')) as Record<string, unknown>;
}

interface MemoryEntry {
  record: SdEntity;
}

export function createMemorySdEntityAdapter(): SdEntityAdapter {
  const store = new Map<string, MemoryEntry>();

  function recordVisible(record: SdEntity): boolean {
    return (record as Record<string, unknown>)['status'] !== 'deleted';
  }

  function applyDefaults(input: CreateSdEntityInput): SdEntity {
    const record = { ...input } as Record<string, unknown>;
    if (record['id'] === undefined) record['id'] = crypto.randomUUID();
    if (record['status'] === undefined) record['status'] = 'active';
    return record as SdEntity;
  }

  function matchesFilter(record: Record<string, unknown>, filter: Record<string, unknown>): boolean {
    for (const [key, val] of Object.entries(filter)) {
      if (val === undefined) continue;
      if (key === 'limit' || key === 'cursor' || key === 'sortDir') continue;
      const rVal = record[key];
      if (rVal instanceof Date && val instanceof Date) {
        if (rVal.getTime() !== val.getTime()) return false;
      } else if (rVal !== val) return false;
    }
    return true;
  }

  const cursorFields = ['id'];

  function compareForSort(a: Record<string, unknown>, b: Record<string, unknown>, sortDir: 'asc' | 'desc'): number {
    for (const f of cursorFields) {
      const aVal = a[f]; const bVal = b[f];
      if (aVal === bVal) continue;
      let cmp = 0;
      if (aVal instanceof Date && bVal instanceof Date) { cmp = aVal.getTime() - bVal.getTime(); }
      else if (typeof aVal === 'number' && typeof bVal === 'number') { cmp = aVal - bVal; }
      else { cmp = String(aVal) < String(bVal) ? -1 : 1; }
      return sortDir === 'desc' ? -cmp : cmp;
    }
    return 0;
  }

  function buildCursorForRecord(record: Record<string, unknown>): string {
    const values: Record<string, unknown> = {};
    for (const f of cursorFields) {
      const val = record[f];
      values[f] = val instanceof Date ? val.toISOString() : val;
    }
    return encodeCursor(values);
  }

  function parseCursorValues(cursor: string): Record<string, unknown> {
    const raw = decodeCursor(cursor);
    return raw;
  }

  return {
    async create(input) {
      if (store.size >= 10000) {
        const firstKey = store.keys().next().value;
        if (firstKey !== undefined) store.delete(firstKey);
      }
      const record = applyDefaults(input);
      const pk = (record as Record<string, unknown>)['id'] as string;
      store.set(pk, { record });
      return { ...record };
    },

    async getById(id, filter) {
      const entry = store.get(id);
      if (!entry) return null;
      if (!recordVisible(entry.record)) return null;
      if (filter && !matchesFilter(entry.record as Record<string, unknown>, filter)) return null;
      return { ...entry.record };
    },

    async update(id, input, filter) {
      const entry = store.get(id);
      if (!entry) return null;
      if (!recordVisible(entry.record)) return null;
      if (filter && !matchesFilter(entry.record as Record<string, unknown>, filter)) return null;
      const updatePayload = input as Record<string, unknown>;
      Object.assign(entry.record, updatePayload);
      return { ...entry.record };
    },

    async delete(id, filter) {
      const entry = store.get(id);
      if (!entry) return false;
      if (!recordVisible(entry.record)) return false;
      if (filter && !matchesFilter(entry.record as Record<string, unknown>, filter)) return false;
      (entry.record as Record<string, unknown>)['status'] = 'deleted';
      return true;
    },

    async list(opts) {
      const sortDir = opts?.sortDir ?? 'asc';
      const rawLimit = opts?.limit ?? 50;
      const limit = Math.min(rawLimit, 200);

      const visible: Array<Record<string, unknown>> = [];
      for (const [pk, entry] of store) {
        if (!recordVisible(entry.record)) continue;
        if (opts && !matchesFilter(entry.record as Record<string, unknown>, opts as Record<string, unknown>)) continue;
        visible.push(entry.record as Record<string, unknown>);
      }

      visible.sort((a, b) => compareForSort(a, b, sortDir));

      let startIdx = 0;
      if (opts?.cursor) {
        const cursorValues = parseCursorValues(opts.cursor);
        const cursorIdx = visible.findIndex(r => {
          for (const f of cursorFields) {
            const rVal = r[f]; const cVal = cursorValues[f];
            if (rVal instanceof Date && cVal instanceof Date) {
              if (rVal.getTime() !== cVal.getTime()) return false;
            } else if (rVal !== cVal) return false;
          }
          return true;
        });
        startIdx = cursorIdx >= 0 ? cursorIdx + 1 : 0;
      }

      const page = visible.slice(startIdx, startIdx + limit + 1);
      const hasMore = page.length > limit;
      const items = page.slice(0, limit).map(r => ({ ...r }) as SdEntity);

      let nextCursor: string | undefined;
      if (hasMore && items.length > 0) {
        nextCursor = buildCursorForRecord(page[limit - 1]);
      }

      return { items, nextCursor, hasMore };
    },

    async clear() { store.clear(); },
  };
}

