import type { Database } from 'bun:sqlite';
import type { Ticket, CreateTicketInput, UpdateTicketInput } from './types';
import type { TicketAdapter, PaginatedResult } from './adapter';

// --- Inlined helpers ---

function encodeCursor(values: Record<string, unknown>): string {
  return Buffer.from(JSON.stringify(values)).toString('base64url');
}

function decodeCursor(cursor: string): Record<string, unknown> {
  return JSON.parse(Buffer.from(cursor, 'base64url').toString('utf-8')) as Record<string, unknown>;
}

function domainToSqlite(val: unknown, fieldName: string): unknown {
  switch (fieldName) {
    case 'metadata': return JSON.stringify(val);
    case 'active': return val ? 1 : 0;
    case 'createdAt': return val instanceof Date ? val.getTime() : val;
    case 'updatedAt': return val instanceof Date ? val.getTime() : val;
    default: return val;
  }
}

function sqliteToDomain(val: unknown, fieldName: string): unknown {
  switch (fieldName) {
    case 'metadata': return typeof val === 'string' ? JSON.parse(val) : val;
    case 'active': return val === 1 || val === true;
    case 'createdAt': return typeof val === 'number' ? new Date(val) : val instanceof Date ? val : new Date(String(val));
    case 'updatedAt': return typeof val === 'number' ? new Date(val) : val instanceof Date ? val : new Date(String(val));
    default: return val;
  }
}

function toRow(record: Record<string, unknown>): Record<string, unknown> {
  const row: Record<string, unknown> = {};
  if (record['id'] !== undefined) row['id'] = domainToSqlite(record['id'], 'id');
  if (record['subject'] !== undefined) row['subject'] = domainToSqlite(record['subject'], 'subject');
  if (record['priority'] !== undefined) row['priority'] = domainToSqlite(record['priority'], 'priority');
  if (record['metadata'] !== undefined) row['metadata'] = domainToSqlite(record['metadata'], 'metadata');
  if (record['active'] !== undefined) row['active'] = domainToSqlite(record['active'], 'active');
  if (record['createdAt'] !== undefined) row['created_at'] = domainToSqlite(record['createdAt'], 'createdAt');
