  if (row['subject'] !== undefined && row['subject'] !== null) record['subject'] = sqliteToDomain(row['subject'], 'subject');
  if (row['priority'] !== undefined && row['priority'] !== null) record['priority'] = sqliteToDomain(row['priority'], 'priority');
  if (row['metadata'] !== undefined && row['metadata'] !== null) record['metadata'] = sqliteToDomain(row['metadata'], 'metadata');
  if (row['active'] !== undefined && row['active'] !== null) record['active'] = sqliteToDomain(row['active'], 'active');
