export function createSqliteTicketAdapter(db: Database): TicketAdapter {
  const table = 'support_tickets';
  let initialized = false;

  function ensureTable(): void {
    if (initialized) return;
    db.run(`CREATE TABLE IF NOT EXISTS ${table} (\n  id TEXT PRIMARY KEY NOT NULL,\n  subject TEXT NOT NULL,\n  priority INTEGER NOT NULL,\n  metadata TEXT,\n  active INTEGER,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n)`);
    initialized = true;
  }

  function applyDefaults(input: CreateTicketInput): Record<string, unknown> {
    const record: Record<string, unknown> = { ...input };
    if (record['id'] === undefined) record['id'] = crypto.randomUUID();
    if (record['createdAt'] === undefined) record['createdAt'] = new Date();
    if (record['updatedAt'] === undefined) record['updatedAt'] = new Date();
    if (record['priority'] === undefined) record['priority'] = 0;
    return record;
  }

  function applyOnUpdate(input: Record<string, unknown>): Record<string, unknown> {
    const result = { ...input };
    result['updatedAt'] = new Date();
    return result;
  }

  const cursorFieldNames = ['id'];
  const cursorColNames = ['id'];

  function buildCursorForRecord(record: Record<string, unknown>): string {
    const values: Record<string, unknown> = {};
    for (const f of cursorFieldNames) {
      const val = record[f];
      values[f] = val instanceof Date ? val.toISOString() : val;
    }
    return encodeCursor(values);
  }

  return {
    async create(input) {
      ensureTable();
      const record = applyDefaults(input);
      const row = toRow(record);
      const columns = Object.keys(row);
      const placeholders = columns.map(() => '?').join(', ');
      const values = columns.map(c => row[c]);
      db.run(`INSERT OR REPLACE INTO ${table} (${columns.join(", ")}) VALUES (${placeholders})`, values);
      return fromRow(row);
    },

    async getById(id, filter) {
      ensureTable();
      const conditions: string[] = ["id = ?"];
      const params: unknown[] = [id];
      if (filter) {
        const filterRow = toRow(filter);
        for (const [col, value] of Object.entries(filterRow)) {
          conditions.push(`${col} = ?`);
          params.push(value);
        }
      }
      const whereClause = conditions.join(' AND ');
      const row = db.query<Record<string, unknown>>(`SELECT * FROM ${table} WHERE ${whereClause}`).get(...params);
      if (!row) return null;
      return fromRow(row);
    },

    async update(id, input, filter) {
      ensureTable();
      const conditions: string[] = ["id = ?"];
      const params: unknown[] = [id];
      if (filter) {
        const filterRow = toRow(filter);
        for (const [col, value] of Object.entries(filterRow)) {
          conditions.push(`${col} = ?`);
          params.push(value);
        }
      }
      const whereClause = conditions.join(' AND ');
      const updatePayload = applyOnUpdate(input as Record<string, unknown>);
      const partial = toRow(updatePayload);
      const entries = Object.entries(partial);
      if (entries.length === 0) {
        const current = db.query<Record<string, unknown>>(`SELECT * FROM ${table} WHERE ${whereClause}`).get(...params);
        return current ? fromRow(current) : null;
      }
      const setClauses = entries.map(([col]) => `${col} = ?`).join(', ');
      const values = [...entries.map(([, v]) => v), ...params];
      const result = db.query<Record<string, unknown>>(`UPDATE ${table} SET ${setClauses} WHERE ${whereClause} RETURNING *`).get(...values);
      return result ? fromRow(result) : null;
    },

    async delete(id, filter) {
      ensureTable();
      const conditions: string[] = ["id = ?"];
      const values: unknown[] = [id];
      if (filter) {
        const filterRow = toRow(filter);
        for (const [col, value] of Object.entries(filterRow)) {
          conditions.push(`${col} = ?`);
          values.push(value);
        }
      }
      const whereClause = conditions.join(' AND ');
      const result = db.query<Record<string, unknown>>(`DELETE FROM ${table} WHERE ${whereClause} RETURNING *`).get(...values);
      return !!result;
    },

    async list(opts) {
      ensureTable();
      const sortDir = opts?.sortDir ?? 'asc';
      const rawLimit = opts?.limit ?? 3;
      const limit = Math.min(rawLimit, 10);
      const conditions: string[] = [];
      const params: unknown[] = [];
      if (opts) {
        for (const [key, val] of Object.entries(opts as Record<string, unknown>)) {
          if (val === undefined) continue;
          if (key === 'limit' || key === 'cursor' || key === 'sortDir') continue;
          const fieldMeta: Record<string, { col: string; type: string }> = {
            'id': { col: 'id', type: 'string' },
            'subject': { col: 'subject', type: 'string' },
            'priority': { col: 'priority', type: 'integer' },
            'metadata': { col: 'metadata', type: 'json' },
            'active': { col: 'active', type: 'boolean' },
            'createdAt': { col: 'created_at', type: 'date' },
            'updatedAt': { col: 'updated_at', type: 'date' },
          };
          const meta = fieldMeta[key];
          if (!meta) continue;
          conditions.push(`${meta.col} = ?`);
          if (meta.type === 'json' || meta.type === 'string[]') params.push(JSON.stringify(val));
          else if (meta.type === 'date') params.push(val instanceof Date ? val.getTime() : val);
          else if (meta.type === 'boolean') params.push(val ? 1 : 0);
          else params.push(val);
        }
      }
      if (opts?.cursor) {
        const cursorValues = decodeCursor(opts.cursor);
        const op = sortDir === 'desc' ? '<' : '>';
        conditions.push(`id ${op} ?`);
        const cv = cursorValues['id'];
        params.push(cv);
      }
      const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
      params.push(limit + 1);
      const rows = db.query<Record<string, unknown>>(`SELECT * FROM ${table} ${where} ORDER BY id ${sortDir === 'desc' ? 'DESC' : 'ASC'} LIMIT ?`).all(...params);

      const hasMore = rows.length > limit;
      const pageRows = rows.slice(0, limit);
      const items = pageRows.map(row => fromRow(row));

      let nextCursor: string | undefined;
      if (hasMore && pageRows.length > 0) {
        nextCursor = buildCursorForRecord(fromRow(pageRows[pageRows.length - 1]) as Record<string, unknown>);
      }

      return { items, nextCursor, hasMore };
    },

    async clear() {
      ensureTable();
      db.run(`DELETE FROM ${table}`);
    },
  };
}

import { mkdir, mkdtemp, rm, writeFile } from 'node:fs/promises';
import { tmpdir } from 'node:os';
import { join } from 'node:path';
import { afterEach, beforeEach, describe, expect, test } from 'bun:test';
import { bunRuntime } from '../src/index';

let tempDir = '';

beforeEach(async () => {
  tempDir = await mkdtemp(join(tmpdir(), 'slingshot-runtime-bun-'));
});

afterEach(async () => {
  if (tempDir) {
    await rm(tempDir, { recursive: true, force: true }).catch(() => {});
    tempDir = '';
  }
});

describe('runtime-bun smoke', () => {
  test('hashes and verifies passwords', async () => {
    const runtime = bunRuntime();
    const hash = await runtime.password.hash('hunter2');

    expect(typeof hash).toBe('string');
    expect(await runtime.password.verify('hunter2', hash)).toBe(true);
    expect(await runtime.password.verify('wrong', hash)).toBe(false);
  });

  test('supports sqlite CRUD, prepared statements, and transactions', () => {
    const runtime = bunRuntime();
    const db = runtime.sqlite.open(join(tempDir, 'runtime.db'));

    db.run('CREATE TABLE items (id TEXT PRIMARY KEY, value TEXT NOT NULL)');
    db.run('INSERT INTO items VALUES (?, ?)', 'a', 'alpha');

    const update = db.prepare<{ value: string }>('UPDATE items SET value = ? WHERE id = ?');
    expect(update.run('beta', 'a').changes).toBe(1);

    const preparedSelect = db.prepare<{ id: string }>('SELECT id FROM items ORDER BY id');

    const transfer = db.transaction(() => {
      db.run('INSERT INTO items VALUES (?, ?)', 'b', 'bravo');
      db.run('INSERT INTO items VALUES (?, ?)', 'c', 'charlie');
    });
    transfer();

    expect(
      db.query<{ id: string; value: string }>('SELECT * FROM items WHERE id = ?').get('a'),
    ).toEqual({ id: 'a', value: 'beta' });
    expect(
      db
        .query<{ id: string }>('SELECT id FROM items ORDER BY id')
        .all()
        .map(row => row.id),
    ).toEqual(['a', 'b', 'c']);
    expect(preparedSelect.all().map(row => row.id)).toEqual(['a', 'b', 'c']);

    db.query('INSERT INTO items VALUES (?, ?)').run('d', 'delta');
    expect(
      db.query<{ value: string }>('SELECT value FROM items WHERE id = ?').get('d')?.value,
    ).toBe('delta');
    expect(
      db.prepare<{ value: string }>('SELECT value FROM items WHERE id = ?').get('missing'),
    ).toBeNull();

    db.close();
  });

  test('reads and writes files and returns null for missing runtime reads', async () => {
    const runtime = bunRuntime();
    const filePath = join(tempDir, 'hello.txt');

    await runtime.fs.write(filePath, 'hello world');
    expect(await runtime.fs.exists(filePath)).toBe(true);

    const bytes = await runtime.fs.readFile(filePath);
    expect(bytes).not.toBeNull();
    expect(new TextDecoder().decode(bytes!)).toBe('hello world');
    expect(await runtime.readFile(filePath)).toBe('hello world');
    expect(await runtime.readFile(join(tempDir, 'missing.txt'))).toBeNull();
  });

  test('scans files with glob support', async () => {
    const runtime = bunRuntime();
    await writeFile(join(tempDir, 'a.ts'), '');
    await writeFile(join(tempDir, 'b.js'), '');
    await mkdir(join(tempDir, 'nested'));
    await writeFile(join(tempDir, 'nested', 'c.ts'), '');

    const matches = await runtime.glob.scan('**/*.ts', { cwd: tempDir });
    expect(matches.map(match => match.replace(/\\/g, '/')).sort()).toEqual(['a.ts', 'nested/c.ts']);
  });

  test('wraps Bun.serve with a usable server instance facade', async () => {
    const runtime = bunRuntime();
    const server = runtime.server.listen({
      port: 0,
      fetch() {
        return new Response('ok');
      },
    });

    try {
      expect(server.port).toBeGreaterThan(0);
      const response = await fetch(`http://127.0.0.1:${server.port}`);
      expect(await response.text()).toBe('ok');
    } finally {
      server.stop(true);
    }
  });

  test('delegates publish and upgrade to the underlying Bun server', () => {
    const originalServe = Bun.serve;
    const publishCalls: Array<{ channel: string; msg: string }> = [];
    const upgradeCalls: Array<{ req: Request; options: { data: unknown } }> = [];

    Object.assign(Bun, {
      serve(options: Parameters<typeof Bun.serve>[0]) {
        return {
          port: undefined,
          stop() {
            return undefined;
          },
          publish(channel: string, msg: string) {
            publishCalls.push({ channel, msg });
          },
          upgrade(req: Request, options: { data: unknown }) {
            upgradeCalls.push({ req, options });
            return true;
          },
        };
      },
    });

    try {
      const runtime = bunRuntime();
      const server = runtime.server.listen({
        port: 4310,
        fetch() {
          return new Response('ok');
        },
      });
      const request = new Request('http://localhost/ws');
      const upgradeOptions = { data: { userId: 'user-1' } };

      expect(server.port).toBe(4310);
      expect(server.upgrade(request, upgradeOptions)).toBe(true);
      server.publish('room:alpha', 'hello');

      expect(upgradeCalls).toEqual([{ req: request, options: upgradeOptions }]);
      expect(publishCalls).toEqual([{ channel: 'room:alpha', msg: 'hello' }]);
    } finally {
      Object.assign(Bun, { serve: originalServe });
    }
  });
});

