import { describe, expect, mock, test } from 'bun:test';
import type { Auth0Deps } from '../../src/providers/auth0Access';
import { createAuth0AccessProvider } from '../../src/providers/auth0Access';

// ---------------------------------------------------------------------------
// Stub helpers
// ---------------------------------------------------------------------------

const DOMAIN = 'test.auth0.com';
const AUDIENCE = 'https://api.example.com';

function makeStubDeps(overrides?: Partial<Auth0Deps>): Auth0Deps {
  return {
    // cast needed: jose's JWKS function type has internal tracking properties
    // (coolingDown, fresh, jwks) that are irrelevant in test stubs
    createRemoteJWKSet: mock(() => (() => Promise.resolve({} as never)) as never) as Auth0Deps['createRemoteJWKSet'],
    // cast needed: jose's JWTVerifyResult requires a `key` field (ResolvedKey) that
    // is not present in test payloads
    jwtVerify: mock(async () => {
      const key: CryptoKey = {} as never;
      return {
        payload: {
          sub: 'auth0|user-123',
          aud: AUDIENCE,
          iss: `https://${DOMAIN}/`,
          email: 'alice@example.com',
          name: 'Alice',
          extra_claim: 'value',
        },
        protectedHeader: { alg: 'RS256' },
        key,
      };
    }) as Auth0Deps['jwtVerify'],
    ...overrides,
  };
}

function makeContext(token?: string): never {
  const ctx: never = {
    req: {
      header: (name: string) => {
        if (name === 'authorization') return token ? `Bearer ${token}` : undefined;
        return undefined;
      },
    },
  } as never;
  return ctx;
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('createAuth0AccessProvider', () => {
  test('verifies a valid JWT and returns principal', async () => {
    const deps = makeStubDeps();
    const provider = createAuth0AccessProvider({ domain: DOMAIN, audience: AUDIENCE }, deps);

    const principal = await provider.verifyRequest(makeContext('valid.jwt.token'));

    expect(principal).not.toBeNull();
    expect(principal?.subject).toBe('auth0|user-123');
    expect(principal?.provider).toBe('auth0');
    expect(principal?.email).toBe('alice@example.com');
    expect(principal?.displayName).toBe('Alice');
  });

  test('includes rawClaims on the principal', async () => {
    const deps = makeStubDeps();
    const provider = createAuth0AccessProvider({ domain: DOMAIN, audience: AUDIENCE }, deps);

    const principal = await provider.verifyRequest(makeContext('valid.jwt.token'));

    expect(principal?.rawClaims).toBeDefined();
    expect((principal?.rawClaims as Record<string, unknown>)['extra_claim']).toBe('value');
  });

  test('returns null when Authorization header is missing', async () => {
    const deps = makeStubDeps();
    const provider = createAuth0AccessProvider({ domain: DOMAIN, audience: AUDIENCE }, deps);

    const principal = await provider.verifyRequest(makeContext());
    expect(principal).toBeNull();
  });

  test('returns null when token is not Bearer-prefixed', async () => {
    const deps = makeStubDeps();
    const provider = createAuth0AccessProvider({ domain: DOMAIN, audience: AUDIENCE }, deps);

    const ctx: never = {
      req: {
        header: (name: string) => (name === 'authorization' ? 'Basic credentials' : undefined),
      },
    } as never;
    const principal = await provider.verifyRequest(ctx);
    expect(principal).toBeNull();
  });

  test('returns null when jwtVerify throws', async () => {
    const deps = makeStubDeps({
      jwtVerify: mock(() => Promise.reject(new Error('Invalid token'))),
    });
    const provider = createAuth0AccessProvider({ domain: DOMAIN, audience: AUDIENCE }, deps);

    const principal = await provider.verifyRequest(makeContext('bad.token'));
    expect(principal).toBeNull();
  });

  test('returns null when sub claim is missing', async () => {
    const deps = makeStubDeps({
      jwtVerify: mock(async () => {
        const key: CryptoKey = {} as never;
        return {
          payload: { aud: AUDIENCE, iss: `https://${DOMAIN}/` },
          protectedHeader: { alg: 'RS256' },
          key,
        };
      }) as Auth0Deps['jwtVerify'],
    });
    const provider = createAuth0AccessProvider({ domain: DOMAIN, audience: AUDIENCE }, deps);

    const principal = await provider.verifyRequest(makeContext('token-without-sub'));
    expect(principal).toBeNull();
  });

  test('provider name is "auth0"', () => {
    const deps = makeStubDeps();
    const provider = createAuth0AccessProvider({ domain: DOMAIN, audience: AUDIENCE }, deps);
    expect(provider.name).toBe('auth0');
  });

  test('createRemoteJWKSet is called once at construction time with the correct URL', () => {
    const deps = makeStubDeps();
    createAuth0AccessProvider({ domain: DOMAIN, audience: AUDIENCE }, deps);
    expect(deps.createRemoteJWKSet).toHaveBeenCalledTimes(1);
    const url = (deps.createRemoteJWKSet as ReturnType<typeof mock>).mock.calls[0]?.[0] as URL;
    expect(url.href).toBe(`https://${DOMAIN}/.well-known/jwks.json`);
  });
});

/**
 * Unit tests for admin typedRoute utilities: registerRoute, createTypedRouter.
 *
 * These are thin type-adapter helpers. Tests verify:
 *   - createTypedRouter returns a router with an openapi method
 *   - registerRoute delegates to router.openapi
 */
import { describe, expect, mock, test } from 'bun:test';
import { createTypedRouter, registerRoute } from '../../src/lib/typedRoute';

// ---------------------------------------------------------------------------
// createTypedRouter
// ---------------------------------------------------------------------------

describe('createTypedRouter', () => {
  test('returns an object (router instance)', () => {
    const router = createTypedRouter();
    expect(router).toBeDefined();
    expect(typeof router).toBe('object');
  });

  test('returned router has an openapi method', () => {
    const router = createTypedRouter();
    expect(typeof router.openapi).toBe('function');
  });

  test('returned router has a route method', () => {
    const router = createTypedRouter();
    expect(typeof router.route).toBe('function');
  });

  test('each call returns a new independent router instance', () => {
    const r1 = createTypedRouter();
    const r2 = createTypedRouter();
    expect(r1).not.toBe(r2);
  });
});

// ---------------------------------------------------------------------------
// registerRoute
// ---------------------------------------------------------------------------

describe('registerRoute', () => {
  test('calls router.openapi with the provided route and handler', () => {
    const openapiMock = mock(() => {});
    const router = { openapi: openapiMock } as any;
    const route = { method: 'get', path: '/test' } as any;
    const handler = mock(() => new Response());

    registerRoute(router, route, handler);

    expect(openapiMock).toHaveBeenCalledWith(route, handler);
  });

  test('forwards the return value of router.openapi', () => {
    const returnValue = { chained: true };
    const router = { openapi: mock(() => returnValue) } as any;
    const result = registerRoute(
      router,
      {} as any,
      mock(() => new Response()),
    );
    // Cast to unknown — the mock returns a plain object but the static return type is
    // OpenAPIHono<AdminEnv>. The test is verifying forwarding behaviour, not the static type.
    expect(result as unknown).toEqual(returnValue);
  });

  test('is called exactly once per registerRoute call', () => {
    const openapiMock = mock(() => {});
    const router = { openapi: openapiMock } as any;
    registerRoute(
      router,
      {} as any,
      mock(() => new Response()),
    );
    expect(openapiMock).toHaveBeenCalledTimes(1);
  });
});

/**
 * Integration tests for the identify middleware.
 *
 * Covers:
 * - Token extraction from cookie and header
 * - JWT verification and session lookup
 * - M2M token detection (scope + no sid)
 * - Session fingerprint binding (all 3 mismatch modes)
 * - Suspension check during identify
 * - Unauthenticated passthrough (always calls next)
 */
import { beforeEach, describe, expect, test } from 'bun:test';
import { Hono } from 'hono';
import type { AppEnv, SlingshotContext } from '@lastshotlabs/slingshot-core';
import { signToken } from '../../src/lib/jwt';
import { createIdentifyMiddleware } from '../../src/middleware/identify';
import { AUTH_RUNTIME_KEY } from '../../src/runtime';
import { makeTestRuntime } from '../helpers/runtime';
import type { MutableTestRuntime } from '../helpers/runtime';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

let runtime: MutableTestRuntime;

function buildApp(signingOverride?: Record<string, unknown>) {
  const signing = signingOverride ?? runtime.signing;
  const app = new Hono<AppEnv>();
  app.use('*', async (c, next) => {
    const ctxPartial = {
      signing,
      pluginState: new Map([[AUTH_RUNTIME_KEY, runtime]]),
    };
    c.set('slingshotCtx', ctxPartial as SlingshotContext);
    await next();
  });
  app.use('*', createIdentifyMiddleware(runtime));
  app.get('/test', c =>
    c.json({
      authUserId: c.get('authUserId'),
      sessionId: c.get('sessionId'),
      authClientId: c.get('authClientId'),
    }),
  );
  return app;
}

beforeEach(() => {
  runtime = makeTestRuntime({});
});

// ---------------------------------------------------------------------------
// Token extraction
// ---------------------------------------------------------------------------

describe('token extraction', () => {
  test('unauthenticated request — all context vars are null', async () => {
    const app = buildApp();
    const res = await app.request('/test');
    expect(res.status).toBe(200);

    const body = await res.json();
    expect(body.authUserId).toBeNull();
    expect(body.sessionId).toBeNull();
    expect(body.authClientId).toBeNull();
  });

  test('valid token in x-user-token header resolves identity', async () => {
    const app = buildApp();
    // Create a user and session
    const { id: userId } = await runtime.adapter.create('test@example.com', 'hash');
    const sessionId = 'sess-test-1';
    const token = await signToken(
      { sub: userId, sid: sessionId },
      3600,
      runtime.config,
      runtime.signing,
    );
    await runtime.repos.session.createSession(userId, token, sessionId, undefined, runtime.config);

    const res = await app.request('/test', {
      headers: { 'x-user-token': token },
    });
    const body = await res.json();
    expect(body.authUserId).toBe(userId);
    expect(body.sessionId).toBe(sessionId);
  });

  test('invalid JWT — treated as unauthenticated, not error', async () => {
    const app = buildApp();
    const res = await app.request('/test', {
      headers: { 'x-user-token': 'not.a.jwt' },
    });
    expect(res.status).toBe(200);

    const body = await res.json();
    expect(body.authUserId).toBeNull();
  });

  test('expired JWT — treated as unauthenticated', async () => {
    const app = buildApp();
    const { id: userId } = await runtime.adapter.create('test@example.com', 'hash');
    // Sign with 0 seconds expiry
    const token = await signToken(
      { sub: userId, sid: 'sess-1' },
      0,
      runtime.config,
      runtime.signing,
    );

    // Wait a moment for it to expire
    await new Promise(r => setTimeout(r, 100));

    const res = await app.request('/test', {
      headers: { 'x-user-token': token },
    });
    const body = await res.json();
    expect(body.authUserId).toBeNull();
  });

  test('token signed with wrong secret — treated as unauthenticated', async () => {
    const app = buildApp();
    const { id: userId } = await runtime.adapter.create('test@example.com', 'hash');
    const token = await signToken({ sub: userId, sid: 'sess-1' }, 3600, runtime.config, {
      secret: 'different-secret-32-chars-long!!',
    });

    const res = await app.request('/test', {
      headers: { 'x-user-token': token },
    });
    const body = await res.json();
    expect(body.authUserId).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// Session mismatch
// ---------------------------------------------------------------------------

describe('session mismatch', () => {
  test('token with valid JWT but no matching session — unauthenticated', async () => {
    const app = buildApp();
    const token = await signToken(
      { sub: 'user-1', sid: 'nonexistent-session' },
      3600,
      runtime.config,
      runtime.signing,
    );

    const res = await app.request('/test', {
      headers: { 'x-user-token': token },
    });
    const body = await res.json();
    expect(body.authUserId).toBeNull();
  });

  test('token with session that stores a different JWT — unauthenticated', async () => {
    const app = buildApp();
    const { id: userId } = await runtime.adapter.create('test@example.com', 'hash');
    const sessionId = 'sess-1';

    // Create session with a different token
    await runtime.repos.session.createSession(
      userId,
      'different-jwt-value',
      sessionId,
      undefined,
      runtime.config,
    );

    // Sign a JWT that references this session but is a different string
    const token = await signToken(
      { sub: userId, sid: sessionId },
      3600,
      runtime.config,
      runtime.signing,
    );

    const res = await app.request('/test', {
      headers: { 'x-user-token': token },
    });
    const body = await res.json();
    // Token/session mismatch — treated as unauthenticated
    expect(body.authUserId).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// M2M token detection
// ---------------------------------------------------------------------------

describe('M2M token detection', () => {
  test('token with scope but no sid — sets authClientId', async () => {
    const app = buildApp();
    const token = await signToken(
      { sub: 'client-123', scope: 'read:data write:data' },
      3600,
      runtime.config,
      runtime.signing,
    );

    const res = await app.request('/test', {
      headers: { 'x-user-token': token },
    });
    const body = await res.json();
    expect(body.authClientId).toBe('client-123');
    expect(body.authUserId).toBeNull();
    expect(body.sessionId).toBeNull();
  });

  test('session token with scope claim does not become an M2M identity', async () => {
    const app = buildApp();
    const { id: userId } = await runtime.adapter.create('scoped-user@example.com', 'hash');
    const sessionId = 'sess-with-scope-1';
    const token = await signToken(
      { sub: userId, sid: sessionId, scope: 'read:data' },
      3600,
      runtime.config,
      runtime.signing,
    );
    await runtime.repos.session.createSession(userId, token, sessionId, undefined, runtime.config);

    const res = await app.request('/test', {
      headers: { 'x-user-token': token },
    });
    const body = await res.json();
    expect(body.authUserId).toBe(userId);
    expect(body.sessionId).toBe(sessionId);
    expect(body.authClientId).toBeNull();
  });
});

// ---------------------------------------------------------------------------
// Fingerprint binding
// ---------------------------------------------------------------------------

describe('session fingerprint binding', () => {
  function buildFingerprintApp(onMismatch: 'unauthenticate' | 'reject' | 'log-only') {
    const signing = {
      ...runtime.signing,
      sessionBinding: { fields: ['ip', 'ua'] as Array<'ip' | 'ua'>, onMismatch },
    };
    (runtime as any).signing = signing;
    return buildApp(signing);
  }

  async function createAuthenticatedSession() {
    const { id: userId } = await runtime.adapter.create('test@example.com', 'hash');
    const sessionId = 'sess-fp-1';
    const token = await signToken(
      { sub: userId, sid: sessionId },
      3600,
      runtime.config,
      runtime.signing,
    );
    await runtime.repos.session.createSession(userId, token, sessionId, undefined, runtime.config);
    return { userId, sessionId, token };
  }

  test('first request stores fingerprint and authenticates', async () => {
    const app = buildFingerprintApp('unauthenticate');
    const { userId, token } = await createAuthenticatedSession();

    const res = await app.request('/test', {
      headers: {
        'x-user-token': token,
        'user-agent': 'TestBrowser/1.0',
      },
    });
    const body = await res.json();
    expect(body.authUserId).toBe(userId);
  });

  test('matching fingerprint on subsequent request — authenticated', async () => {
    const app = buildFingerprintApp('unauthenticate');
    const { userId, token } = await createAuthenticatedSession();

    // First request sets the fingerprint
    await app.request('/test', {
      headers: { 'x-user-token': token, 'user-agent': 'TestBrowser/1.0' },
    });

    // Wait for async fingerprint store
    await new Promise(r => setTimeout(r, 50));

    // Second request with same UA
    const res = await app.request('/test', {
      headers: { 'x-user-token': token, 'user-agent': 'TestBrowser/1.0' },
    });
    const body = await res.json();
    expect(body.authUserId).toBe(userId);
  });

  test('onMismatch=unauthenticate — mismatched UA clears identity', async () => {
    const app = buildFingerprintApp('unauthenticate');
    const { token } = await createAuthenticatedSession();

    // First request sets fingerprint with UA-A
    await app.request('/test', {
      headers: { 'x-user-token': token, 'user-agent': 'BrowserA/1.0' },
    });
    await new Promise(r => setTimeout(r, 50));

    // Second request with different UA
    const res = await app.request('/test', {
      headers: { 'x-user-token': token, 'user-agent': 'CompletelyDifferentBrowser/2.0' },
    });
    const body = await res.json();
    expect(body.authUserId).toBeNull();
  });

  test('onMismatch=reject — mismatched UA throws 401', async () => {
    const app = buildFingerprintApp('reject');
    const { token } = await createAuthenticatedSession();

    app.onError((err, c) => {
      if (err instanceof Error && 'status' in err) {
        return c.json({ error: err.message }, (err as any).status);
      }
      return c.json({ error: 'Internal error' }, 500);
    });

    // First request sets fingerprint
    await app.request('/test', {
      headers: { 'x-user-token': token, 'user-agent': 'BrowserA/1.0' },
    });
    await new Promise(r => setTimeout(r, 50));

    // Second request with different UA → should get 401
    const res = await app.request('/test', {
      headers: { 'x-user-token': token, 'user-agent': 'DifferentBrowser/2.0' },
    });
    expect(res.status).toBe(401);
  });

  test('onMismatch=log-only — mismatched UA still authenticates', async () => {
    const app = buildFingerprintApp('log-only');
    const { userId, token } = await createAuthenticatedSession();

    // First request sets fingerprint
    await app.request('/test', {
      headers: { 'x-user-token': token, 'user-agent': 'BrowserA/1.0' },
    });
    await new Promise(r => setTimeout(r, 50));

    // Second request with different UA — still authenticated in log-only mode
    const res = await app.request('/test', {
      headers: { 'x-user-token': token, 'user-agent': 'DifferentBrowser/2.0' },
    });
    const body = await res.json();
    expect(body.authUserId).toBe(userId);
  });
});

// ---------------------------------------------------------------------------
// Middleware always calls next()
// ---------------------------------------------------------------------------

describe('passthrough behavior', () => {
  test('middleware never short-circuits — always calls next()', async () => {
    const app = buildApp();
    // Replace the test handler to track execution
    app.get('/passthrough', c => {
      return c.json({ ok: true });
    });
    // Mount identify on this path too
    app.use('/passthrough', createIdentifyMiddleware(runtime));

    await app.request('/passthrough', {
      headers: { 'x-user-token': 'garbage-token' },
    });
    // Handler should still be called even with bad token
    // Note: the handler registration order means our /test handler may run instead.
    // The key test is that the response status is 200 (not 401/500).
    const res = await app.request('/test', {
      headers: { 'x-user-token': 'totally-invalid' },
    });
    expect(res.status).toBe(200);
  });
});

/**
 * Integration tests for the password reset flow.
 *
 * Covers:
 * - POST /auth/forgot-password (enumeration-safe, rate-limited, constant-time)
 * - POST /auth/reset-password (token consumption, session revocation, breach check, reuse check)
 */
import { beforeEach, describe, expect, test } from 'bun:test';
import type { ContentfulStatusCode } from 'hono/utils/http-status';
import { HttpError } from '@lastshotlabs/slingshot-core';
import { createLoginRouter } from '../../src/routes/login';
import { createPasswordResetRouter } from '../../src/routes/passwordReset';
import { makeEventBus, makeTestRuntime, wrapWithRuntime } from '../helpers/runtime';
import type { MutableTestRuntime } from '../helpers/runtime';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function buildApp(runtime: MutableTestRuntime) {
  const app = wrapWithRuntime(runtime);
  app.onError((err, c) =>
    c.json(
      { error: err.message },
      (err instanceof HttpError ? err.status : 500) as ContentfulStatusCode,
    ),
  );
  app.route('/', createPasswordResetRouter({ rateLimit: runtime.config as any }, runtime));
  app.route('/', createLoginRouter({ primaryField: 'email' }, runtime));
  return app;
}

const jsonPost = (path: string, body: Record<string, unknown>) =>
  app.request(path, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });

let app: ReturnType<typeof buildApp>;
let runtime: MutableTestRuntime;
let emitted: Array<{ event: string; payload: unknown }>;

// Capture the reset token from the event bus
let capturedResetToken: string | null;

beforeEach(() => {
  runtime = makeTestRuntime({ concealRegistration: null });
  emitted = [];
  capturedResetToken = null;
  runtime.eventBus = {
    ...makeEventBus(event => emitted.push({ event, payload: null })),
    emit: ((event: string, payload: unknown) => {
      emitted.push({ event, payload });
      // Capture reset token from the delivery event
      if (event === 'auth:delivery.password_reset' && payload && typeof payload === 'object') {
        capturedResetToken = (payload as any).token;
      }
    }) as any,
  } as any;
  app = buildApp(runtime);
});

// ---------------------------------------------------------------------------
// POST /auth/forgot-password
// ---------------------------------------------------------------------------

describe('POST /auth/forgot-password', () => {
  test('returns 200 for registered email', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    await runtime.adapter.create('alice@example.com', hash);

    const res = await jsonPost('/auth/forgot-password', { email: 'alice@example.com' });
    expect(res.status).toBe(200);

    const body = await res.json();
    expect(body.message).toContain('If that email is registered');
  });

  test('returns 200 for unregistered email (enumeration-safe)', async () => {
    const res = await jsonPost('/auth/forgot-password', { email: 'nobody@example.com' });
    expect(res.status).toBe(200);

    const body = await res.json();
    expect(body.message).toContain('If that email is registered');
  });

  test('same response shape for registered and unregistered emails', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    await runtime.adapter.create('exists@example.com', hash);

    const res1 = await jsonPost('/auth/forgot-password', { email: 'exists@example.com' });
    const res2 = await jsonPost('/auth/forgot-password', { email: 'ghost@example.com' });

    const body1 = await res1.json();
    const body2 = await res2.json();

    expect(res1.status).toBe(res2.status);
    expect(Object.keys(body1).sort()).toEqual(Object.keys(body2).sort());
  });

  test('emits delivery event for registered email', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    await runtime.adapter.create('alice@example.com', hash);

    await jsonPost('/auth/forgot-password', { email: 'alice@example.com' });

    // Fire-and-forget — wait a tick for the async emit
    await new Promise(r => setTimeout(r, 200));

    const deliveryEvent = emitted.find(e => e.event === 'auth:delivery.password_reset');
    expect(deliveryEvent).toBeDefined();
  });

  test('does NOT emit delivery event for unregistered email', async () => {
    await jsonPost('/auth/forgot-password', { email: 'nobody@example.com' });
    await new Promise(r => setTimeout(r, 200));

    const deliveryEvent = emitted.find(e => e.event === 'auth:delivery.password_reset');
    expect(deliveryEvent).toBeUndefined();
  });

  test('rate-limits by IP when the bucket reaches 5 attempts', async () => {
    for (let i = 0; i < 4; i++) {
      const res = await jsonPost('/auth/forgot-password', { email: `addr${i}@example.com` });
      expect(res.status).toBe(200);
    }

    const res = await jsonPost('/auth/forgot-password', { email: 'addr4@example.com' });
    expect(res.status).toBe(429);
  });

  test('rejects invalid email format', async () => {
    const res = await jsonPost('/auth/forgot-password', { email: 'not-an-email' });
    expect(res.status).toBe(400);
  });
});

// ---------------------------------------------------------------------------
// POST /auth/reset-password
// ---------------------------------------------------------------------------

describe('POST /auth/reset-password', () => {
  test('resets password with valid token', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    await runtime.adapter.create('alice@example.com', hash);

    // Request reset
    await jsonPost('/auth/forgot-password', { email: 'alice@example.com' });
    await new Promise(r => setTimeout(r, 200));
    expect(capturedResetToken).not.toBeNull();

    // Reset password
    const res = await jsonPost('/auth/reset-password', {
      token: capturedResetToken!,
      password: 'NewSecure456!',
    });
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.ok).toBe(true);
  });

  test('can login with new password after reset', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    await runtime.adapter.create('alice@example.com', hash);

    await jsonPost('/auth/forgot-password', { email: 'alice@example.com' });
    await new Promise(r => setTimeout(r, 200));

    await jsonPost('/auth/reset-password', {
      token: capturedResetToken!,
      password: 'NewSecure456!',
    });

    // Old password fails
    const oldRes = await jsonPost('/auth/login', {
      email: 'alice@example.com',
      password: 'OldPass123!',
    });
    expect(oldRes.status).toBe(401);

    // New password works
    const newRes = await jsonPost('/auth/login', {
      email: 'alice@example.com',
      password: 'NewSecure456!',
    });
    expect(newRes.status).toBe(200);
  });

  test('token can only be used once (atomic consumption)', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    await runtime.adapter.create('alice@example.com', hash);

    await jsonPost('/auth/forgot-password', { email: 'alice@example.com' });
    await new Promise(r => setTimeout(r, 200));
    const token = capturedResetToken!;

    // First use succeeds
    const res1 = await jsonPost('/auth/reset-password', { token, password: 'NewPass456!' });
    expect(res1.status).toBe(200);

    // Second use fails (consumed)
    const res2 = await jsonPost('/auth/reset-password', { token, password: 'AnotherPass789!' });
    expect(res2.status).toBe(400);
  });

  test('invalid token returns 400', async () => {
    const res = await jsonPost('/auth/reset-password', {
      token: 'totally-bogus-token',
      password: 'NewSecure456!',
    });
    expect(res.status).toBe(400);
    const body = await res.json();
    expect(body.error).toContain('Invalid or expired');
  });

  test('revokes all sessions after password reset', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    const { id: userId } = await runtime.adapter.create('alice@example.com', hash);

    // Create a session
    await runtime.repos.session.createSession(
      userId,
      'fake-jwt',
      'sess-1',
      undefined,
      runtime.config,
    );
    let sessions = await runtime.repos.session.getUserSessions(userId, runtime.config);
    expect(sessions.length).toBe(1);

    // Reset password
    await jsonPost('/auth/forgot-password', { email: 'alice@example.com' });
    await new Promise(r => setTimeout(r, 200));
    await jsonPost('/auth/reset-password', {
      token: capturedResetToken!,
      password: 'NewSecure456!',
    });

    // Sessions should be revoked
    sessions = await runtime.repos.session.getUserSessions(userId, runtime.config);
    const activeSessions = sessions.filter(s => s.isActive);
    expect(activeSessions.length).toBe(0);
  });

  test('emits password.reset event', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    await runtime.adapter.create('alice@example.com', hash);

    await jsonPost('/auth/forgot-password', { email: 'alice@example.com' });
    await new Promise(r => setTimeout(r, 200));

    await jsonPost('/auth/reset-password', {
      token: capturedResetToken!,
      password: 'NewSecure456!',
    });

    const resetEvent = emitted.find(e => e.event === 'security.auth.password.reset');
    expect(resetEvent).toBeDefined();
  });

  test('weak password rejected by policy', async () => {
    const hash = await Bun.password.hash('OldPass123!');
    await runtime.adapter.create('alice@example.com', hash);

    await jsonPost('/auth/forgot-password', { email: 'alice@example.com' });
    await new Promise(r => setTimeout(r, 200));

    // Password too short / no digit
    const res = await jsonPost('/auth/reset-password', {
      token: capturedResetToken!,
      password: 'short',
    });
    expect(res.status).toBe(400);
  });

  test('rate-limits reset attempts by IP', async () => {
    for (let i = 0; i < 10; i++) {
      await jsonPost('/auth/reset-password', { token: `bogus-${i}`, password: 'NewSecure456!' });
    }

    const res = await jsonPost('/auth/reset-password', {
      token: 'one-more',
      password: 'NewSecure456!',
    });
    expect(res.status).toBe(429);
  });
});

import { describe, expect, test } from 'bun:test';
import { Hono } from 'hono';
import { createBearerAuth } from '../../src/middleware/bearerAuth';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Builds a minimal Hono app with bearerAuth on /protected/* */
function buildApp(config: Parameters<typeof createBearerAuth>[0]) {
  const app = new Hono();
  app.use('/protected/*', createBearerAuth(config));
  app.get('/protected/resource', c => {
    const clientId = (c as any).get('bearerClientId');
    return c.json({ ok: true, ...(clientId ? { clientId } : {}) });
  });
  return app;
}

function req(app: Hono, token?: string) {
  const headers: Record<string, string> = {};
  if (token !== undefined) {
    headers['Authorization'] = token;
  }
  return app.request('/protected/resource', { headers });
}

// ---------------------------------------------------------------------------
// 1. Static secret (string config)
// ---------------------------------------------------------------------------

describe('createBearerAuth — static secret', () => {
  const app = buildApp('my-secret-token');

  test('valid token grants access (200)', async () => {
    const res = await req(app, 'Bearer my-secret-token');
    expect(res.status).toBe(200);
    expect(await res.json()).toEqual({ ok: true });
  });

  test('invalid token is rejected (401)', async () => {
    const res = await req(app, 'Bearer wrong-token');
    expect(res.status).toBe(401);
    expect(await res.json()).toEqual({ error: 'Unauthorized' });
  });

  test('missing Authorization header returns 401', async () => {
    const res = await req(app);
    expect(res.status).toBe(401);
    expect(await res.json()).toEqual({ error: 'Unauthorized' });
  });

  test('malformed header without "Bearer " prefix returns 401', async () => {
    const res = await req(app, 'Basic my-secret-token');
    expect(res.status).toBe(401);
    expect(await res.json()).toEqual({ error: 'Unauthorized' });
  });

  test('empty Authorization header returns 401', async () => {
    const res = await req(app, '');
    expect(res.status).toBe(401);
    expect(await res.json()).toEqual({ error: 'Unauthorized' });
  });

  test('"Bearer " with no token value returns 401', async () => {
    const res = await req(app, 'Bearer ');
    expect(res.status).toBe(401);
    // Empty string after "Bearer " — timingSafeEqual("", "my-secret-token") should fail
    expect(await res.json()).toEqual({ error: 'Unauthorized' });
  });

  test('token with extra whitespace is not trimmed (rejected)', async () => {
    const res = await req(app, 'Bearer  my-secret-token');
    // Double space means the extracted token starts with a space
    expect(res.status).toBe(401);
  });
});

// ---------------------------------------------------------------------------
// 2. Rotating secrets (string[] config)
// ---------------------------------------------------------------------------

describe('createBearerAuth — rotating secrets (string[])', () => {
  const app = buildApp(['new-secret', 'old-secret']);

  test('first token in array grants access', async () => {
    const res = await req(app, 'Bearer new-secret');
    expect(res.status).toBe(200);
    expect(await res.json()).toEqual({ ok: true });
  });

  test('second token in array grants access', async () => {
    const res = await req(app, 'Bearer old-secret');
    expect(res.status).toBe(200);
    expect(await res.json()).toEqual({ ok: true });
  });

  test('unknown token is rejected', async () => {
    const res = await req(app, 'Bearer unknown-token');
    expect(res.status).toBe(401);
    expect(await res.json()).toEqual({ error: 'Unauthorized' });
  });

  test('missing header returns 401', async () => {
    const res = await req(app);
    expect(res.status).toBe(401);
  });
});

// ---------------------------------------------------------------------------
// 3. Named clients (BearerAuthClient[] config)
// ---------------------------------------------------------------------------

describe('createBearerAuth — named clients (BearerAuthClient[])', () => {
  const app = buildApp([
    { clientId: 'service-a', token: 'token-a' },
    { clientId: 'service-b', token: 'token-b', revoked: false },
    { clientId: 'legacy', token: 'legacy-token', revoked: true },
  ]);

  test('valid client token grants access and sets bearerClientId', async () => {
    const res = await req(app, 'Bearer token-a');
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.ok).toBe(true);
    expect(body.clientId).toBe('service-a');
  });

  test('second non-revoked client also grants access with correct clientId', async () => {
    const res = await req(app, 'Bearer token-b');
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.clientId).toBe('service-b');
  });

  test('revoked client token is rejected (401)', async () => {
    const res = await req(app, 'Bearer legacy-token');
    expect(res.status).toBe(401);
    expect(await res.json()).toEqual({ error: 'Unauthorized' });
  });

  test('unknown token not matching any client is rejected', async () => {
    const res = await req(app, 'Bearer totally-unknown');
    expect(res.status).toBe(401);
  });

  test('missing Authorization header returns 401', async () => {
    const res = await req(app);
    expect(res.status).toBe(401);
  });
});

// ---------------------------------------------------------------------------
// 4. Edge cases
// ---------------------------------------------------------------------------

describe('createBearerAuth — edge cases', () => {
  test('empty string[] config always rejects', async () => {
    const app = buildApp([]);
    const res = await req(app, 'Bearer any-token');
    expect(res.status).toBe(401);
    expect(await res.json()).toEqual({ error: 'Unauthorized' });
  });

  test('empty BearerAuthClient[] config always rejects', async () => {
    const app = buildApp([] as { clientId: string; token: string }[]);
    const res = await req(app, 'Bearer any-token');
    expect(res.status).toBe(401);
  });

  test('only "Bearer" keyword without space and token returns 401', async () => {
    const app = buildApp('secret');
    const res = await req(app, 'Bearer');
    expect(res.status).toBe(401);
  });

  test('case-sensitive: "bearer " (lowercase) prefix is rejected', async () => {
    const app = buildApp('my-secret');
    const res = await req(app, 'bearer my-secret');
    expect(res.status).toBe(401);
  });

  test('handler is not called on auth failure', async () => {
    let handlerCalled = false;
    const app = new Hono();
    app.use('/protected/*', createBearerAuth('secret'));
    app.get('/protected/resource', c => {
      handlerCalled = true;
      return c.json({ ok: true });
    });

    await req(app, 'Bearer wrong');
    expect(handlerCalled).toBe(false);
  });

  test('handler is called on auth success', async () => {
    let handlerCalled = false;
    const app = new Hono();
    app.use('/protected/*', createBearerAuth('secret'));
    app.get('/protected/resource', c => {
      handlerCalled = true;
      return c.json({ ok: true });
    });

    await req(app, 'Bearer secret');
    expect(handlerCalled).toBe(true);
  });

  test('all-revoked client list rejects everything', async () => {
    const app = buildApp([
      { clientId: 'a', token: 'token-a', revoked: true },
      { clientId: 'b', token: 'token-b', revoked: true },
    ]);
    const res = await req(app, 'Bearer token-a');
    expect(res.status).toBe(401);
  });
});

import { describe, expect, test } from 'bun:test';
import { defaultValidationErrorFormatter, defaultHook, createRouter, getSlingshotCtx } from '../../src/context';

describe('defaultValidationErrorFormatter', () => {
  test('formats issues into error + details', () => {
    const issues = [
      { path: ['user', 'email'], message: 'Required', code: 'invalid_type' as const },
      { path: ['age'], message: 'Must be positive', code: 'too_small' as const },
    ];
    const result = defaultValidationErrorFormatter(issues as never, 'req-123') as {
      error: string;
      details: { path: string; message: string }[];
      requestId: string;
    };
    expect(result.error).toBe('Required, Must be positive');
    expect(result.details).toEqual([
