import { describe, expect, test } from 'bun:test';
import { getUserResolver, getUserResolverOrNull } from '../../src/userResolver';
import { attachContext } from '../../src/context/contextStore';

/**
 * Create a minimal branded SlingshotContext-like object with just the fields
 * needed by userResolver. We use attachContext to install the brand symbol,
 * then pass the context directly to the resolver helpers.
 */
function createBrandedContext(userResolver: { resolveUserId(req: Request): Promise<string | null> } | null) {
  // Build a minimal context object that satisfies the shape resolveContext checks.
  const ctx = { userResolver } as Record<string, unknown>;
  // We need a carrier (app) to brand the context through attachContext.
  const app = {};
  attachContext(app, ctx as never);
  // After attachContext, ctx now carries the brand symbol and can be recognized
  // by isContextObject, so resolveContext(ctx) will return ctx directly.
  return ctx;
}

describe('getUserResolver', () => {
  test('returns the resolver when one is registered', () => {
    const fakeResolver = {
      resolveUserId: async (_req: Request) => 'user-123',
    };
    const ctx = createBrandedContext(fakeResolver);
    const result = getUserResolver(ctx);
    expect(result).toBe(fakeResolver);
  });

  test('throws when no UserResolver is registered (null)', () => {
    const ctx = createBrandedContext(null);
    expect(() => getUserResolver(ctx)).toThrow(
      'No UserResolver registered for this app instance.',
    );
  });

  test('resolves user from the returned resolver', async () => {
    const fakeResolver = {
      resolveUserId: async (_req: Request) => 'user-456',
    };
    const ctx = createBrandedContext(fakeResolver);
    const resolver = getUserResolver(ctx);
    const userId = await resolver.resolveUserId(new Request('http://localhost/'));
    expect(userId).toBe('user-456');
  });
});

describe('getUserResolverOrNull', () => {
  test('returns the resolver when one is registered', () => {
    const fakeResolver = {
      resolveUserId: async (_req: Request) => 'user-789',
    };
    const ctx = createBrandedContext(fakeResolver);
    const result = getUserResolverOrNull(ctx);
    expect(result).toBe(fakeResolver);
  });

  test('returns null when no UserResolver is registered', () => {
    const ctx = createBrandedContext(null);
    const result = getUserResolverOrNull(ctx);
    expect(result).toBeNull();
  });
});

describe('getUserResolver with app carrier', () => {
  test('resolves from an app object that has a context attached', () => {
    const fakeResolver = {
      resolveUserId: async (_req: Request) => 'user-app',
    };
    const ctx = { userResolver: fakeResolver } as Record<string, unknown>;
    const app = {};
    attachContext(app, ctx as never);
    // Pass the app (not the context) — resolveContext will call getContext(app)
    const result = getUserResolver(app);
    expect(result).toBe(fakeResolver);
  });

  test('throws when app has no context attached', () => {
    const plainObj = {};
    expect(() => getUserResolver(plainObj)).toThrow(
      'SlingshotContext not found',
    );
  });
});

/**
 * Coverage-targeted tests for zodWalker.ts uncovered branches.
 *
 * Covers: string length_equals/regex, all format cases (ipv6, cidrv4/v6, time,
 * duration, cuid/cuid2/ulid/nanoid/xid/ksuid, base64/base64url, e164, jwt,
 * emoji, lowercase, uppercase, mac), int type, nan, never, symbol,
 * tuple rest, default/prefault/catch/nonoptional/readonly/success wrappers,
 * pipe, transform, intersection non-object, lazy depth exceeded,
 * custom, template_literal, promise, function, file.
 */
import { describe, expect, test } from 'bun:test';
import { z } from 'zod';
import { walkSchema } from '../../src/faker';

// Helper to create a mock Zod schema node for types not easily constructed
// through the public z.* API.
function mockSchema(def: Record<string, unknown>): any {
  return { _zod: { def } };
}

// ---------------------------------------------------------------------------
// String: length_equals check
// ---------------------------------------------------------------------------

describe('string length_equals', () => {
  test('z.string().length(10) produces exactly 10 chars', () => {
    const schema = z.string().length(10);
    for (let i = 0; i < 20; i++) {
      const val = walkSchema(schema as any, { seed: i }) as string;
      expect(val).toHaveLength(10);
    }
  });
});

// ---------------------------------------------------------------------------
// String: regex check
// ---------------------------------------------------------------------------

describe('string regex', () => {
  test('z.string().regex() is handled without error', () => {
    const schema = z.string().regex(/^[A-Z]{3}$/);
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(typeof val).toBe('string');
  });
});

// ---------------------------------------------------------------------------
// String format: ipv6
// ---------------------------------------------------------------------------

describe('string format: ipv6', () => {
  test('z.ipv6() produces a string', () => {
    const schema = z.ipv6();
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(typeof val).toBe('string');
    expect(val).toContain(':');
  });
});

// ---------------------------------------------------------------------------
// String format: cidrv4, cidrv6
// ---------------------------------------------------------------------------

describe('string format: cidr', () => {
  test('cidrv4 format via mock', () => {
    const schema = z.cidrv4();
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(val).toContain('/');
  });

  test('cidrv6 format via mock', () => {
    const schema = z.cidrv6();
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(val).toContain('/');
    expect(val).toContain(':');
  });
});

// ---------------------------------------------------------------------------
// String format: time
// ---------------------------------------------------------------------------

describe('string format: time', () => {
  test('z.string().time() produces a time string', () => {
    const schema = z.string().time();
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(typeof val).toBe('string');
    expect(val).toContain(':');
  });

  test('z.string().time({ precision: 0 }) produces no fractional seconds', () => {
    const schema = z.string().time({ precision: 0 });
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(val).not.toContain('.');
  });

  test('z.string().time({ precision: 3 }) produces 3-digit fraction', () => {
    const schema = z.string().time({ precision: 3 });
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(val).toContain('.');
    const frac = val.split('.')[1];
    expect(frac).toHaveLength(3);
  });
});

// ---------------------------------------------------------------------------
// String format: duration
// ---------------------------------------------------------------------------

describe('string format: duration', () => {
  test('z.string().duration() produces P...D format', () => {
    const schema = z.string().duration();
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(val).toMatch(/^P\d+D$/);
  });
});

// ---------------------------------------------------------------------------
// String format: e164
// ---------------------------------------------------------------------------

describe('string format: e164', () => {
  test('z.string().e164() produces +1 followed by 10 digits', () => {
    const schema = z.string().e164();
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    expect(val).toMatch(/^\+1\d{10}$/);
  });
});

// ---------------------------------------------------------------------------
// String format: jwt
// ---------------------------------------------------------------------------

describe('string format: jwt', () => {
  test('z.string().jwt() produces three dot-separated segments', () => {
    const schema = z.string().jwt();
    const val = walkSchema(schema as any, { seed: 1 }) as string;
    const parts = val.split('.');
    expect(parts).toHaveLength(3);
  });
});

// ---------------------------------------------------------------------------
// String format: emoji
// ---------------------------------------------------------------------------

describe('string format: emoji', () => {
  test('emoji format via mock', () => {
    const schema = mockSchema({ type: 'string', format: 'emoji' });
    const val = walkSchema(schema, { seed: 1 }) as string;
