/** Create an in-memory adapter for testing. */
function createMemoryAdapter<T extends { id?: string }>() {
  const store: T[] = [];
  return {
    store,
    create: async (input: T): Promise<T> => {
      const record = { ...input, id: input.id ?? crypto.randomUUID() };
      store.push(record as T);
      return record as T;
    },
    clear: async () => {
      store.length = 0;
    },
  };
}

