  });

  it('formats an update entry with ~ indicator', () => {
    const output = formatDeployPlan({
      services: [
        {
          serviceName: 'api',
          stackName: 'main',
          status: 'update',
          currentImageTag: 'v1',
          newImageTag: 'v2',
          changes: ['image tag: v1 \u2192 v2'],
        },
      ],
