  });

  it('no recipient (no recipientMapper and no payload.email) → does not enqueue', async () => {
    const bus = makeBus();
    const queue = makeQueue();
    const renderer = makeRenderer();

    const config: MailPluginConfig = {
      provider: {
        name: 'test',
