import { Hono } from 'hono';
import { createAuthResolvedConfig, createMemoryAuthAdapter } from '@lastshotlabs/slingshot-auth';
import type { AuthResolvedConfig, AuthRuntimeContext } from '@lastshotlabs/slingshot-auth';
import {
  AUTH_RUNTIME_KEY,
  createAuthRateLimitService,
  createMemoryAuthRateLimitRepository,
  createMemoryDeletionCancelTokenRepository,
  createMemoryMagicLinkRepository,
  createMemoryMfaChallengeRepository,
  createMemoryOAuthCodeRepository,
  createMemoryOAuthReauthRepository,
  createMemoryOAuthStateStore,
  createMemoryResetTokenRepository,
  createMemorySessionRepository,
  createMemoryVerificationTokenRepository,
  makeDummyHashGetter,
} from '@lastshotlabs/slingshot-auth/testing';
import type {
  AppEnv,
  ResolvedStores,
  SlingshotContext,
  SlingshotEventBus,
} from '@lastshotlabs/slingshot-core';
import type { OAuthProviders } from '../../../slingshot-auth/src/lib/oauth';

// Removes readonly modifiers so test files can mutate runtime fields directly
// without unsafe `as any` casts.
export type MutableTestRuntime = {
  -readonly [K in keyof AuthRuntimeContext]: AuthRuntimeContext[K];
};

// The stub intentionally omits type-safe generic overloads — this is an
// opaque test-boundary mock, not a real implementation.
export function makeEventBus(onEmit?: (event: string) => void): SlingshotEventBus {
  return {
    emit: (event: string) => {
      onEmit?.(event);
    },
    on: () => {},
    off: () => {},
    shutdown: async () => {},
    clientSafeKeys: new Set<string>(),
    registerClientSafeEvents: () => {},
    ensureClientSafeEventKey: (key: string) => key,
  } as unknown as SlingshotEventBus;
}

export function makeTestRuntime(
  configOverrides: Partial<AuthResolvedConfig> = {},
  onEmit?: (event: string) => void,
): MutableTestRuntime {
  const adapter = createMemoryAuthAdapter();
  const rateLimitRepo = createMemoryAuthRateLimitRepository();
  const rateLimitService = createAuthRateLimitService(rateLimitRepo);
  const passwordRuntime = Bun.password;
  const oauthProviders: OAuthProviders = {};

  return {
    adapter,
    config: createAuthResolvedConfig(configOverrides),
    eventBus: makeEventBus(onEmit),
    password: passwordRuntime,
    getDummyHash: makeDummyHashGetter(passwordRuntime),
    signing: { secret: 'test-signing-secret-32-chars-ok!' },
    dataEncryptionKeys: [],
    oauth: { providers: oauthProviders, stateStore: createMemoryOAuthStateStore() },
    lockout: null,
    rateLimit: rateLimitService,
    credentialStuffing: null,
    securityGate: {
      preAuthCheck: async () => ({ allowed: true }),
      lockoutCheck: async () => ({ allowed: true }),
      recordLoginFailure: async () => ({ stuffingNowBlocked: false }),
      recordLoginSuccess: async () => {},
    },
    queueFactory: null,
    repos: {
      oauthCode: createMemoryOAuthCodeRepository(),
      oauthReauth: createMemoryOAuthReauthRepository(),
      magicLink: createMemoryMagicLinkRepository(),
      deletionCancelToken: createMemoryDeletionCancelTokenRepository(),
      mfaChallenge: createMemoryMfaChallengeRepository(),
      samlRequestId: null,
      verificationToken: createMemoryVerificationTokenRepository(),
      resetToken: createMemoryResetTokenRepository(),
      session: createMemorySessionRepository(),
    },
    stores: {
      sessions: 'memory',
      oauthState: 'memory',
      cache: 'memory',
      authStore: 'memory',
      sqlite: undefined,
    } satisfies ResolvedStores,
  };
}

export function wrapWithRuntime(runtime: AuthRuntimeContext): Hono<AppEnv> {
  const app = new Hono<AppEnv>();
  app.use('*', async (c, next) => {
    const ctx: SlingshotContext = {
      signing: runtime.signing,
      pluginState: new Map([[AUTH_RUNTIME_KEY, runtime]]),
    } as never;
    c.set('slingshotCtx', ctx);
    await next();
  });
  return app;
}

/**
 * Auto-close sweep unit tests.
 *
 * Enterprise invariants:
 * - Polls with closesAt in the past get closed
 * - closedBy is null on sweep-closed polls
 * - Polls without closesAt are never swept
 * - closesAt in the future is not swept
 * - Sweep with intervalMs 0 does not run
 */
import { afterEach, describe, expect, it, mock } from 'bun:test';
import { startCloseSweep } from '../../src/lib/closeSweep';
import type { PollAdapter } from '../../src/types/adapters';
import type { PollRecord } from '../../src/types/public';

function makePoll(overrides: Partial<PollRecord> = {}): PollRecord {
  return {
    id: 'poll-1',
    sourceType: 'test:source',
    sourceId: 'source-1',
    scopeId: 'scope-1',
    authorId: 'user-author',
    question: 'Pick one',
    options: ['A', 'B', 'C'],
    multiSelect: false,
    anonymous: false,
    closed: false,
    createdAt: new Date().toISOString(),
    ...overrides,
  };
}

describe('closeSweep', () => {
  let handle: { stop(): void } | undefined;

  afterEach(() => {
    handle?.stop();
  });

  it('closes polls with closesAt in the past', async () => {
    const pastDate = new Date(Date.now() - 60_000).toISOString();
    const updateFn = mock(async () => makePoll({ closed: true }));
    const emitFn = mock(() => {});

    const adapter: Partial<PollAdapter> = {
      list: async () => ({
        items: [makePoll({ id: 'poll-1', closesAt: pastDate })],
      }),
      update: updateFn,
    };

    handle = startCloseSweep({
      pollAdapter: adapter as PollAdapter,
      bus: { emit: emitFn },
      intervalMs: 50,
    });

    // Wait for at least one tick.
    await new Promise(r => setTimeout(r, 120));

    expect(updateFn).toHaveBeenCalled();
    const [id, data] = updateFn.mock.calls[0] as [string, Record<string, unknown>];
    expect(id).toBe('poll-1');
    expect(data.closed).toBe(true);
    expect(data.closedBy).toBeNull();

    expect(emitFn).toHaveBeenCalledWith(
      'polls:poll.closed',
      expect.objectContaining({
        id: 'poll-1',
        closedBy: null,
      }),
    );
  });

  it('does not sweep polls without closesAt', async () => {
    const updateFn = mock(async () => makePoll());

    const adapter: Partial<PollAdapter> = {
      list: async () => ({
        items: [makePoll({ id: 'poll-2', closesAt: undefined })],
      }),
      update: updateFn,
    };

    handle = startCloseSweep({
      pollAdapter: adapter as PollAdapter,
      bus: { emit: mock(() => {}) },
      intervalMs: 50,
    });

    await new Promise(r => setTimeout(r, 120));
    expect(updateFn).not.toHaveBeenCalled();
  });

  it('does not sweep polls with closesAt in the future', async () => {
    const futureDate = new Date(Date.now() + 3_600_000).toISOString();
    const updateFn = mock(async () => makePoll());

    const adapter: Partial<PollAdapter> = {
      list: async () => ({
        items: [makePoll({ id: 'poll-3', closesAt: futureDate })],
      }),
      update: updateFn,
    };

    handle = startCloseSweep({
      pollAdapter: adapter as PollAdapter,
      bus: { emit: mock(() => {}) },
      intervalMs: 50,
    });

    await new Promise(r => setTimeout(r, 120));
    expect(updateFn).not.toHaveBeenCalled();
  });

  it('does not sweep already-closed polls', async () => {
    const pastDate = new Date(Date.now() - 60_000).toISOString();
    const updateFn = mock(async () => makePoll());

    const adapter: Partial<PollAdapter> = {
      list: async () => ({
        items: [makePoll({ id: 'poll-4', closed: true, closesAt: pastDate })],
      }),
      update: updateFn,
    };

    handle = startCloseSweep({
      pollAdapter: adapter as PollAdapter,
      bus: { emit: mock(() => {}) },
      intervalMs: 50,
    });

    await new Promise(r => setTimeout(r, 120));
    expect(updateFn).not.toHaveBeenCalled();
  });

  it('returns a noop handle when intervalMs is 0', () => {
    const emptyAdapter: PollAdapter = {} as never;
    handle = startCloseSweep({
      pollAdapter: emptyAdapter,
      bus: { emit: () => {} },
      intervalMs: 0,
    });

    // Should not throw.
    handle.stop();
  });

  it('stop() clears the interval (no dangling timers)', async () => {
    const updateFn = mock(async () => makePoll());
    const pastDate = new Date(Date.now() - 60_000).toISOString();

    const adapter: Partial<PollAdapter> = {
      list: async () => ({
        items: [makePoll({ id: 'poll-5', closesAt: pastDate })],
      }),
      update: updateFn,
    };

    handle = startCloseSweep({
      pollAdapter: adapter as PollAdapter,
      bus: { emit: mock(() => {}) },
      intervalMs: 50,
    });

    // Stop before any tick fires.
    handle.stop();
    handle = undefined;

    await new Promise(r => setTimeout(r, 120));
    expect(updateFn).not.toHaveBeenCalled();
  });
});

/**
 * Provider capability mismatch tests.
 *
 * Tests behavior when a provider has missing optional methods or capabilities.
 * Verifies graceful fallback or clear error handling.
 */
import { describe, expect, it } from 'bun:test';
import type { SearchIndexSettings, SearchIndexTask, SearchProvider } from '../src/types/provider';
import type { SearchQuery, SuggestQuery } from '../src/types/query';
import type { SearchResponse, SuggestResponse } from '../src/types/response';

// ============================================================================
// Minimal provider stubs
// ============================================================================

function makeMinimalProvider(overrides: Partial<SearchProvider> = {}): SearchProvider {
  const store = new Map<string, Map<string, Record<string, unknown>>>();
  const settings = new Map<string, SearchIndexSettings>();

  const base: SearchProvider = {
    name: 'minimal-stub',

    async connect() {},
    async teardown() {},

    async healthCheck() {
      return { healthy: true, provider: 'minimal-stub', latencyMs: 0 };
    },

    async createOrUpdateIndex(indexName, s): Promise<SearchIndexTask | undefined> {
      if (!store.has(indexName)) store.set(indexName, new Map());
      settings.set(indexName, s);
      return undefined;
    },

    async deleteIndex(indexName) {
      store.delete(indexName);
      settings.delete(indexName);
    },

    async listIndexes() {
      return [...store.entries()].map(([name, docs]) => ({
        name,
        documentCount: docs.size,
        updatedAt: new Date(),
      }));
    },

    async getIndexSettings(indexName) {
      const s = settings.get(indexName);
      if (!s) throw new Error(`Index '${indexName}' not found`);
      return s;
    },

    async indexDocument(indexName, document, documentId) {
      const idx = store.get(indexName);
      if (!idx) throw new Error(`Index '${indexName}' not found`);
      idx.set(documentId, document);
    },

    async deleteDocument(indexName, documentId) {
      store.get(indexName)?.delete(documentId);
    },

    async indexDocuments(indexName, documents, primaryKey): Promise<SearchIndexTask | undefined> {
      const idx = store.get(indexName);
      if (!idx) throw new Error(`Index '${indexName}' not found`);
      for (const doc of documents) {
        const id = String(doc[primaryKey] ?? '');
        if (id) idx.set(id, doc);
      }
      return undefined;
    },

    async deleteDocuments(indexName, ids): Promise<SearchIndexTask | undefined> {
      const idx = store.get(indexName);
      if (!idx) return undefined;
      for (const id of ids) idx.delete(id);
      return undefined;
    },

    async clearIndex(indexName): Promise<SearchIndexTask | undefined> {
      store.get(indexName)?.clear();
      return undefined;
    },

    async search(indexName: string, query: SearchQuery): Promise<SearchResponse> {
      const idx = store.get(indexName);
      if (!idx) throw new Error(`Index '${indexName}' not found`);
      const hits = [...idx.values()]
        .filter(
          doc =>
            !query.q ||
            Object.values(doc).some(
              v => typeof v === 'string' && v.toLowerCase().includes(query.q.toLowerCase()),
            ),
        )
        .map(document => ({ document }));
      const limited = hits.slice(query.offset ?? 0, (query.offset ?? 0) + (query.limit ?? 20));
      return {
        hits: limited,
        totalHits: hits.length,
        totalHitsRelation: 'exact' as const,
        query: query.q,
        processingTimeMs: 0,
        indexName,
        offset: query.offset ?? 0,
        limit: query.limit ?? 20,
      };
    },

    async multiSearch(queries) {
      return Promise.all(queries.map(({ indexName, query }) => base.search(indexName, query)));
    },

    async suggest(): Promise<SuggestResponse> {
      // Basic stub: return no suggestions
      return { suggestions: [], processingTimeMs: 0 };
    },

    ...overrides,
  };

  return base;
}

