// tests/unit/ppr.test.ts
// Unit tests for slingshot-ssr PPR build-time shell pre-renderer.
// Uses bun:test; do NOT run - the full test suite runs after all phases land.
import { describe, expect, it } from 'bun:test';
import { prerenderPprShells } from '../../src/ppr/index';
import type { PprCacheShape, PprRouteDescriptor } from '../../src/ppr/index';

type MockReactElement = PprRouteDescriptor['element'];

function makeMockCache(): PprCacheShape & { stored: Map<string, unknown> } {
  const stored = new Map<string, unknown>();
  return {
    stored,
    set(path: string, shell: { shellHtml: string; ok: boolean }): void {
      if (shell.ok) {
        stored.set(path, shell);
      }
    },
    has(path: string): boolean {
      return stored.has(path);
    },
  };
}

function makeExtractShell(
  ok = true,
): (element: MockReactElement) => Promise<{ shellHtml: string; ok: boolean }> {
  return async () => ({
    shellHtml: ok ? '<div>shell content</div>' : '',
    ok,
  });
}

function makeRoutes(paths: string[]): PprRouteDescriptor[] {
  return paths.map(path => {
    const element: MockReactElement = {
      type: 'div',
      props: { children: path },
      key: null,
    } as never;
    return { path, element };
  });
}

describe('prerenderPprShells', () => {
  it('does nothing when routes array is empty', async () => {
    const cache = makeMockCache();
    await prerenderPprShells([], cache, makeExtractShell());
    expect(cache.stored.size).toBe(0);
  });

  it('calls extractShell once per route', async () => {
    const calls: MockReactElement[] = [];
    const extractShell = async (element: MockReactElement) => {
      calls.push(element);
      return { shellHtml: '<div>shell</div>', ok: true };
    };

    const routes = makeRoutes(['/a', '/b', '/c']);
    const cache = makeMockCache();
    await prerenderPprShells(routes, cache, extractShell);

    expect(calls.length).toBe(3);
  });

  it('stores successful shells in the cache', async () => {
    const cache = makeMockCache();
    const routes = makeRoutes(['/home', '/dashboard']);
    await prerenderPprShells(routes, cache, makeExtractShell(true));

    expect(cache.has('/home')).toBe(true);
    expect(cache.has('/dashboard')).toBe(true);
  });

  it('does not store failed shells in the cache', async () => {
    const cache = makeMockCache();
    const routes = makeRoutes(['/broken']);
    await prerenderPprShells(routes, cache, makeExtractShell(false));

    expect(cache.stored.size).toBe(0);
  });

  it('handles a mix of successful and failed shells', async () => {
    let callCount = 0;
    const extractShell = async () => {
      callCount++;
      const ok = callCount % 2 === 1;
      return { shellHtml: ok ? '<div>ok</div>' : '', ok };
    };

    const cache = makeMockCache();
    const routes = makeRoutes(['/a', '/b', '/c', '/d']);
    await prerenderPprShells(routes, cache, extractShell);

    expect(cache.has('/a')).toBe(true);
    expect(cache.has('/c')).toBe(true);
  });

  it('resolves without throwing when extractShell rejects for one route', async () => {
    const extractShell = async (element: MockReactElement) => {
      const props = element.props as { children?: string };
      if (String(props.children) === '/explode') {
        throw new Error('extraction failed');
      }
      return { shellHtml: '<div>ok</div>', ok: true };
    };

    const cache = makeMockCache();
    const routes = makeRoutes(['/safe', '/explode', '/also-safe']);

    await expect(prerenderPprShells(routes, cache, extractShell)).resolves.toBeUndefined();
  });

  it('processes all routes concurrently (Promise.allSettled pattern)', async () => {
    const order: string[] = [];
    const extractShell = async (element: MockReactElement) => {
      const props = element.props as { children?: string };
      const path = String(props.children ?? '?');
      order.push(path);
      return { shellHtml: '<div>shell</div>', ok: true };
    };

    const routes = makeRoutes(['/one', '/two', '/three']);
    const cache = makeMockCache();
    await prerenderPprShells(routes, cache, extractShell);

    expect(order.length).toBe(3);
    expect(order).toContain('/one');
    expect(order).toContain('/two');
    expect(order).toContain('/three');
  });
});

import { describe, expect, it, mock } from 'bun:test';
import { createWebhookMemoryQueue } from '../../src/queues/memory';
import { WebhookDeliveryError } from '../../src/types/queue';
import type { WebhookJob } from '../../src/types/queue';

function makeJob(overrides?: Partial<WebhookJob>): Omit<WebhookJob, 'id' | 'createdAt'> {
  return {
    deliveryId: 'del-1',
    endpointId: 'ep-1',
    url: 'https://example.com/hook',
    secret: 'secret',
    event: 'auth:user.created',
    payload: '{}',
    attempts: 0,
    ...overrides,
  };
}

describe('memory queue', () => {
  it('calls processor for enqueued job', async () => {
    const processorMock = mock(async (_job: WebhookJob) => {});
    const q = createWebhookMemoryQueue({ maxAttempts: 3 });
    await q.start(processorMock);
    await q.enqueue(makeJob());
    // Allow microtask queue to flush
    await new Promise(r => setTimeout(r, 10));
    expect(processorMock).toHaveBeenCalledTimes(1);
    await q.stop();
  });

  it('retries on failure up to maxAttempts, then calls onDeadLetter', async () => {
    const deadLetterMock = mock((_job: WebhookJob, _err: Error) => {});
    let callCount = 0;
    const processor = async (_job: WebhookJob) => {
      callCount++;
      throw new Error('delivery failed');
    };
    const q = createWebhookMemoryQueue({ maxAttempts: 3, onDeadLetter: deadLetterMock });
    await q.start(processor);
    await q.enqueue(makeJob());
    await new Promise(r => setTimeout(r, 50));
    expect(callCount).toBe(3);
    expect(deadLetterMock).toHaveBeenCalledTimes(1);
    await q.stop();
  });

  it('depth decreases after job is processed', async () => {
    const q = createWebhookMemoryQueue({ maxAttempts: 1 });
    const processorMock = mock(async (_job: WebhookJob) => {});
    await q.start(processorMock);

    expect(await q.depth!()).toBe(0);
    await q.enqueue(makeJob());
    // Allow processing
    await new Promise(r => setTimeout(r, 30));
    expect(await q.depth!()).toBe(0);
    await q.stop();
  });

  it('depth reflects pending jobs before processing', async () => {
    const q = createWebhookMemoryQueue({ maxAttempts: 1 });
    // Don't start — no processor, jobs just accumulate
    await q.enqueue(makeJob());
    await q.enqueue(makeJob({ deliveryId: 'del-2' }));
    expect(await q.depth!()).toBe(2);
    await q.stop();
  });

  it('stops immediately on non-retryable error', async () => {
    const deadLetterMock = mock((_job: WebhookJob, _err: Error) => {});
    let callCount = 0;
    const processor = async (_job: WebhookJob) => {
      callCount++;
      throw new WebhookDeliveryError('permanent failure', false, 400);
    };
    const q = createWebhookMemoryQueue({ maxAttempts: 5, onDeadLetter: deadLetterMock });
    await q.start(processor);
    await q.enqueue(makeJob());
    await new Promise(r => setTimeout(r, 50));
    expect(callCount).toBe(1);
    expect(deadLetterMock).toHaveBeenCalledTimes(1);
    await q.stop();
  });
});

import { describe, expect, it, mock } from 'bun:test';
import { createInProcessAdapter } from '@lastshotlabs/slingshot-core';
import { wireEventSubscriptions } from '../../src/lib/eventWiring';
import { createWebhookMemoryQueue } from '../../src/queues/memory';
import type { WebhookAdapter } from '../../src/types/adapter';
import type { WebhookPluginConfig } from '../../src/types/config';
import type { WebhookDelivery, WebhookEndpoint } from '../../src/types/models';

function createAdapter(seedEndpoints: WebhookEndpoint[] = []): WebhookAdapter {
  const endpoints = [...seedEndpoints];
  const deliveries: WebhookDelivery[] = [];

  return {
    async getEndpoint(id) {
      return endpoints.find(endpoint => endpoint.id === id) ?? null;
    },
    async findEndpointsForEvent(_event) {
      return endpoints;
    },
    async createDelivery(input) {
      const delivery: WebhookDelivery = {
        id: `delivery-${deliveries.length + 1}`,
        endpointId: input.endpointId,
        event: input.event,
        payload: input.payload,
        status: 'pending',
        attempts: 0,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };
      deliveries.push(delivery);
      return delivery;
    },
    async updateDelivery(id, input) {
      const delivery = deliveries.find(item => item.id === id);
      if (!delivery) {
        throw new Error('missing delivery');
      }
      Object.assign(delivery, input, { updatedAt: new Date().toISOString() });
      return delivery;
    },
    async getDelivery(id) {
      return deliveries.find(item => item.id === id) ?? null;
    },
    async listDeliveries() {
      return { items: [...deliveries], hasMore: false };
    },
  };
}

function createEndpoint(id = 'endpoint-1'): WebhookEndpoint {
  return {
    id,
    url: 'https://example.com/hook',
    secret: 'secret-value',
    events: ['auth:*'],
    enabled: true,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
}

describe('eventWiring', () => {
  it('subscribes to matching events and delivers to matching endpoints', async () => {
    const bus = createInProcessAdapter();
    const adapter = createAdapter([createEndpoint()]);
    const queue = createWebhookMemoryQueue();
    const processorMock = mock(async () => {});
    await queue.start(processorMock);

    const config: WebhookPluginConfig = { events: ['auth:*'] };
    const unsubs = wireEventSubscriptions(bus, config, queue, adapter);

    bus.emit('auth:user.created', { userId: 'u1', email: 'u@example.com', tenantId: null });
    await new Promise(resolve => setTimeout(resolve, 30));

    const deliveries = await adapter.listDeliveries();
    expect(deliveries.items.length).toBe(1);
    expect(deliveries.items[0].event).toBe('auth:user.created');

    for (const unsub of unsubs) unsub();
    await queue.stop();
  });

  it('does not subscribe to non-matching events', async () => {
    const bus = createInProcessAdapter();
    const adapter = createAdapter([createEndpoint()]);
    const queue = createWebhookMemoryQueue({ maxAttempts: 1 });
    await queue.start(async () => {});

    const config: WebhookPluginConfig = { events: ['security.*'] };
    const unsubs = wireEventSubscriptions(bus, config, queue, adapter);

    bus.emit('auth:user.created', { userId: 'u1', email: 'u@example.com', tenantId: null });
    await new Promise(resolve => setTimeout(resolve, 30));

    const deliveries = await adapter.listDeliveries();
    expect(deliveries.items.length).toBe(0);

    for (const unsub of unsubs) unsub();
    await queue.stop();
  });

  it('subscribes to all events when config.events is omitted', async () => {
    const bus = createInProcessAdapter();
    const adapter = createAdapter([createEndpoint()]);
    const queue = createWebhookMemoryQueue();
    await queue.start(async () => {});

    const config: WebhookPluginConfig = {};
    const unsubs = wireEventSubscriptions(bus, config, queue, adapter);

    bus.emit('auth:user.created', { userId: 'u1', email: 'u@example.com', tenantId: null });
    await new Promise(resolve => setTimeout(resolve, 30));

    const deliveries = await adapter.listDeliveries();
    expect(deliveries.items.length).toBe(1);

    for (const unsub of unsubs) unsub();
    await queue.stop();
  });

  it('handles findEndpointsForEvent failure gracefully', async () => {
    const bus = createInProcessAdapter();
    const queue = createWebhookMemoryQueue();
    await queue.start(async () => {});

    const failingAdapter: WebhookAdapter = {
      ...createAdapter(),
      async findEndpointsForEvent() {
        throw new Error('adapter exploded');
      },
    };

    const config: WebhookPluginConfig = { events: ['auth:*'] };
    const unsubs = wireEventSubscriptions(bus, config, queue, failingAdapter);

    bus.emit('auth:user.created', { userId: 'u1', email: 'u@example.com', tenantId: null });
    await new Promise(resolve => setTimeout(resolve, 30));

    for (const unsub of unsubs) unsub();
    await queue.stop();
  });

  it('compensates delivery to dead when enqueue fails', async () => {
    const bus = createInProcessAdapter();
    const adapter = createAdapter([createEndpoint()]);

    const failingQueue = {
      name: 'failing',
      enqueue: mock(async () => {
        throw new Error('queue unavailable');
      }),
      start: mock(async () => {}),
      stop: mock(async () => {}),
      depth: mock(async () => 0),
    };

    const config: WebhookPluginConfig = { events: ['auth:*'] };
    const unsubs = wireEventSubscriptions(bus, config, failingQueue, adapter);

    bus.emit('auth:user.created', { userId: 'u1', email: 'u@example.com', tenantId: null });
    await new Promise(resolve => setTimeout(resolve, 30));

    const deliveries = await adapter.listDeliveries();
    expect(deliveries.items.length).toBe(1);
    expect(deliveries.items[0].status).toBe('dead');
    expect(deliveries.items[0].lastAttempt?.error).toContain('enqueue failed');

    for (const unsub of unsubs) unsub();
  });
});

import { existsSync, readFileSync } from 'node:fs';
import {
  discoverOwnedFiles,
  fileNeedsRuntimeCoverage,
  parseLcov,
  type CoverageFileSummary,
} from './coverage-lcov';
import { type CoverageSuite, coverageArtifactPath, coverageSuites } from './workspace-test-suites';

interface CoverageSummary {
  linesFound: number;
  linesHit: number;
  functionsFound: number;
  functionsHit: number;
  branchesFound: number;
  branchesHit: number;
  ownedFiles: number;
  missingFiles: string[];
}

function percent(hit: number, found: number): number {
  return found === 0 ? 100 : (hit / found) * 100;
}

function formatPercent(hit: number, found: number): string {
  return `${percent(hit, found).toFixed(1)}% (${hit}/${found})`;
}

function suiteEnvPrefix(suite: CoverageSuite): string {
  return suite.name.toUpperCase().replace(/[^A-Z0-9]+/g, '_');
}

function readThreshold(
  suite: CoverageSuite,
  metric: 'LINES' | 'FUNCTIONS' | 'BRANCHES',
): number | null {
  const suiteSpecific = Bun.env[`SLINGSHOT_COVERAGE_MIN_${suiteEnvPrefix(suite)}_${metric}`];
  const global = Bun.env[`SLINGSHOT_COVERAGE_MIN_${metric}`];
  const raw = suiteSpecific ?? global;
  if (raw == null || raw.trim().length === 0) return null;
  const value = Number(raw);
  return Number.isFinite(value) ? value : null;
}

function summarizeCoverage(
  ownedFiles: string[],
  fileCoverage: Map<string, CoverageFileSummary>,
): CoverageSummary {
  const runtimeOwnedFiles = ownedFiles.filter(fileNeedsRuntimeCoverage);
  const summary: CoverageSummary = {
    linesFound: 0,
    linesHit: 0,
    functionsFound: 0,
    functionsHit: 0,
    branchesFound: 0,
    branchesHit: 0,
    ownedFiles: runtimeOwnedFiles.length,
    missingFiles: [],
  };

  for (const file of runtimeOwnedFiles) {
    const entry = fileCoverage.get(file);
    if (!entry) {
      summary.missingFiles.push(file);
      continue;
    }

    summary.linesFound += entry.linesFound;
    summary.linesHit += entry.linesHit;
    summary.functionsFound += entry.functionsFound;
    summary.functionsHit += entry.functionsHit;
    summary.branchesFound += entry.branchesFound;
    summary.branchesHit += entry.branchesHit;
  }

  return summary;
}

function assertNonEmptyCoverage(suite: CoverageSuite, summary: CoverageSummary): string[] {
  const failures: string[] = [];
  if (summary.ownedFiles === 0) {
    failures.push(`${suite.name}: no owned files matched ${suite.ownedGlobs.join(', ')}`);
  }
  if (summary.linesFound === 0) {
    failures.push(`${suite.name}: no executable lines were captured`);
  }
  if (summary.functionsFound === 0) {
    failures.push(`${suite.name}: no functions were captured`);
  }
  if (summary.missingFiles.length > 0) {
    const preview = summary.missingFiles.slice(0, 5).join(', ');
    failures.push(
      `${suite.name}: ${summary.missingFiles.length} owned file(s) were never loaded under coverage${preview ? ` (${preview})` : ''}`,
    );
  }
  return failures;
}

function assertThresholds(suite: CoverageSuite, summary: CoverageSummary): string[] {
  const failures: string[] = [];
  const lineThreshold = readThreshold(suite, 'LINES');
  if (lineThreshold != null && percent(summary.linesHit, summary.linesFound) < lineThreshold) {
    failures.push(
      `${suite.name}: line coverage ${formatPercent(summary.linesHit, summary.linesFound)} is below ${lineThreshold.toFixed(1)}%`,
    );
  }

  const functionThreshold = readThreshold(suite, 'FUNCTIONS');
  if (
    functionThreshold != null &&
    percent(summary.functionsHit, summary.functionsFound) < functionThreshold
  ) {
    failures.push(
      `${suite.name}: function coverage ${formatPercent(summary.functionsHit, summary.functionsFound)} is below ${functionThreshold.toFixed(1)}%`,
    );
  }

  const branchThreshold = readThreshold(suite, 'BRANCHES');
  if (
    branchThreshold != null &&
    summary.branchesFound > 0 &&
    percent(summary.branchesHit, summary.branchesFound) < branchThreshold
  ) {
    failures.push(
      `${suite.name}: branch coverage ${formatPercent(summary.branchesHit, summary.branchesFound)} is below ${branchThreshold.toFixed(1)}%`,
    );
  }

  return failures;
}

const failures: string[] = [];

for (const suite of coverageSuites) {
  const artifact = coverageArtifactPath(suite);
  if (!existsSync(artifact)) {
    failures.push(`${suite.name}: missing coverage artifact at ${artifact}`);
    continue;
  }

  const ownedFiles = await discoverOwnedFiles(suite);
  const report = parseLcov(artifact);
  const summary = summarizeCoverage(ownedFiles, report.files);
  console.log(
    [
      `${suite.name}:`,
      `owned files ${summary.ownedFiles}`,
      `lines ${formatPercent(summary.linesHit, summary.linesFound)}`,
      `functions ${formatPercent(summary.functionsHit, summary.functionsFound)}`,
      `branches ${formatPercent(summary.branchesHit, summary.branchesFound)}`,
    ].join(' '),
  );

  failures.push(...assertNonEmptyCoverage(suite, summary));
  failures.push(...assertThresholds(suite, summary));
}

if (failures.length > 0) {
  console.error('coverage check failed');
  for (const failure of failures) {
    console.error(`- ${failure}`);
  }
  process.exit(1);
}

console.log(`coverage check passed for ${coverageSuites.length} suite(s)`);

/**
 * Redis integration tests for the BullMQ adapter — behaviors that require a live
 * Redis instance and cannot be validated with mocks alone.
 *
 * Guard: set BULLMQ_INTEGRATION_REDIS_URL to opt in.
 * The entire suite is skipped when the variable is absent so unrelated CI jobs
 * and local runs without Redis are unaffected.
 *
 *   BULLMQ_INTEGRATION_REDIS_URL=redis://localhost:6380 \
 *     bun test tests/docker/bullmq-adapter-redis-integration.test.ts
 *
 * Cleanup contract: afterEach calls shutdown() on every bus created in the test
 * and obliterates each queue from Redis so subsequent runs start from a clean state.
 */
import { Queue } from 'bullmq';
import { afterEach, describe, expect, test } from 'bun:test';
import { createBullMQAdapter } from '../../packages/slingshot-bullmq/src/bullmqAdapter';
import type { SlingshotEventBus } from '../../packages/slingshot-core/src/eventBus';

// Local dynamic-bus cast: community:* events are declared via entity config
// and not in SlingshotEventMap. Rule 14: widen locally, don't pollute the global map.
type DynamicEventBus = {
  emit(event: string, payload: Record<string, unknown>): void;
  on(
    event: string,
    handler: (payload: Record<string, unknown>) => void | Promise<void>,
    opts?: { durable?: boolean; name?: string },
  ): void;
};

// ─────────────────────────────────────────────────────────────────────────────
// Guard
// ─────────────────────────────────────────────────────────────────────────────

const REDIS_URL = process.env.BULLMQ_INTEGRATION_REDIS_URL;

function connectionFromUrl(url: string) {
  const u = new URL(url);
  return {
    host: u.hostname,
    port: Number(u.port) || 6379,
    ...(u.password ? { password: decodeURIComponent(u.password) } : {}),
    ...(u.pathname && u.pathname !== '/' ? { db: Number(u.pathname.slice(1)) } : {}),
  };
}

// Unreachable when skipIf fires, but must have a value for type-checking.
const connection = REDIS_URL ? connectionFromUrl(REDIS_URL) : { host: 'localhost', port: 6379 };

// ─────────────────────────────────────────────────────────────────────────────
// Per-test cleanup registry
// ─────────────────────────────────────────────────────────────────────────────

type CleanupFn = () => Promise<void>;
const cleanupFns: CleanupFn[] = [];

afterEach(async () => {
  const fns = cleanupFns.splice(0);
  await Promise.allSettled(fns.map(fn => fn()));
});

/**
 * Register a bus + queue names for cleanup after the current test.
 * Shutdown is called first so connections are closed before obliterate.
 */
function registerCleanup(bus: SlingshotEventBus, queueNames: string[]): void {
  cleanupFns.push(async () => {
    await (bus as any).shutdown?.();
    for (const name of queueNames) {
      const q = new Queue(name, { connection });
      try {
        await q.obliterate({ force: true });
      } finally {
        await q.close();
      }
    }
  });
}

// ─────────────────────────────────────────────────────────────────────────────
// Helpers
// ─────────────────────────────────────────────────────────────────────────────

/** Poll until condition() returns true or deadline passes. */
async function waitFor(condition: () => boolean, timeoutMs = 5000): Promise<void> {
  const deadline = Date.now() + timeoutMs;
  while (!condition()) {
    if (Date.now() >= deadline) throw new Error(`waitFor timed out after ${timeoutMs}ms`);
    await new Promise(r => setTimeout(r, 50));
  }
}

/** Derive the BullMQ queue name for a given (prefix, event, subName) triple. */
function queueName(prefix: string, event: string, subName: string): string {
  return `${prefix}:${event}:${subName}`.replace(/:/g, '_');
}

let testSeq = 0;
/** Unique per-test prefix to prevent cross-run queue contamination. */
function testPrefix(): string {
  return `bsi-${Date.now()}-${++testSeq}`;
}

// ─────────────────────────────────────────────────────────────────────────────
// Suite — skipped when BULLMQ_INTEGRATION_REDIS_URL is not set
// ─────────────────────────────────────────────────────────────────────────────

describe.skipIf(!REDIS_URL)(
  'BullMQ adapter — Redis integration (BULLMQ_INTEGRATION_REDIS_URL)',
  () => {
    test(// Why: the central durability promise — that jobs survive a process restart —
    // can only be verified end-to-end with real Redis. Mocks confirm queue.add()
    // is called but cannot prove the job persists in Redis across adapter
    // lifecycles. By seeding the queue directly (no worker attached), then
    // starting a fresh adapter, we reproduce the exact scenario of a deploy or crash.
    'T1 — jobs enqueued before the adapter starts are consumed when the worker registers', async () => {
      const prefix = testPrefix();
      const qName = queueName(prefix, 'auth:user.created', 'restart-consumer');

      // Seed Redis with a job before any worker exists
      const seedQueue = new Queue(qName, { connection });
      await seedQueue.add('auth:user.created', { userId: 'pre-start-u1' });
      await seedQueue.close();

      // Start an adapter that registers on the same queue name
      const bus = createBullMQAdapter({ connection, prefix });
      registerCleanup(bus, [qName]);

      const received: string[] = [];
      bus.on(
        'auth:user.created',
        p => {
          received.push(p.userId);
        },
        {
          durable: true,
          name: 'restart-consumer',
        },
      );

      await waitFor(() => received.length >= 1, 8000);
      expect(received).toEqual(['pre-start-u1']);
    }, 15_000);

    test(// Why: BullMQ's worker.close() is specified as non-forceful — it waits for
    // the currently processing job to complete. This is the mechanism that makes
    // graceful deploys safe. Mocks mark closed=true synchronously; only real
    // BullMQ + Redis can prove the implementation honours that contract and that
    // shutdown() does not resolve until the job callback returns.
    'T2 — shutdown() resolves only after the in-flight job completes', async () => {
      const prefix = testPrefix();
      const qName = queueName(prefix, 'auth:login', 'graceful-drain');
      const bus = createBullMQAdapter({ connection, prefix });
      registerCleanup(bus, [qName]);

      let jobCompleted = false;

      bus.on(
        'auth:login',
        async () => {
          await new Promise(r => setTimeout(r, 250));
          jobCompleted = true;
        },
        { durable: true, name: 'graceful-drain' },
      );

      bus.emit('auth:login', { userId: 'u-graceful', sessionId: 's1' });

      // Allow the worker to pick up and start processing the job before we shut down
      await new Promise(r => setTimeout(r, 80));

      await (bus as any).shutdown();

      expect(jobCompleted).toBe(true);
    }, 15_000);

    test(// Why: BullMQ serialises payloads to JSON before writing to Redis, then
    // deserialises on read. TypeScript types do not catch runtime issues such
    // as non-ASCII characters being corrupted, emoji being stripped, or
    // optional null values being coerced. Only a real Redis round-trip proves
    // the byte sequence the listener receives is identical to what was emitted.
    'T3 — complex payload with unicode and optional null fields round-trips faithfully', async () => {
      const prefix = testPrefix();
      const qName = queueName(prefix, 'community:thread.created', 'payload-fidelity');
      const bus = createBullMQAdapter({ connection, prefix });
      registerCleanup(bus, [qName]);

      const emitted = {
        threadId: 'thd-αβγ-123',
        containerId: 'ctr-🌍-xyz',
        authorId: 'author-üñícode',
        title: 'Héllo wörld — 日本語タイトル 🎉',
        contentType: 'markdown',
        tenantId: 'tenant-99',
      };

      const received: (typeof emitted)[] = [];
      (bus as unknown as DynamicEventBus).on(
        'community:thread.created',
        p => {
          received.push(p as typeof emitted);
        },
        {
          durable: true,
          name: 'payload-fidelity',
        },
      );

      (bus as unknown as DynamicEventBus).emit('community:thread.created', emitted);

      await waitFor(() => received.length >= 1, 8000);
      expect(received[0]).toEqual(emitted);
    }, 15_000);

    test(// Why: documentation states that colons in {prefix}:{event}:{name} are
    // replaced with underscores in the actual Redis queue name. Users inspecting
    // Redis via KEYS/SCAN, the BullMQ dashboard, or writing operational tooling
    // need to know the exact key format. Only a real Redis connection lets us
    // verify the key that appears on the wire matches the documented pattern.
    'T4 — Redis queue key matches the documented colon→underscore sanitized pattern', async () => {
      const prefix = testPrefix();
      const subName = 'naming-probe';
      const sanitized = queueName(prefix, 'auth:login', subName);

      const bus = createBullMQAdapter({ connection, prefix });
      registerCleanup(bus, [sanitized]);

      const received: string[] = [];
      bus.on(
        'auth:login',
        p => {
          received.push(p.userId);
        },
        {
          durable: true,
          name: subName,
        },
      );
      bus.emit('auth:login', { userId: 'naming-u1', sessionId: 's1' });

      await waitFor(() => received.length >= 1, 8000);

      // Open a Queue client for the *expected* sanitized name and inspect job counts.
      // If the adapter used a different name, this Queue would be empty/non-existent
      // and getJobCounts() would return all zeros, failing the assertion.
      const inspector = new Queue(sanitized, { connection });
      const counts = await inspector.getJobCounts('completed', 'active', 'waiting');
      await inspector.close();

      expect(counts.completed + counts.active + counts.waiting).toBeGreaterThanOrEqual(1);
    }, 15_000);

    test(// Why: the adapter contract guarantees non-durable listeners fire via the
    // local EventEmitter and are not blocked on Redis I/O. With a real network
    // connection and real Redis latency, we can assert that after a single
    // microtask yield the non-durable handler has fired, while the durable
    // handler (which requires a Queue.add → Worker round-trip) has not yet.
    // Mock tests cannot verify this because mock add() resolves synchronously.
    'T5 — non-durable listeners fire before the durable Redis round-trip completes', async () => {
      const prefix = testPrefix();
      const qName = queueName(prefix, 'auth:login', 'timing-durable');
      const bus = createBullMQAdapter({ connection, prefix });
      registerCleanup(bus, [qName]);

      const timeline: string[] = [];

      bus.on('auth:login', () => {
        timeline.push('non-durable');
      });
      bus.on(
        'auth:login',
        () => {
          timeline.push('durable');
        },
        { durable: true, name: 'timing-durable' },
      );

      bus.emit('auth:login', { userId: 'u-timing', sessionId: 's1' });

      // Non-durable fires via Promise.resolve — one microtask tick is enough
      await Promise.resolve();
      expect(timeline).toEqual(['non-durable']);

      // Wait for the durable path to complete
      await waitFor(() => timeline.length >= 2, 8000);
      expect(timeline).toEqual(['non-durable', 'durable']);
    }, 15_000);

    test(// Why: verifies that rapid-fire emits are not silently dropped under real
    // Redis throughput. Mocks confirm call counts synchronously; only real Redis
    // can reveal issues such as queue back-pressure, connection saturation, or
    // race conditions in job ID generation that would cause jobs to overwrite
    // each other or be refused by the broker.
    'T6 — five rapid emits all deliver exactly five jobs (no loss under load)', async () => {
      const prefix = testPrefix();
      const qName = queueName(prefix, 'auth:login', 'rapid-consumer');
      const bus = createBullMQAdapter({ connection, prefix });
      registerCleanup(bus, [qName]);

      const receivedIds: string[] = [];
      bus.on(
        'auth:login',
        p => {
          receivedIds.push(p.userId);
        },
        {
          durable: true,
          name: 'rapid-consumer',
        },
      );

      for (let i = 1; i <= 5; i++) {
        bus.emit('auth:login', { userId: `rapid-u${i}`, sessionId: `s${i}` });
      }

      await waitFor(() => receivedIds.length >= 5, 10_000);

      expect(receivedIds).toHaveLength(5);
      // All five distinct payloads arrived — none were merged, overwritten, or duplicated
      expect(new Set(receivedIds).size).toBe(5);
    }, 20_000);

    test(// Why: in production, multiple processes each create their own adapter and
    // register the same subscription name. BullMQ's competing-consumers model
    // guarantees each job is delivered to exactly one worker — not broadcast.
    // This is the inverse of the per-adapter fanout (same event, different names).
    // Only real Redis can verify that BullMQ honours at-most-once delivery across
    // two live Worker connections sharing a queue.
    'T7 — competing consumers: two workers on the same queue each process a job exactly once', async () => {
      const prefix = testPrefix();
      const qName = queueName(prefix, 'auth:login', 'competing');

      const busA = createBullMQAdapter({ connection, prefix });
      const busB = createBullMQAdapter({ connection, prefix });
      // Both cleanup registrations share the same Redis queue — obliterate only once
      registerCleanup(busA, [qName]);
      registerCleanup(busB, []);

      const processedByA: string[] = [];
      const processedByB: string[] = [];

      busA.on(
        'auth:login',
        p => {
          processedByA.push(p.userId);
        },
        {
          durable: true,
          name: 'competing',
        },
      );
      busB.on(
        'auth:login',
        p => {
          processedByB.push(p.userId);
        },
        {
          durable: true,
          name: 'competing',
        },
      );

      // Emit two jobs — competing consumers must share the load, not duplicate it
      busA.emit('auth:login', { userId: 'cc-u1', sessionId: 'cc-s1' });
      busB.emit('auth:login', { userId: 'cc-u2', sessionId: 'cc-s2' });

      const total = () => processedByA.length + processedByB.length;
      await waitFor(() => total() >= 2, 10_000);

      const allReceived = [...processedByA, ...processedByB];
      expect(allReceived).toHaveLength(2);
      // No job was delivered to both workers (competing consumers, not fanout)
      expect(new Set(allReceived).size).toBe(2);
    }, 20_000);

    test(// Why: the mock tests confirm that defaultJobOptions.attempts is passed to
    // the Queue constructor, but they cannot prove BullMQ actually honours it
    // during job execution. Only a real Redis + Worker cycle can verify that
    // a job which throws is retried the correct number of times and ultimately
    // delivered when the listener eventually succeeds.
    'T8 — listener that throws transiently is retried and eventually succeeds', async () => {
      const prefix = testPrefix();
      const qName = queueName(prefix, 'auth:login', 'retry-transient');
      const bus = createBullMQAdapter({ connection, prefix, attempts: 3 });
      registerCleanup(bus, [qName]);

      let callCount = 0;
      const received: string[] = [];

      bus.on(
        'auth:login',
        async p => {
          callCount++;
          if (callCount < 3) throw new Error('transient failure');
          received.push(p.userId);
        },
        { durable: true, name: 'retry-transient' },
      );

      bus.emit('auth:login', { userId: 'retry-u1', sessionId: 's1' });

      await waitFor(() => received.length >= 1, 15_000);

      // Listener was called exactly 3 times (2 failures + 1 success)
      expect(callCount).toBe(3);
      expect(received).toEqual(['retry-u1']);
    }, 25_000);

    test(// Why: confirms that when all attempts are exhausted BullMQ moves the job
    // to the failed set in Redis rather than silently dropping it or retrying
    // indefinitely. The failed handler log (F8 fix) is only observable via
    // console.error; the failed set is the durable record operators use to
    // inspect and replay jobs. Only real Redis can prove the job lands there.
    'T9 — after all attempts exhausted the job lands in the BullMQ failed set', async () => {
      const prefix = testPrefix();
      const qName = queueName(prefix, 'auth:login', 'retry-exhaust');
      const bus = createBullMQAdapter({ connection, prefix, attempts: 2 });
      registerCleanup(bus, [qName]);

      let callCount = 0;

      bus.on(
        'auth:login',
        async () => {
          callCount++;
          throw new Error('always fails');
        },
        { durable: true, name: 'retry-exhaust' },
      );

      bus.emit('auth:login', { userId: 'exhaust-u1', sessionId: 's1' });

      // Wait for both attempts to fire
      await waitFor(() => callCount >= 2, 15_000);
      // Allow BullMQ time to write the job to the failed set
      await new Promise(r => setTimeout(r, 500));

      const inspector = new Queue(qName, { connection });
      const counts = await inspector.getJobCounts('failed');
      await inspector.close();

      expect(callCount).toBe(2);
      expect(counts.failed).toBe(1);
    }, 25_000);
  },
);

// Docker integration tests for the slingshot-bullmq adapter (SlingshotEventBus contract).
// Requires: Redis on localhost:6380 (slingshot-redis-1 Docker container).
// Run with: bun test tests/docker/bullmq-adapter.test.ts
import { afterAll, beforeAll, describe, expect, it } from 'bun:test';
import { createBullMQAdapter } from '../../packages/slingshot-bullmq/src/bullmqAdapter';
import type { SlingshotEventBus } from '../../packages/slingshot-core/src/eventBus';

// Redis connection pointing at the Docker container (same as all other docker tests)
const REDIS_CONNECTION = { host: 'localhost', port: 6380 };

// ──────────────────────────────────────────────────────────────────────────────
// Helpers
// ──────────────────────────────────────────────────────────────────────────────

/** Wait up to `ms` milliseconds for `condition` to become true, polling every 50 ms. */
async function waitFor(condition: () => boolean, ms = 5000): Promise<void> {
  const deadline = Date.now() + ms;
  while (!condition()) {
    if (Date.now() >= deadline) throw new Error('waitFor timed out');
    await new Promise(r => setTimeout(r, 50));
  }
}

/** Unique suffix so parallel / repeated runs don't share queue state. */
const RUN_ID = Date.now();

function uniqueName(label: string): string {
  return `${label}-${RUN_ID}`;
}

// ──────────────────────────────────────────────────────────────────────────────
// Non-durable (EventEmitter) tests — no Redis involved
// ──────────────────────────────────────────────────────────────────────────────

describe('BullMQ adapter — non-durable subscriptions', () => {
  let bus: SlingshotEventBus & { shutdown(): Promise<void> };

  beforeAll(() => {
    bus = createBullMQAdapter({ connection: REDIS_CONNECTION }) as any;
  });

  afterAll(async () => {
    await bus.shutdown();
  });

  it('on(event, listener) → emit(event, payload) calls listener', async () => {
    const received: Array<{ userId: string; sessionId: string }> = [];

    const listener = (payload: { userId: string; sessionId: string }) => {
      received.push(payload);
    };

    bus.on('auth:login', listener);
    bus.emit('auth:login', { userId: 'u1', sessionId: 's1' });

    // Listeners are called fire-and-forget via Promise.resolve — give the
    // microtask queue one tick to settle before asserting.
    await new Promise(r => setTimeout(r, 20));

    expect(received).toHaveLength(1);
    expect(received[0]).toEqual({ userId: 'u1', sessionId: 's1' });
  });

  it('off(event, listener) → listener is not called after removal', async () => {
    const received: string[] = [];

    const listener = (payload: { userId: string; sessionId: string }) => {
      received.push(payload.userId);
    };

    bus.on('auth:logout', listener);
    bus.emit('auth:logout', { userId: 'u-before', sessionId: 's-before' });
    await new Promise(r => setTimeout(r, 20));
    expect(received).toHaveLength(1);

    bus.off('auth:logout', listener);
    bus.emit('auth:logout', { userId: 'u-after', sessionId: 's-after' });
    await new Promise(r => setTimeout(r, 20));

    // Should still be 1 — the second emit must not reach the removed listener
    expect(received).toHaveLength(1);
    expect(received[0]).toBe('u-before');
  });

  it('multiple non-durable listeners for the same event are all called', async () => {
    const calls: string[] = [];

    const l1 = () => {
      calls.push('l1');
    };
    const l2 = () => {
      calls.push('l2');
    };

    bus.on('app:ready', l1);
    bus.on('app:ready', l2);
    bus.emit('app:ready', { plugins: [] });

    await new Promise(r => setTimeout(r, 20));

    expect(calls).toContain('l1');
    expect(calls).toContain('l2');
  });
});

// ──────────────────────────────────────────────────────────────────────────────
// Validation tests (no Redis required)
// ──────────────────────────────────────────────────────────────────────────────

describe('BullMQ adapter — validation', () => {
  it('on({ durable: true }) without name throws synchronously', () => {
    const bus = createBullMQAdapter({ connection: REDIS_CONNECTION });

    expect(() => {
      bus.on('auth:login', () => {}, { durable: true });
    }).toThrow('[BullMQAdapter] durable subscriptions require a name');
  });

  it('duplicate durable registration (same event + name) throws', () => {
    const bus = createBullMQAdapter({ connection: REDIS_CONNECTION });
    bus.on('auth:login', () => {}, { durable: true, name: uniqueName('dup-check') });

    expect(() => {
      bus.on('auth:login', () => {}, { durable: true, name: uniqueName('dup-check') });
    }).toThrow('already exists');
  });

  it('off() on a durable listener throws', () => {
    const bus = createBullMQAdapter({ connection: REDIS_CONNECTION });
    const listener = () => {};
    bus.on('auth:login', listener, { durable: true, name: uniqueName('off-durable') });

    expect(() => {
      bus.off('auth:login', listener);
    }).toThrow('cannot remove a durable subscription via off()');
  });
});

// ──────────────────────────────────────────────────────────────────────────────
// Durable (BullMQ Queue + Worker) tests — Redis required
// ──────────────────────────────────────────────────────────────────────────────

describe('BullMQ adapter — durable subscriptions (Redis)', () => {
  // Each test gets its own isolated bus + unique queue names to prevent
  // cross-test interference (stale jobs from a previous run could be picked up).
  // We shut each bus down in afterAll.

  const buses: Array<SlingshotEventBus & { shutdown(): Promise<void> }> = [];

  afterAll(async () => {
    await Promise.all(buses.map(b => b.shutdown()));
  });

  function makeBus() {
    const b = createBullMQAdapter({ connection: REDIS_CONNECTION }) as SlingshotEventBus & {
      shutdown(): Promise<void>;
    };
    buses.push(b);
    return b;
  }

  it('durable on + emit immediately (no sleep) processes the job (regression: race condition fix)', async () => {
    const bus = makeBus();
    const received: Array<{ userId: string; sessionId: string }> = [];

    bus.on(
      'auth:login',
      payload => {
        received.push(payload);
      },
      { durable: true, name: uniqueName('login-no-sleep') },
    );

    // No artificial sleep — queue/worker setup is now synchronous.
    // emit() must reach the queue even without a delay.
    bus.emit('auth:login', { userId: 'u-immediate', sessionId: 's-immediate' });

    await waitFor(() => received.length >= 1, 5000);

    expect(received).toHaveLength(1);
    expect(received[0]).toEqual({ userId: 'u-immediate', sessionId: 's-immediate' });
  });

  it('durable on + emit → worker processes job and calls listener', async () => {
    const bus = makeBus();
    const received: Array<{ userId: string; sessionId: string }> = [];

    bus.on(
      'auth:login',
      payload => {
        received.push(payload);
      },
      { durable: true, name: uniqueName('login-basic') },
    );

    bus.emit('auth:login', { userId: 'u-durable', sessionId: 's-durable' });

    await waitFor(() => received.length >= 1, 5000);

    expect(received).toHaveLength(1);
    expect(received[0]).toEqual({ userId: 'u-durable', sessionId: 's-durable' });
  });

  it('multiple durable subscriptions for the same event all process the job', async () => {
    const bus = makeBus();
    const receivedA: string[] = [];
    const receivedB: string[] = [];

    bus.on(
      'auth:login',
      payload => {
        receivedA.push(payload.userId);
      },
      { durable: true, name: uniqueName('login-fanout-a') },
    );
    bus.on(
      'auth:login',
      payload => {
        receivedB.push(payload.userId);
      },
      { durable: true, name: uniqueName('login-fanout-b') },
    );

    bus.emit('auth:login', { userId: 'u-fanout', sessionId: 's-fanout' });

    await waitFor(() => receivedA.length >= 1 && receivedB.length >= 1, 5000);

    expect(receivedA).toHaveLength(1);
    expect(receivedB).toHaveLength(1);
    expect(receivedA[0]).toBe('u-fanout');
    expect(receivedB[0]).toBe('u-fanout');
  });

  it('durable listener receives correct payload', async () => {
    const bus = makeBus();
    const received: Array<{ userId: string; email: string }> = [];

    bus.on(
      'auth:user.created',
      payload => {
        received.push({ userId: payload.userId, email: payload.email ?? '' });
      },
      { durable: true, name: uniqueName('user-created-payload') },
    );

    bus.emit('auth:user.created', { userId: 'u-new', email: 'test@example.com' });

    await waitFor(() => received.length >= 1, 5000);

    expect(received[0].userId).toBe('u-new');
    expect(received[0].email).toBe('test@example.com');
  });

  it('shutdown() closes workers and queues without hanging', async () => {
    const bus = makeBus();

    bus.on('auth:login', () => {}, { durable: true, name: uniqueName('shutdown-test') });

    // Should resolve without hanging (5s timeout is the test runner default)
    await expect(bus.shutdown()).resolves.toBeUndefined();

    // Remove from buses so afterAll doesn't double-close
    const idx = buses.indexOf(bus);
    if (idx !== -1) buses.splice(idx, 1);
  });
});

import { createMongoAuthAdapter } from '@auth/adapters/mongoAuth';
import { afterAll, beforeAll, beforeEach, describe, expect, it } from 'bun:test';
import type { AuthAdapter } from '@lastshotlabs/slingshot-core';
import { getMongooseModule } from '../../src/lib/mongo';
import {
  connectTestMongo,
  disconnectTestServices,
  flushTestServices,
  getTestAuthConn,
} from '../setup-docker';

let mongoAuthAdapter: AuthAdapter;

beforeAll(async () => {
  await connectTestMongo();
  mongoAuthAdapter = createMongoAuthAdapter(getTestAuthConn(), getMongooseModule());
});

afterAll(async () => {
  await disconnectTestServices();
});

beforeEach(async () => {
  await flushTestServices();
});

describe('mongoAuthAdapter', () => {
  // -----------------------------------------------------------------------
  // User CRUD
  // -----------------------------------------------------------------------

  describe('create + findByEmail', () => {
    it('creates a user and finds by email', async () => {
      const { id } = await mongoAuthAdapter.create('test@example.com', 'hashed-pw');
      expect(id).toBeTruthy();

      const found = await mongoAuthAdapter.findByEmail('test@example.com');
      expect(found).not.toBeNull();
      expect(found!.id).toBe(id);
      expect(found!.passwordHash).toBe('hashed-pw');
    });

    it('returns null for non-existent email', async () => {
      const found = await mongoAuthAdapter.findByEmail('nobody@example.com');
      expect(found).toBeNull();
    });

    it('throws 409 on duplicate email', async () => {
      await mongoAuthAdapter.create('dup@example.com', 'pw1');
      try {
        await mongoAuthAdapter.create('dup@example.com', 'pw2');
        throw new Error('Expected duplicate to throw');
      } catch (err: any) {
        expect(err.message).toContain('Email already registered');
      }
    });
  });

  describe('findByIdentifier', () => {
    it('finds user by email identifier', async () => {
      const { id } = await mongoAuthAdapter.create('ident@example.com', 'pw');
      const found = await mongoAuthAdapter.findByIdentifier!('ident@example.com');
      expect(found).not.toBeNull();
      expect(found!.id).toBe(id);
    });

    it('returns null for missing identifier', async () => {
      const found = await mongoAuthAdapter.findByIdentifier!('missing@example.com');
      expect(found).toBeNull();
    });
  });

  describe('deleteUser', () => {
    it('deletes a user', async () => {
      const { id } = await mongoAuthAdapter.create('delete@example.com', 'pw');
      await mongoAuthAdapter.deleteUser!(id);
      const found = await mongoAuthAdapter.findByEmail('delete@example.com');
      expect(found).toBeNull();
    });
  });

  // -----------------------------------------------------------------------
  // Password
  // -----------------------------------------------------------------------

  describe('setPassword + hasPassword', () => {
    it('sets and checks password', async () => {
      const { id } = await mongoAuthAdapter.create('pw@example.com', '');
      expect(await mongoAuthAdapter.hasPassword!(id)).toBe(false);

      await mongoAuthAdapter.setPassword!(id, 'new-hashed-pw');
      expect(await mongoAuthAdapter.hasPassword!(id)).toBe(true);

      const found = await mongoAuthAdapter.findByEmail('pw@example.com');
      expect(found!.passwordHash).toBe('new-hashed-pw');
    });
  });

  // -----------------------------------------------------------------------
  // OAuth Providers
  // -----------------------------------------------------------------------

  describe('findOrCreateByProvider', () => {
    it('creates a new user for unknown provider', async () => {
      const result = await mongoAuthAdapter.findOrCreateByProvider!('google', 'gid-123', {
        email: 'oauth@example.com',
      });
      expect(result.created).toBe(true);
      expect(result.id).toBeTruthy();
    });

    it('finds existing user by provider key', async () => {
      const first = await mongoAuthAdapter.findOrCreateByProvider!('google', 'gid-456', {
        email: 'existing@example.com',
      });
      const second = await mongoAuthAdapter.findOrCreateByProvider!('google', 'gid-456', {
        email: 'existing@example.com',
      });
      expect(second.created).toBe(false);
      expect(second.id).toBe(first.id);
    });

    it('throws 409 if email belongs to credential account', async () => {
      await mongoAuthAdapter.create('cred@example.com', 'pw');
      try {
        await mongoAuthAdapter.findOrCreateByProvider!('google', 'gid-789', {
          email: 'cred@example.com',
        });
        throw new Error('Expected 409 to throw');
      } catch (err: any) {
        expect(err.message).toContain('An account with this email already exists');
      }
    });
  });

  describe('linkProvider + unlinkProvider', () => {
    it('links and unlinks a provider', async () => {
      const { id } = await mongoAuthAdapter.create('link@example.com', 'pw');
      await mongoAuthAdapter.linkProvider!(id, 'google', 'gid-link');

      const user = await mongoAuthAdapter.getUser!(id);
      expect(user!.providerIds).toContain('google:gid-link');

      await mongoAuthAdapter.unlinkProvider!(id, 'google');
      const updated = await mongoAuthAdapter.getUser!(id);
      expect(updated!.providerIds).not.toContain('google:gid-link');
    });

    it('linkProvider is idempotent', async () => {
      const { id } = await mongoAuthAdapter.create('idempotent@example.com', 'pw');
      await mongoAuthAdapter.linkProvider!(id, 'google', 'gid-same');
      await mongoAuthAdapter.linkProvider!(id, 'google', 'gid-same');

      const user = await mongoAuthAdapter.getUser!(id);
      const count = user!.providerIds!.filter((p: string) => p === 'google:gid-same').length;
      expect(count).toBe(1);
    });

    it('throws 404 for non-existent user', async () => {
      try {
        await mongoAuthAdapter.linkProvider!('000000000000000000000000', 'google', 'gid');
        throw new Error('Expected 404 to throw');
      } catch (err: any) {
        expect(err.message).toContain('User not found');
      }
    });
  });

  // -----------------------------------------------------------------------
  // Roles (app-wide)
  // -----------------------------------------------------------------------

  describe('roles', () => {
    it('manages app-wide roles', async () => {
      const { id } = await mongoAuthAdapter.create('roles@example.com', 'pw');

      expect(await mongoAuthAdapter.getRoles!(id)).toEqual([]);

      await mongoAuthAdapter.setRoles!(id, ['admin', 'user']);
      expect(await mongoAuthAdapter.getRoles!(id)).toEqual(['admin', 'user']);

      await mongoAuthAdapter.addRole!(id, 'editor');
      expect(await mongoAuthAdapter.getRoles!(id)).toContain('editor');

      await mongoAuthAdapter.removeRole!(id, 'admin');
      expect(await mongoAuthAdapter.getRoles!(id)).not.toContain('admin');
    });

    it('addRole is idempotent ($addToSet)', async () => {
      const { id } = await mongoAuthAdapter.create('roledup@example.com', 'pw');
      await mongoAuthAdapter.addRole!(id, 'admin');
      await mongoAuthAdapter.addRole!(id, 'admin');
      const roles = await mongoAuthAdapter.getRoles!(id);
      expect(roles.filter((r: string) => r === 'admin').length).toBe(1);
    });
  });

  // -----------------------------------------------------------------------
  // Email verification
  // -----------------------------------------------------------------------

  describe('email verification', () => {
    it('defaults to unverified, can be toggled', async () => {
      const { id } = await mongoAuthAdapter.create('verify@example.com', 'pw');
      expect(await mongoAuthAdapter.getEmailVerified!(id)).toBe(false);

      await mongoAuthAdapter.setEmailVerified!(id, true);
      expect(await mongoAuthAdapter.getEmailVerified!(id)).toBe(true);
    });
  });

  // -----------------------------------------------------------------------
  // getUser
  // -----------------------------------------------------------------------

  describe('getUser', () => {
    it('returns user profile', async () => {
      const { id } = await mongoAuthAdapter.create('profile@example.com', 'pw');
      const user = await mongoAuthAdapter.getUser!(id);
      expect(user).not.toBeNull();
      expect(user!.email).toBe('profile@example.com');
      expect(user!.emailVerified).toBe(false);
    });

    it('returns null for non-existent user', async () => {
      const user = await mongoAuthAdapter.getUser!('000000000000000000000000');
      expect(user).toBeNull();
    });
  });

  // -----------------------------------------------------------------------
  // MFA
  // -----------------------------------------------------------------------

  describe('MFA', () => {
    it('manages MFA secret and enabled state', async () => {
      const { id } = await mongoAuthAdapter.create('mfa@example.com', 'pw');

      expect(await mongoAuthAdapter.getMfaSecret!(id)).toBeNull();
      expect(await mongoAuthAdapter.isMfaEnabled!(id)).toBe(false);

      await mongoAuthAdapter.setMfaSecret!(id, 'JBSWY3DPEHPK3PXP');
      expect(await mongoAuthAdapter.getMfaSecret!(id)).toBe('JBSWY3DPEHPK3PXP');

      await mongoAuthAdapter.setMfaEnabled!(id, true);
      expect(await mongoAuthAdapter.isMfaEnabled!(id)).toBe(true);
    });

    it('manages recovery codes', async () => {
      const { id } = await mongoAuthAdapter.create('recovery@example.com', 'pw');
      const codes = ['code1', 'code2', 'code3'];

      await mongoAuthAdapter.setRecoveryCodes!(id, codes);
      expect(await mongoAuthAdapter.getRecoveryCodes!(id)).toEqual(codes);

      await mongoAuthAdapter.removeRecoveryCode!(id, 'code2');
      expect(await mongoAuthAdapter.getRecoveryCodes!(id)).toEqual(['code1', 'code3']);
    });

    it('manages MFA methods', async () => {
      const { id } = await mongoAuthAdapter.create('methods@example.com', 'pw');

      expect(await mongoAuthAdapter.getMfaMethods!(id)).toEqual([]);

      await mongoAuthAdapter.setMfaMethods!(id, ['totp', 'email-otp']);
      expect(await mongoAuthAdapter.getMfaMethods!(id)).toEqual(['totp', 'email-otp']);
    });

    it("getMfaMethods backward compat: mfaEnabled but no methods → ['totp']", async () => {
      const { id } = await mongoAuthAdapter.create('compat@example.com', 'pw');
      await mongoAuthAdapter.setMfaEnabled!(id, true);
      // mfaMethods is empty but mfaEnabled is true
      const methods = await mongoAuthAdapter.getMfaMethods!(id);
      expect(methods).toEqual(['totp']);
    });
  });

  // -----------------------------------------------------------------------
  // WebAuthn
  // -----------------------------------------------------------------------

  describe('WebAuthn', () => {
    const cred = {
      credentialId: 'cred-abc',
      publicKey: 'pk-abc',
      signCount: 0,
      transports: ['usb'] as string[],
      name: 'My Key',
      createdAt: Date.now(),
    };

    it('adds and retrieves credentials', async () => {
      const { id } = await mongoAuthAdapter.create('webauthn@example.com', 'pw');
      await mongoAuthAdapter.addWebAuthnCredential!(id, cred);

      const creds = await mongoAuthAdapter.getWebAuthnCredentials!(id);
      expect(creds).toHaveLength(1);
      expect(creds[0].credentialId).toBe('cred-abc');
      expect(creds[0].publicKey).toBe('pk-abc');
      expect(creds[0].signCount).toBe(0);
      expect(creds[0].transports).toEqual(['usb']);
      expect(creds[0].name).toBe('My Key');
    });

    it('updates sign count', async () => {
      const { id } = await mongoAuthAdapter.create('signcount@example.com', 'pw');
      await mongoAuthAdapter.addWebAuthnCredential!(id, cred);
      await mongoAuthAdapter.updateWebAuthnCredentialSignCount!(id, 'cred-abc', 5);

      const creds = await mongoAuthAdapter.getWebAuthnCredentials!(id);
      expect(creds[0].signCount).toBe(5);
    });

    it('removes a credential', async () => {
      const { id } = await mongoAuthAdapter.create('removecred@example.com', 'pw');
      await mongoAuthAdapter.addWebAuthnCredential!(id, cred);
      await mongoAuthAdapter.removeWebAuthnCredential!(id, 'cred-abc');

      const creds = await mongoAuthAdapter.getWebAuthnCredentials!(id);
      expect(creds).toHaveLength(0);
    });

    it('finds user by credential ID', async () => {
      const { id } = await mongoAuthAdapter.create('findcred@example.com', 'pw');
      await mongoAuthAdapter.addWebAuthnCredential!(id, { ...cred, credentialId: 'cred-find' });

      const userId = await mongoAuthAdapter.findUserByWebAuthnCredentialId!('cred-find');
      expect(userId).toBe(id);
    });

    it('returns null for unknown credential ID', async () => {
      const userId = await mongoAuthAdapter.findUserByWebAuthnCredentialId!('nope');
      expect(userId).toBeNull();
    });
  });

  // -----------------------------------------------------------------------
  // Tenant roles
  // -----------------------------------------------------------------------

  describe('tenant roles', () => {
    it('manages tenant-scoped roles', async () => {
      const { id } = await mongoAuthAdapter.create('tenant@example.com', 'pw');
      const tenantId = 'tenant-1';

      expect(await mongoAuthAdapter.getTenantRoles!(id, tenantId)).toEqual([]);

      await mongoAuthAdapter.setTenantRoles!(id, tenantId, ['admin']);
      expect(await mongoAuthAdapter.getTenantRoles!(id, tenantId)).toEqual(['admin']);

      await mongoAuthAdapter.addTenantRole!(id, tenantId, 'editor');
      expect(await mongoAuthAdapter.getTenantRoles!(id, tenantId)).toContain('editor');

      await mongoAuthAdapter.removeTenantRole!(id, tenantId, 'admin');
      const roles = await mongoAuthAdapter.getTenantRoles!(id, tenantId);
      expect(roles).not.toContain('admin');
      expect(roles).toContain('editor');
    });

    it('addTenantRole upserts for new tenant', async () => {
      const { id } = await mongoAuthAdapter.create('upsert@example.com', 'pw');
      await mongoAuthAdapter.addTenantRole!(id, 'new-tenant', 'member');
      expect(await mongoAuthAdapter.getTenantRoles!(id, 'new-tenant')).toEqual(['member']);
    });
  });
});

// Requires a running MongoDB instance.
// Run with: bun test tests/docker/permissions-mongo-adapter.test.ts
// Default connection: mongodb://localhost:27018/slingshot_test
// Override: TEST_MONGO_URL=<url> bun test tests/docker/permissions-mongo-adapter.test.ts
import { afterAll, beforeAll, beforeEach, describe, expect, test } from 'bun:test';
import mongoose from 'mongoose';
import { createMongoPermissionsAdapter } from '../../packages/slingshot-permissions/src/adapters/mongo';
import type { PermissionsMongoAdapter } from '../../packages/slingshot-permissions/src/adapters/mongo';

const MONGO_URI = process.env.TEST_MONGO_URL ?? 'mongodb://localhost:27018/slingshot_test';

describe('Permissions MongoDB adapter (docker)', () => {
  let conn: mongoose.Connection;
  let adapter: PermissionsMongoAdapter;

  beforeAll(async () => {
    conn = await mongoose.createConnection(MONGO_URI).asPromise();
    adapter = createMongoPermissionsAdapter(conn);
  });

  afterAll(async () => {
    await conn.close();
  });

  beforeEach(async () => {
    await adapter.clear();
  });

  // ---------------------------------------------------------------------------
  // Helpers
  // ---------------------------------------------------------------------------

  function makeGrant(overrides: Partial<Parameters<typeof adapter.createGrant>[0]> = {}) {
    return {
      subjectId: 'user-1',
      subjectType: 'user' as const,
      tenantId: null,
      resourceType: null,
      resourceId: null,
      roles: ['admin'],
      effect: 'allow' as const,
      grantedBy: 'system',
      ...overrides,
    };
  }

  // ---------------------------------------------------------------------------
  // createGrant
  // ---------------------------------------------------------------------------

  describe('createGrant', () => {
    test('creates a grant and returns its id', async () => {
      const id = await adapter.createGrant(makeGrant());
      expect(id).toBeDefined();
      expect(typeof id).toBe('string');
    });

    test('created grant is retrievable via getGrantsForSubject', async () => {
      const id = await adapter.createGrant(makeGrant({ roles: ['editor'] }));
      const grants = await adapter.getGrantsForSubject('user-1');
      expect(grants.length).toBe(1);
      expect(grants[0].id).toBe(id);
      expect(grants[0].roles).toEqual(['editor']);
      expect(grants[0].effect).toBe('allow');
      expect(grants[0].grantedAt).toBeInstanceOf(Date);
    });

    test('validation rejects grant without roles', async () => {
      await expect(adapter.createGrant(makeGrant({ roles: [] }))).rejects.toThrow(
        'at least one role',
      );
    });

    test('validation rejects resourceId without resourceType', async () => {
      await expect(
        adapter.createGrant(makeGrant({ resourceType: null, resourceId: 'res-1' })),
      ).rejects.toThrow('resourceId requires resourceType');
    });

    test('validation rejects invalid effect', async () => {
      await expect(adapter.createGrant(makeGrant({ effect: 'maybe' as any }))).rejects.toThrow(
        "effect must be 'allow' or 'deny'",
      );
    });

    test('stores optional reason', async () => {
      await adapter.createGrant(makeGrant({ reason: 'Promoted to admin' }));
      const grants = await adapter.getGrantsForSubject('user-1');
      expect(grants[0].reason).toBe('Promoted to admin');
    });

    test('stores expiresAt', async () => {
      const future = new Date(Date.now() + 86_400_000);
      await adapter.createGrant(makeGrant({ expiresAt: future }));
      const grants = await adapter.getGrantsForSubject('user-1');
      expect(grants[0].expiresAt).toBeInstanceOf(Date);
      expect(grants[0].expiresAt!.getTime()).toBe(future.getTime());
    });
  });

  // ---------------------------------------------------------------------------
  // revokeGrant
  // ---------------------------------------------------------------------------

  describe('revokeGrant', () => {
    test('revokes an existing grant', async () => {
      const id = await adapter.createGrant(makeGrant());
      const result = await adapter.revokeGrant(id, 'admin-1');
      expect(result).toBe(true);

      // Active grants should no longer include the revoked one
      const active = await adapter.getGrantsForSubject('user-1');
      expect(active.length).toBe(0);

      // History includes the revoked grant with revocation metadata
      const history = await adapter.listGrantHistory('user-1', 'user');
      expect(history[0].revokedBy).toBe('admin-1');
      expect(history[0].revokedAt).toBeInstanceOf(Date);
    });

    test('returns false for already-revoked grant', async () => {
      const id = await adapter.createGrant(makeGrant());
      await adapter.revokeGrant(id, 'admin-1');
      const result = await adapter.revokeGrant(id, 'admin-2');
      expect(result).toBe(false);
    });

    test('returns false for nonexistent grant', async () => {
      // Use a valid ObjectId format for Mongo
      const result = await adapter.revokeGrant('000000000000000000000000', 'admin-1');
      expect(result).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // getGrantsForSubject
  // ---------------------------------------------------------------------------

  describe('getGrantsForSubject', () => {
    test('returns all grants for a subject', async () => {
      await adapter.createGrant(makeGrant({ roles: ['admin'] }));
      await adapter.createGrant(makeGrant({ roles: ['editor'] }));
      const grants = await adapter.getGrantsForSubject('user-1');
      expect(grants.length).toBe(2);
    });

    test('filters by subjectType', async () => {
      await adapter.createGrant(makeGrant({ subjectType: 'user' }));
      await adapter.createGrant(makeGrant({ subjectId: 'user-1', subjectType: 'group' }));
      const userGrants = await adapter.getGrantsForSubject('user-1', 'user');
      expect(userGrants.length).toBe(1);
      expect(userGrants[0].subjectType).toBe('user');
    });

    test('filters by scope tenantId', async () => {
      await adapter.createGrant(makeGrant({ tenantId: 'tenant-a' }));
      await adapter.createGrant(makeGrant({ tenantId: 'tenant-b' }));
      const grants = await adapter.getGrantsForSubject('user-1', undefined, {
        tenantId: 'tenant-a',
      });
      expect(grants.length).toBe(1);
      expect(grants[0].tenantId).toBe('tenant-a');
    });

    test('filters by scope resourceType and resourceId', async () => {
      await adapter.createGrant(makeGrant({ resourceType: 'document', resourceId: 'doc-1' }));
      await adapter.createGrant(makeGrant({ resourceType: 'document', resourceId: 'doc-2' }));
      await adapter.createGrant(makeGrant({ resourceType: 'project', resourceId: 'proj-1' }));
      const grants = await adapter.getGrantsForSubject('user-1', undefined, {
        resourceType: 'document',
        resourceId: 'doc-1',
      });
      expect(grants.length).toBe(1);
      expect(grants[0].resourceId).toBe('doc-1');
    });

    test('returns empty array for unknown subject', async () => {
      const grants = await adapter.getGrantsForSubject('nonexistent');
      expect(grants).toEqual([]);
    });
  });

  // ---------------------------------------------------------------------------
  // listGrantsOnResource
  // ---------------------------------------------------------------------------

  describe('listGrantsOnResource', () => {
    test('returns grants targeting a specific resource', async () => {
      await adapter.createGrant(makeGrant({ resourceType: 'document', resourceId: 'doc-1' }));
      await adapter.createGrant(
        makeGrant({ subjectId: 'user-2', resourceType: 'document', resourceId: 'doc-1' }),
      );
      await adapter.createGrant(makeGrant({ resourceType: 'document', resourceId: 'doc-2' }));
      const grants = await adapter.listGrantsOnResource('document', 'doc-1');
      expect(grants.length).toBe(2);
      grants.forEach(g => {
        expect(g.resourceType).toBe('document');
        expect(g.resourceId).toBe('doc-1');
      });
    });

    test('scopes by tenantId', async () => {
      await adapter.createGrant(
        makeGrant({ tenantId: 'tenant-a', resourceType: 'document', resourceId: 'doc-1' }),
      );
      await adapter.createGrant(
        makeGrant({
          tenantId: 'tenant-b',
          resourceType: 'document',
          resourceId: 'doc-1',
          subjectId: 'user-2',
        }),
      );
      const grants = await adapter.listGrantsOnResource('document', 'doc-1', 'tenant-a');
      expect(grants.length).toBe(1);
      expect(grants[0].tenantId).toBe('tenant-a');
    });

    test('returns empty for resource with no grants', async () => {
      const grants = await adapter.listGrantsOnResource('document', 'nonexistent');
      expect(grants).toEqual([]);
    });
  });

  // ---------------------------------------------------------------------------
  // Wildcard grants (null resourceType / resourceId)
  // ---------------------------------------------------------------------------

  describe('wildcard grants', () => {
    test('grant with null resourceType applies to all resource types', async () => {
      const id = await adapter.createGrant(makeGrant({ resourceType: null, resourceId: null }));
      const grants = await adapter.getGrantsForSubject('user-1');
      expect(grants.length).toBe(1);
      expect(grants[0].id).toBe(id);
      expect(grants[0].resourceType).toBeNull();
      expect(grants[0].resourceId).toBeNull();
    });

    test('grant with resourceType but null resourceId applies to all instances', async () => {
      await adapter.createGrant(makeGrant({ resourceType: 'document', resourceId: null }));
      const grants = await adapter.getGrantsForSubject('user-1');
      expect(grants[0].resourceType).toBe('document');
      expect(grants[0].resourceId).toBeNull();
    });
  });

  // ---------------------------------------------------------------------------
  // Tenant-scoped grants
  // ---------------------------------------------------------------------------

  describe('tenant-scoped grants', () => {
    test('grants are isolated per tenant', async () => {
      await adapter.createGrant(makeGrant({ tenantId: 'tenant-a', roles: ['admin'] }));
      await adapter.createGrant(makeGrant({ tenantId: 'tenant-b', roles: ['viewer'] }));

      const tenantA = await adapter.getGrantsForSubject('user-1', undefined, {
        tenantId: 'tenant-a',
      });
      const tenantB = await adapter.getGrantsForSubject('user-1', undefined, {
        tenantId: 'tenant-b',
      });
      expect(tenantA.length).toBe(1);
      expect(tenantA[0].roles).toEqual(['admin']);
      expect(tenantB.length).toBe(1);
      expect(tenantB[0].roles).toEqual(['viewer']);
    });

    test('global grants (null tenantId) are separate from tenant-scoped', async () => {
      await adapter.createGrant(makeGrant({ tenantId: null }));
      await adapter.createGrant(makeGrant({ tenantId: 'tenant-a' }));
      const all = await adapter.getGrantsForSubject('user-1');
      expect(all.length).toBe(2);
    });
  });

  // ---------------------------------------------------------------------------
  // deleteAllGrantsForSubject
  // ---------------------------------------------------------------------------

  describe('deleteAllGrantsForSubject', () => {
    test('deletes all grants for a subject', async () => {
      await adapter.createGrant(makeGrant());
      await adapter.createGrant(makeGrant({ roles: ['editor'] }));
      await adapter.createGrant(makeGrant({ subjectId: 'user-2' }));

      await adapter.deleteAllGrantsForSubject({ subjectId: 'user-1', subjectType: 'user' });
      const user1Grants = await adapter.getGrantsForSubject('user-1');
      expect(user1Grants.length).toBe(0);

      const user2Grants = await adapter.getGrantsForSubject('user-2');
      expect(user2Grants.length).toBe(1);
    });

    test('scopes by subjectType', async () => {
      await adapter.createGrant(makeGrant({ subjectType: 'user' }));
      await adapter.createGrant(makeGrant({ subjectId: 'user-1', subjectType: 'group' }));

      await adapter.deleteAllGrantsForSubject({ subjectId: 'user-1', subjectType: 'user' });
      const remaining = await adapter.getGrantsForSubject('user-1');
      expect(remaining.length).toBe(1);
      expect(remaining[0].subjectType).toBe('group');
    });
  });

  // ---------------------------------------------------------------------------
  // clear
  // ---------------------------------------------------------------------------

  describe('clear', () => {
    test('removes all grants', async () => {
      await adapter.createGrant(makeGrant());
      await adapter.createGrant(makeGrant({ subjectId: 'user-2' }));
      await adapter.clear();
      const grants1 = await adapter.getGrantsForSubject('user-1');
      const grants2 = await adapter.getGrantsForSubject('user-2');
      expect(grants1.length).toBe(0);
      expect(grants2.length).toBe(0);
    });
  });
});

