describe('plugin lifecycle — teardown ordering', () => {
  const teardownOrder: string[] = [];

  const teardownA: SlingshotPlugin = {
    name: 'teardown-a',
    setupPost: async () => {},
    teardown: async () => {
      teardownOrder.push('a');
    },
  };

  const teardownB: SlingshotPlugin = {
    name: 'teardown-b',
    dependencies: ['teardown-a'],
    setupPost: async () => {},
