describe('SSE E2E — event delivery', () => {
  test('emit matching event on bus → formatted event appears in response body', async () => {
    const { url, cleanup, bus } = await createTestFullServer({
      sse: {
        endpoints: {
          '/__sse/feed': {
            events: ['community:thread.created'],
            heartbeat: false,
          },
        },
      },
    });

    const res = await fetch(`${url}/__sse/feed`);
    expect(res.status).toBe(200);

    // Give the stream a moment to register the client
    await new Promise(r => setTimeout(r, 50));

    // Emit on the bus
    (bus as unknown as DynamicEventBus).emit('community:thread.created', {
      id: 'thread-1',
      title: 'Hello',
    });

    const events = await readSseEvents(res, 1);
    expect(events.length).toBeGreaterThan(0);
    const eventLine = events.find(e => e.includes('community:thread.created'));
    expect(eventLine).toBeDefined();
    expect(eventLine).toContain('thread-1');

    await res.body?.cancel();
    await cleanup();
  });

  test('emit event NOT in epConfig.events → does not appear in stream', async () => {
    const { url, cleanup, bus } = await createTestFullServer({
      sse: {
        endpoints: {
          '/__sse/feed': {
            events: ['community:thread.created'],
            heartbeat: false,
          },
        },
      },
    });

    const res = await fetch(`${url}/__sse/feed`);
    expect(res.status).toBe(200);

    await new Promise(r => setTimeout(r, 50));

    // Emit an event NOT in the list
    (bus as unknown as DynamicEventBus).emit('community:reply.created', { id: 'reply-1' });

    const events = await readSseEvents(res, 1, 300);
    const replyEvent = events.find(e => e.includes('community:reply.created'));
    expect(replyEvent).toBeUndefined();

    await res.body?.cancel();
    await cleanup();
  });

  test('filter suppresses event when filter returns false', async () => {
    const { url, cleanup, bus } = await createTestFullServer({
      sse: {
        endpoints: {
          '/__sse/feed': {
            events: ['community:thread.created'],
            heartbeat: false,
            filter: () => false,
          },
        },
      },
    });

    const res = await fetch(`${url}/__sse/feed`);
    expect(res.status).toBe(200);

    await new Promise(r => setTimeout(r, 50));
    (bus as unknown as DynamicEventBus).emit('community:thread.created', { id: 'thread-x' });

    const events = await readSseEvents(res, 1, 300);
    const eventLine = events.find(e => e.includes('community:thread.created'));
    expect(eventLine).toBeUndefined();

    await res.body?.cancel();
    await cleanup();
  });

  test('registered custom client-safe events stream successfully', async () => {
    const customEvent = 'content:test.document.created';
    // Create a bus instance and register the custom event before server creation
    const customBus = createInProcessAdapter();
    customBus.registerClientSafeEvents([customEvent]);

    const { url, cleanup, bus } = await createTestFullServer({
      eventBus: customBus,
      sse: {
        endpoints: {
          '/__sse/feed': {
            events: [customEvent],
            heartbeat: false,
          },
        },
      },
    });

    const res = await fetch(`${url}/__sse/feed`);
    expect(res.status).toBe(200);

    await new Promise(r => setTimeout(r, 50));
    (bus as any).emit(customEvent, { id: 'doc-1', title: 'Registered custom event' });

    const events = await readSseEvents(res, 1);
    expect(events.length).toBeGreaterThan(0);
    const eventLine = events.find(e => e.includes(customEvent));
    expect(eventLine).toBeDefined();
    expect(eventLine).toContain('doc-1');

    await res.body?.cancel();
    await cleanup();
  });
});

describe('SSE E2E — disconnect', () => {
  test('after cancel, no further chunks arrive on reader', async () => {
    const { url, cleanup, bus } = await createTestFullServer({
      sse: {
        endpoints: {
          '/__sse/feed': {
            events: ['community:thread.created'],
            heartbeat: false,
          },
        },
      },
    });

    const res = await fetch(`${url}/__sse/feed`);
    const reader = res.body!.getReader();

    // Read ': connected' comment
    await reader.read();

    // Cancel the stream
    reader.releaseLock();
    await res.body!.cancel();

    // Give server a moment to process the disconnect
    await new Promise(r => setTimeout(r, 100));

    // Emit — should not raise errors on server side
    (bus as unknown as DynamicEventBus).emit('community:thread.created', {
      id: 'after-disconnect',
    });

    // No assertion on reader since it's cancelled — just verify no server error / hang
    await cleanup();
  });
});

/**
 * E2E tests for the slingshot-webhooks plugin.
 *
 * Management routes are hardened behind user auth + admin role checks, so these
 * tests create authenticated admin sessions unless they are explicitly testing
 * unauthorised or forbidden access.
 */
import { afterEach, beforeEach, describe, expect, test } from 'bun:test';
import { createWebhookPlugin } from '@lastshotlabs/slingshot-webhooks';
import { createWebhookMemoryQueue } from '@lastshotlabs/slingshot-webhooks/testing';
import type { E2EServerHandle } from '../../src/testing';
import { authHeader, createMemoryAuthAdapter } from '../setup';
import { createTestHttpServer } from '../setup-e2e';

const TEST_TENANT_ID = 'tenant-a';

function makeWebhookPlugin(
  opts: {
    requireAuth?: boolean;
    events?: string[];
  } = {},
) {
  const queue = createWebhookMemoryQueue({ maxAttempts: 1 });

  const plugin = createWebhookPlugin({
    queue,
    events: opts.events ?? ['user.*', 'order.*'],
    managementRole: opts.requireAuth ? 'admin' : undefined,
  });

  return { queue, plugin };
}

async function registerSession(
  baseUrl: string,
  emailPrefix: string,
): Promise<{ headers: Record<string, string>; userId: string }> {
  const res = await fetch(`${baseUrl}/auth/register`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      email: `${emailPrefix}-${crypto.randomUUID()}@example.com`,
      password: 'password123',
    }),
  });
  expect(res.status).toBe(201);
  const body = (await res.json()) as { token: string; userId: string };
  return { headers: authHeader(body.token), userId: body.userId };
}

function withJson(headers: Record<string, string>): Record<string, string> {
  return { 'Content-Type': 'application/json', ...headers };
}

function withTenant(headers: Record<string, string> = {}): Record<string, string> {
  return { 'x-tenant-id': TEST_TENANT_ID, ...headers };
}

async function createAuthedHandle(
  plugin: ReturnType<typeof makeWebhookPlugin>['plugin'],
  role: 'admin' | 'user',
  emailPrefix: string,
): Promise<{ handle: E2EServerHandle; headers: Record<string, string> }> {
  const adapter = createMemoryAuthAdapter();
  const handle = await createTestHttpServer(
    {
      plugins: [plugin],
      tenancy: {
        resolution: 'header',
        headerName: 'x-tenant-id',
        onResolve: async tenantId => (tenantId === TEST_TENANT_ID ? { id: tenantId } : null),
      },
    },
    { auth: { adapter, defaultRole: role } },
  );
  const session = await registerSession(handle.baseUrl, emailPrefix);
  if (role === 'admin') {
    await adapter.setTenantRoles?.(session.userId, TEST_TENANT_ID, ['admin']);
  }
  return { handle, headers: withTenant(session.headers) };
}

