import { checkBreachedPassword } from '@auth/lib/breachedPassword';
import { describe, expect, spyOn, test } from 'bun:test';

const noopEventBus = {
  emit: () => {},
  on: () => {},
  off: () => {},
} as any;

describe('checkBreachedPassword', () => {
  test('returns not breached when suffix not in response', async () => {
    // Mock fetch to return a response that doesn't include our hash suffix
    const mockFetch = spyOn(globalThis, 'fetch').mockResolvedValueOnce(
      new Response(
        '00000000000000000000000000000000000:5\r\nFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF:3',
        {
          status: 200,
        },
      ),
    );

    const result = await checkBreachedPassword(
      'verysecurepassword123!',
      undefined,
      undefined,
      noopEventBus,
    );
    expect(result.breached).toBe(false);
    expect(result.count).toBe(0);
    mockFetch.mockRestore();
  });

  test('returns breached: false on API failure with onApiFailure=allow', async () => {
    const mockFetch = spyOn(globalThis, 'fetch').mockRejectedValueOnce(new Error('Network error'));

    const result = await checkBreachedPassword(
      'password',
      { onApiFailure: 'allow' },
      undefined,
      noopEventBus,
    );
    expect(result.breached).toBe(false);
    mockFetch.mockRestore();
  });

  test('returns breached: true on API failure with onApiFailure=block', async () => {
    const mockFetch = spyOn(globalThis, 'fetch').mockRejectedValueOnce(new Error('Network error'));

    const result = await checkBreachedPassword(
      'password',
      { onApiFailure: 'block' },
      undefined,
      noopEventBus,
    );
    expect(result.breached).toBe(true);
    mockFetch.mockRestore();
  });

  test('respects minBreachCount', async () => {
    // Mock returns empty body — suffix won't be found, count=0 < minBreachCount=10
    const mockFetch = spyOn(globalThis, 'fetch').mockResolvedValueOnce(
      new Response('', { status: 200 }),
    );

    const result = await checkBreachedPassword(
      'somepassword',
      { minBreachCount: 10 },
      undefined,
      noopEventBus,
    );
    expect(result.breached).toBe(false); // count=0 < minBreachCount=10
    mockFetch.mockRestore();
  });
});

import type { OpenAPIHono } from '@hono/zod-openapi';
import { beforeEach, describe, expect, test } from 'bun:test';
import { authHeader, createTestApp } from '../setup';

let app: OpenAPIHono<any>;

beforeEach(async () => {
  app = await createTestApp(
    {},
    {
      auth: {
        enabled: true,
        roles: ['admin', 'user'],
        defaultRole: 'user',
        refreshTokens: {
          accessTokenExpiry: 900,
          refreshTokenExpiry: 86400,
          rotationGraceSeconds: 2,
        },
      },
    },
  );
});

const json = (body: Record<string, unknown>) => ({
  method: 'POST' as const,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body),
});

// ---------------------------------------------------------------------------
// Concurrent refresh token rotation
// ---------------------------------------------------------------------------

describe('concurrent refresh token rotation', () => {
  test('two concurrent refreshes from the same token — at least one succeeds', async () => {
    // Register a user and get a refresh token
    const regRes = await app.request(
      '/auth/register',
      json({
        email: 'concurrent-rt@example.com',
        password: 'password123',
      }),
    );
    expect(regRes.status).toBe(201);
    const { refreshToken: rt1 } = await regRes.json();
    expect(rt1).toBeString();

    // Fire two concurrent refresh requests with the same token
    const [res1, res2] = await Promise.all([
      app.request('/auth/refresh', json({ refreshToken: rt1 })),
      app.request('/auth/refresh', json({ refreshToken: rt1 })),
    ]);

    const status1 = res1.status;
    const status2 = res2.status;

    // At least one must succeed
    expect(status1 === 200 || status2 === 200).toBe(true);

    // Collect successful responses
    const successes: Array<{ token: string; refreshToken: string; userId: string }> = [];
    if (status1 === 200) successes.push(await res1.json());
    if (status2 === 200) successes.push(await res2.json());

    // Each successful response returns a new, distinct refresh token
    for (const s of successes) {
      expect(s.refreshToken).toBeString();
      expect(s.refreshToken).not.toBe(rt1);
      expect(s.token).toBeString();
      expect(s.userId).toBeString();
    }

    // If both succeeded (grace window), the tokens should differ
    if (successes.length === 2) {
      // Both rotations produce distinct refresh tokens
      expect(successes[0].refreshToken).not.toBe(successes[1].refreshToken);
    }
  });

  test('old refresh token is rejected after grace window expires', async () => {
    const regRes = await app.request(
      '/auth/register',
      json({
        email: 'invalidate-rt@example.com',
        password: 'password123',
      }),
    );
    const { refreshToken: rt1 } = await regRes.json();

    // Rotate once
    const refreshRes = await app.request('/auth/refresh', json({ refreshToken: rt1 }));
    expect(refreshRes.status).toBe(200);

    // Wait beyond grace window (grace is 2s, wait 3s)
    await Bun.sleep(3000);

    // Old token should now be fully invalidated (past grace window → theft detection).
    // Theft detection invalidates the entire session — this is correct security behavior.
    const oldRes = await app.request('/auth/refresh', json({ refreshToken: rt1 }));
    expect(oldRes.status).toBe(401);
  });

  test('old refresh token works within grace window', async () => {
    const regRes = await app.request(
      '/auth/register',
      json({
        email: 'grace-rt@example.com',
        password: 'password123',
      }),
    );
    const { refreshToken: rt1 } = await regRes.json();

    // Rotate once
    const refreshRes = await app.request('/auth/refresh', json({ refreshToken: rt1 }));
    expect(refreshRes.status).toBe(200);

    // Immediately use old token (within 2s grace window) — should succeed
    const graceRes = await app.request('/auth/refresh', json({ refreshToken: rt1 }));
    expect(graceRes.status).toBe(200);
  });

  test('no duplicate sessions are created by concurrent refreshes', async () => {
    const regRes = await app.request(
      '/auth/register',
      json({
        email: 'no-dup-sessions@example.com',
        password: 'password123',
      }),
    );
    const { refreshToken: rt1, token } = await regRes.json();

    // Count sessions before
    const beforeRes = await app.request('/auth/sessions', { headers: authHeader(token) });
    const { sessions: beforeSessions } = await beforeRes.json();
    const sessionCountBefore = beforeSessions.length;

    // Fire concurrent refreshes
    const results = await Promise.all([
      app.request('/auth/refresh', json({ refreshToken: rt1 })),
      app.request('/auth/refresh', json({ refreshToken: rt1 })),
    ]);

    // Get a valid token from the successful response(s)
    let validToken: string | null = null;
    for (const r of results) {
      if (r.status === 200) {
        const body = await r.json();
        validToken = body.token;
      }
    }
    expect(validToken).not.toBeNull();

    // Check session count — should not have increased (refresh rotates, does not create)
    const afterRes = await app.request('/auth/sessions', { headers: authHeader(validToken!) });
    const { sessions: afterSessions } = await afterRes.json();
    expect(afterSessions.length).toBe(sessionCountBefore);
  });

  test('concurrent refreshes from different sessions succeed independently', async () => {
    // Register and login to create two separate sessions with their own refresh tokens
    const regRes = await app.request(
      '/auth/register',
      json({
        email: 'multi-device@example.com',
        password: 'password123',
      }),
    );
    const { refreshToken: rt1 } = await regRes.json();

    const loginRes = await app.request(
      '/auth/login',
      json({
        email: 'multi-device@example.com',
        password: 'password123',
      }),
    );
    const { refreshToken: rt2 } = await loginRes.json();

    // Both tokens are distinct (different sessions)
    expect(rt1).not.toBe(rt2);

    // Refresh both concurrently
    const [res1, res2] = await Promise.all([
      app.request('/auth/refresh', json({ refreshToken: rt1 })),
      app.request('/auth/refresh', json({ refreshToken: rt2 })),
    ]);

    // Both should succeed — they are independent sessions
    expect(res1.status).toBe(200);
    expect(res2.status).toBe(200);

    const body1 = await res1.json();
    const body2 = await res2.json();

    expect(body1.refreshToken).toBeString();
    expect(body2.refreshToken).toBeString();
    expect(body1.refreshToken).not.toBe(body2.refreshToken);
  });
});

import type { OpenAPIHono } from '@hono/zod-openapi';
import { beforeEach, describe, expect, test } from 'bun:test';
import { authHeader, createTestApp } from '../setup';

const json = (body: Record<string, unknown>) => ({
  method: 'POST' as const,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body),
});

// ---------------------------------------------------------------------------
// Concurrent session creation at maxSessions limit
// ---------------------------------------------------------------------------

describe('concurrent session creation at maxSessions limit', () => {
  let app: OpenAPIHono<any>;

  beforeEach(async () => {
    app = await createTestApp(
      {},
      {
        auth: {
          enabled: true,
          roles: ['admin', 'user'],
          defaultRole: 'user',
          sessionPolicy: { maxSessions: 3 },
        },
      },
    );
  });

  test('total sessions never exceed maxSessions after concurrent logins', async () => {
    // Register user (creates session 1)
    const regRes = await app.request(
      '/auth/register',
      json({
        email: 'concurrent-sess@example.com',
        password: 'password123',
      }),
    );
    expect(regRes.status).toBe(201);
    await regRes.json();

    // Login to create session 2
    const login1 = await app.request(
      '/auth/login',
      json({
        email: 'concurrent-sess@example.com',
        password: 'password123',
      }),
    );
    expect(login1.status).toBe(200);

    // Now we have 2 sessions, maxSessions is 3.
    // Fire two concurrent logins — both try to create session 3 and 4.
    // The atomic session creation should ensure total never exceeds 3.
    const [res1, res2] = await Promise.all([
      app.request(
        '/auth/login',
        json({
          email: 'concurrent-sess@example.com',
          password: 'password123',
        }),
      ),
      app.request(
        '/auth/login',
        json({
          email: 'concurrent-sess@example.com',
          password: 'password123',
        }),
      ),
    ]);

    // Both logins should succeed (the system evicts oldest to make room)
    expect(res1.status).toBe(200);
    expect(res2.status).toBe(200);

    // Get a valid token from one of the responses
    const { token: validToken } = await res1.json();

    // Check total sessions — must not exceed maxSessions (3)
    const sessionsRes = await app.request('/auth/sessions', {
      headers: authHeader(validToken),
    });
    expect(sessionsRes.status).toBe(200);
    const { sessions } = await sessionsRes.json();
    const activeSessions = sessions.filter((s: any) => s.isActive);
    expect(activeSessions.length).toBeLessThanOrEqual(3);
    expect(activeSessions.length).toBeGreaterThanOrEqual(1);
  });

  test('evicts oldest sessions correctly under concurrent pressure', async () => {
    // Register creates session 1
    await app.request(
      '/auth/register',
      json({
        email: 'evict-concurrent@example.com',
        password: 'password123',
      }),
    );

    // Fill to maxSessions (3)
    await app.request(
      '/auth/login',
      json({
        email: 'evict-concurrent@example.com',
        password: 'password123',
      }),
    );
    await app.request(
      '/auth/login',
      json({
        email: 'evict-concurrent@example.com',
        password: 'password123',
      }),
    );

    // Now at 3 sessions. Two more concurrent logins should evict the oldest.
    const [res1, res2] = await Promise.all([
      app.request(
        '/auth/login',
        json({
          email: 'evict-concurrent@example.com',
          password: 'password123',
        }),
      ),
      app.request(
        '/auth/login',
        json({
          email: 'evict-concurrent@example.com',
          password: 'password123',
        }),
      ),
    ]);

    expect(res1.status).toBe(200);
    expect(res2.status).toBe(200);

    const { token } = await res2.json();

    // Verify session count is bounded
    const sessionsRes = await app.request('/auth/sessions', {
      headers: authHeader(token),
    });
    const { sessions } = await sessionsRes.json();
    const active = sessions.filter((s: any) => s.isActive);
    expect(active.length).toBeLessThanOrEqual(3);
  });

  test('concurrent logins for different users do not interfere', async () => {
    // Register two different users
    await app.request(
      '/auth/register',
      json({
        email: 'user-a@example.com',
        password: 'password123',
      }),
    );
    await app.request(
      '/auth/register',
      json({
        email: 'user-b@example.com',
        password: 'password123',
      }),
    );

    // Concurrent logins for both users
    const [resA, resB] = await Promise.all([
      app.request(
        '/auth/login',
        json({
          email: 'user-a@example.com',
          password: 'password123',
        }),
      ),
      app.request(
        '/auth/login',
        json({
          email: 'user-b@example.com',
          password: 'password123',
        }),
      ),
    ]);

    expect(resA.status).toBe(200);
    expect(resB.status).toBe(200);

    const { token: tokenA } = await resA.json();
    const { token: tokenB } = await resB.json();

    // Each user should have their own sessions (2 each: register + login)
    const sessA = await app.request('/auth/sessions', { headers: authHeader(tokenA) });
    const sessB = await app.request('/auth/sessions', { headers: authHeader(tokenB) });

    const { sessions: sessionsA } = await sessA.json();
    const { sessions: sessionsB } = await sessB.json();

    expect(sessionsA.length).toBe(2);
    expect(sessionsB.length).toBe(2);
  });

  test('maxSessions=1 with concurrent logins results in exactly 1 active session', async () => {
    // Separate app with maxSessions=1
    const strictApp = await createTestApp(
      {},
      {
        auth: {
          enabled: true,
          roles: ['admin', 'user'],
          defaultRole: 'user',
          sessionPolicy: { maxSessions: 1 },
        },
      },
    );

    await strictApp.request(
      '/auth/register',
      json({
        email: 'strict-max@example.com',
        password: 'password123',
      }),
    );

    // Three concurrent logins
    const results = await Promise.all([
      strictApp.request(
        '/auth/login',
        json({
          email: 'strict-max@example.com',
          password: 'password123',
        }),
      ),
      strictApp.request(
        '/auth/login',
        json({
          email: 'strict-max@example.com',
          password: 'password123',
        }),
      ),
      strictApp.request(
        '/auth/login',
        json({
          email: 'strict-max@example.com',
          password: 'password123',
        }),
      ),
    ]);

    // All logins should succeed
    for (const r of results) {
      expect(r.status).toBe(200);
    }

    // Try each token to find one whose session is still active.
    // With maxSessions=1, earlier sessions get evicted by later logins,
    // so only the last-to-execute login's token is still valid.
    let validToken: string | null = null;
    const bodies = await Promise.all(results.map(r => r.json()));
    for (const body of bodies) {
      const sessionsRes = await strictApp.request('/auth/sessions', {
        headers: authHeader(body.token),
      });
      if (sessionsRes.status === 200) {
        const { sessions } = await sessionsRes.json();
        const active = sessions.filter((s: any) => s.isActive);
        // The key invariant: never more than maxSessions
        expect(active.length).toBeLessThanOrEqual(1);
        if (active.length > 0) validToken = body.token;
      }
    }

    // At least one session must survive
    expect(validToken).not.toBeNull();
  });
});

import type { OpenAPIHono } from '@hono/zod-openapi';
import { beforeEach, describe, expect, it } from 'bun:test';
import { createTestApp } from '../setup';

// ---------------------------------------------------------------------------
// Hono CORS behaviour via createTestApp (security.cors config)
// ---------------------------------------------------------------------------

describe('CORS — wildcard (*)', () => {
  let app: OpenAPIHono<any>;

  beforeEach(async () => {
    app = await createTestApp({
      security: { cors: '*', rateLimit: { windowMs: 60_000, max: 1000 } },
    });
  });

  it('sets Access-Control-Allow-Origin: * for any origin', async () => {
    const res = await app.request('/health', {
      headers: { Origin: 'http://random.com' },
    });
    expect(res.headers.get('access-control-allow-origin')).toBe('*');
  });

  it('OPTIONS preflight returns 204', async () => {
    const res = await app.request('/health', { method: 'OPTIONS' });
    expect(res.status).toBe(204);
  });
});

describe('CORS — specific origin allowlist', () => {
  let app: OpenAPIHono<any>;

  beforeEach(async () => {
    app = await createTestApp({
      security: {
        cors: ['http://allowed.example.com', 'http://also-allowed.example.com'],
        rateLimit: { windowMs: 60_000, max: 1000 },
      },
    });
  });

  it('reflects the allowed origin in ACAO header', async () => {
    const res = await app.request('/health', {
      headers: { Origin: 'http://allowed.example.com' },
    });
    expect(res.headers.get('access-control-allow-origin')).toBe('http://allowed.example.com');
  });

  it('sets Access-Control-Allow-Credentials: true for allowed origin', async () => {
    const res = await app.request('/health', {
      headers: { Origin: 'http://allowed.example.com' },
    });
    expect(res.headers.get('access-control-allow-credentials')).toBe('true');
  });

  it('allows second origin in the list', async () => {
    const res = await app.request('/health', {
      headers: { Origin: 'http://also-allowed.example.com' },
    });
    expect(res.headers.get('access-control-allow-origin')).toBe('http://also-allowed.example.com');
  });

  it('does not reflect a non-matching origin in ACAO header', async () => {
    const res = await app.request('/health', {
      headers: { Origin: 'http://evil.example.com' },
    });
    // Hono's cors does not echo back an origin that isn't in the allowlist
    expect(res.headers.get('access-control-allow-origin')).not.toBe('http://evil.example.com');
  });

  it('OPTIONS preflight returns 204', async () => {
    const res = await app.request('/health', {
      method: 'OPTIONS',
      headers: { Origin: 'http://allowed.example.com' },
    });
    expect(res.status).toBe(204);
  });
});

import {
  type CredentialStuffingService,
  createCredentialStuffingService,
  createMemoryCredentialStuffingRepository,
} from '@auth/lib/credentialStuffing';
import { describe, expect, test } from 'bun:test';

let svc: CredentialStuffingService;

describe('credential stuffing — isStuffingBlocked', () => {
  test('not blocked below threshold', async () => {
    svc = createCredentialStuffingService(
      { maxAccountsPerIp: { count: 3, windowMs: 60000 } },
      createMemoryCredentialStuffingRepository(),
    );
    await svc.trackFailedLogin('1.2.3.4', 'user1@example.com');
    await svc.trackFailedLogin('1.2.3.4', 'user2@example.com');
    expect(await svc.isStuffingBlocked('1.2.3.4', 'user3@example.com')).toBe(false);
  });

  test('blocked when accounts-per-IP exceeds threshold', async () => {
    svc = createCredentialStuffingService(
      { maxAccountsPerIp: { count: 3, windowMs: 60000 } },
      createMemoryCredentialStuffingRepository(),
    );
    await svc.trackFailedLogin('1.2.3.4', 'user1@example.com');
    await svc.trackFailedLogin('1.2.3.4', 'user2@example.com');
    await svc.trackFailedLogin('1.2.3.4', 'user3@example.com');
    expect(await svc.isStuffingBlocked('1.2.3.4', 'user4@example.com')).toBe(true);
  });

  test('blocked when IPs-per-account exceeds threshold', async () => {
    svc = createCredentialStuffingService(
      { maxIpsPerAccount: { count: 3, windowMs: 60000 } },
      createMemoryCredentialStuffingRepository(),
    );
    await svc.trackFailedLogin('1.1.1.1', 'target@example.com');
    await svc.trackFailedLogin('2.2.2.2', 'target@example.com');
    await svc.trackFailedLogin('3.3.3.3', 'target@example.com');
    expect(await svc.isStuffingBlocked('4.4.4.4', 'target@example.com')).toBe(true);
  });

  test("repeated same IP+account doesn't inflate set size", async () => {
    svc = createCredentialStuffingService(
      { maxAccountsPerIp: { count: 3, windowMs: 60000 } },
      createMemoryCredentialStuffingRepository(),
    );
    await svc.trackFailedLogin('1.2.3.4', 'user1@example.com');
    await svc.trackFailedLogin('1.2.3.4', 'user1@example.com');
    await svc.trackFailedLogin('1.2.3.4', 'user1@example.com');
    // Still only 1 unique account, threshold is 3
    expect(await svc.isStuffingBlocked('1.2.3.4', 'user2@example.com')).toBe(false);
  });

  test('onDetected callback is called when blocked', async () => {
    const detected: any[] = [];
    svc = createCredentialStuffingService(
      {
        maxAccountsPerIp: { count: 2, windowMs: 60000 },
        onDetected: signal => {
          detected.push(signal);
        },
      },
      createMemoryCredentialStuffingRepository(),
    );
    await svc.trackFailedLogin('1.2.3.4', 'user1@example.com');
    await svc.trackFailedLogin('1.2.3.4', 'user2@example.com');
    await svc.isStuffingBlocked('1.2.3.4', 'user3@example.com');
    expect(detected.length).toBe(1);
    expect(detected[0].type).toBe('ip');
  });
});

