      }),
    ).rejects.toThrow(/already exists|duplicate/i);
  });

  test('listM2MClients returns created clients', async () => {
    await createM2MClient({
      adapter: memoryAuthAdapter,
      clientId: 'c1',
      name: 'C1',
      password: runtimePassword,
      scopes: [],
    });
    await createM2MClient({
      adapter: memoryAuthAdapter,
