import type { OpenAPIHono } from '@hono/zod-openapi';
import { beforeEach, describe, expect, it } from 'bun:test';
import { getAuthRuntimeContext } from '@lastshotlabs/slingshot-auth';
import { getContext } from '@lastshotlabs/slingshot-core';
import { createTestApp } from '../setup';

// ---------------------------------------------------------------------------
// Setup: app with email verification enabled + /protected/verified fixture route
// ---------------------------------------------------------------------------

describe('requireVerifiedEmail middleware', () => {
  let app: OpenAPIHono<any>;
  const getRuntime = (targetApp: object) =>
    getAuthRuntimeContext(getContext(targetApp).pluginState);

  beforeEach(async () => {
    app = await createTestApp(
      {},
      {
        auth: {
          enabled: true,
          roles: ['user'],
          defaultRole: 'user',
          emailVerification: {
            required: false, // required:false means verification is optional for login, but enforced by middleware
          },
        },
      },
    );
  });

  // ---------------------------------------------------------------------------
  // Unauthenticated request
  // ---------------------------------------------------------------------------

  it('returns 401 when no token is provided (via userAuth)', async () => {
    const res = await app.request('/protected/verified');
    expect(res.status).toBe(401);
    const body = await res.json();
    expect(body.error).toBeDefined();
  });

  it('returns 401 from requireVerifiedEmail itself when userId is null', async () => {
    // /protected/verified-no-auth uses requireVerifiedEmail WITHOUT userAuth,
    // so the 401 comes from requireVerifiedEmail's own null-userId check (line 17)
    const res = await app.request('/protected/verified-no-auth');
    expect(res.status).toBe(401);
    const body = await res.json();
    expect(body.error).toBe('Unauthorized');
  });

  // ---------------------------------------------------------------------------
  // Authenticated but email not verified
  // ---------------------------------------------------------------------------

  it("returns 403 when authenticated user's email is not verified", async () => {
    const reg = await app.request('/auth/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: 'unverified@test.com', password: 'password123' }),
    });
    expect(reg.status).toBe(201);
    const { token } = await reg.json();

    // Email is not verified after registration (emailVerification.required: false)
    const res = await app.request('/protected/verified', {
      headers: { 'x-user-token': token },
    });
    expect(res.status).toBe(403);
    const body = await res.json();
    expect(body.error).toMatch(/email not verified/i);
  });

  // ---------------------------------------------------------------------------
  // Authenticated with verified email
  // ---------------------------------------------------------------------------

  it("returns 200 when authenticated user's email is verified", async () => {
    const reg = await app.request('/auth/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: 'verified@test.com', password: 'password123' }),
    });
    expect(reg.status).toBe(201);
    const { token, userId } = await reg.json();

    // Directly mark email as verified via the adapter
    const adapter = getRuntime(app).adapter;
    await adapter.setEmailVerified!(userId, true);

    const res = await app.request('/protected/verified', {
      headers: { 'x-user-token': token },
    });
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.ok).toBe(true);
  });

  // ---------------------------------------------------------------------------
  // Full verification token flow
  // ---------------------------------------------------------------------------

  it('allows access after completing the email verification token flow', async () => {
    let capturedToken = '';

    // Create a fresh app that captures the verification token
    const appWithCapture = await createTestApp(
      {},
      {
        auth: {
          enabled: true,
          roles: ['user'],
          defaultRole: 'user',
          emailVerification: {
            required: false,
          },
        },
      },
    );

    // Register listener AFTER createTestApp so we get the bus set by the plugin
    const evHandler = (payload: { token: string }) => {
      capturedToken = payload.token;
    };
    getRuntime(appWithCapture).eventBus.on('auth:delivery.email_verification', evHandler);

    const reg = await appWithCapture.request('/auth/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email: 'flow@test.com', password: 'password123' }),
    });
    const { token: jwt } = await reg.json();

    // Use the verification token
    const verifyRes = await appWithCapture.request('/auth/verify-email', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-user-token': jwt,
      },
      body: JSON.stringify({ token: capturedToken }),
    });
    expect(verifyRes.status).toBe(200);

    // Now the protected route should be accessible
    const res = await appWithCapture.request('/protected/verified', {
      headers: { 'x-user-token': jwt },
    });
    getRuntime(appWithCapture).eventBus.off('auth:delivery.email_verification', evHandler);
    expect(res.status).toBe(200);
  });
});

/**
 * Integration tests for the POST /auth/reset-password route with password
 * history enforcement.
 *
 * Uses `makeTestRuntime` + `createResetToken` to inject a real reset token
 * directly into the repo (bypassing email delivery) so the route can be
 * exercised end-to-end without a mail transport.
 *
 * Covers:
 *   - Reset-password with a previously-used password returns 400 PASSWORD_PREVIOUSLY_USED
 *   - Reset-password with a new password returns 200 { ok: true }
 *   - Reset token is single-use: second attempt with the same token returns 400
 *   - All active sessions are revoked after a successful reset
 */
import { recordPasswordChange } from '@auth/lib/passwordHistory';
import { createResetToken } from '@auth/lib/resetPassword';
import { createPasswordResetRouter } from '@auth/routes/passwordReset';
import { beforeEach, describe, expect, test } from 'bun:test';
import {
  makeTestRuntime,
  wrapWithRuntime,
} from '../../packages/slingshot-auth/tests/helpers/runtime';

const json = (body: Record<string, unknown>) => ({
  method: 'POST' as const,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body),
});

function buildApp(runtime: ReturnType<typeof makeTestRuntime>) {
  const app = wrapWithRuntime(runtime);
  app.onError((err: any, c) => c.json({ error: err.message, code: err?.code }, err?.status ?? 500));
  app.route('/', createPasswordResetRouter({}, runtime));
  return app;
}

describe('POST /auth/reset-password — password history enforcement', () => {
  let runtime: ReturnType<typeof makeTestRuntime>;

  beforeEach(() => {
    runtime = makeTestRuntime({
      passwordReset: { tokenExpiry: 3600 },
      passwordPolicy: { preventReuse: 3 },
    });
  });

  test('previously-used password returns 400 PASSWORD_PREVIOUSLY_USED', async () => {
    const email = 'rh-reuse@example.com';
    const initialHash = await Bun.password.hash('InitialPass1!');
    const { id: userId } = await runtime.adapter.create(email, initialHash);
    // Seed 'InitialPass1!' into history so the route sees it as reused
    await recordPasswordChange(runtime.adapter, userId, initialHash, 5);

    const rawToken = await createResetToken(
      runtime.repos.resetToken,
      userId,
      email,
      runtime.config,
    );

    const app = buildApp(runtime);
    const res = await app.request(
      '/auth/reset-password',
      json({ token: rawToken, password: 'InitialPass1!' }),
    );
    expect(res.status).toBe(400);
    const body = await res.json();
    expect(body.code).toBe('PASSWORD_PREVIOUSLY_USED');
  });

  test('new password returns 200 { ok: true }', async () => {
    const email = 'rh-ok@example.com';
    const initialHash = await Bun.password.hash('InitialPass1!');
    const { id: userId } = await runtime.adapter.create(email, initialHash);

    const rawToken = await createResetToken(
      runtime.repos.resetToken,
      userId,
      email,
      runtime.config,
    );

    const app = buildApp(runtime);
    const res = await app.request(
      '/auth/reset-password',
      json({ token: rawToken, password: 'BrandNew1!X' }),
    );
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.ok).toBe(true);
  });

  test('token is single-use: second attempt returns 400 invalid token', async () => {
    const email = 'rh-replay@example.com';
    const hash = await Bun.password.hash('InitialPass1!');
    const { id: userId } = await runtime.adapter.create(email, hash);

    const rawToken = await createResetToken(
      runtime.repos.resetToken,
      userId,
      email,
      runtime.config,
    );

    const app = buildApp(runtime);
    // First use — succeeds
    await app.request('/auth/reset-password', json({ token: rawToken, password: 'NewPass1!X' }));
    // Second use — token already consumed
    const res = await app.request(
      '/auth/reset-password',
      json({ token: rawToken, password: 'AnotherPass1!' }),
    );
    expect(res.status).toBe(400);
  });

  test('all sessions are revoked after a successful reset', async () => {
    const email = 'rh-sessions@example.com';
    const hash = await Bun.password.hash('InitialPass1!');
    const { id: userId } = await runtime.adapter.create(email, hash);

    // Create a session for the user
    await runtime.repos.session.atomicCreateSession(
      userId,
      'tok-before-reset',
      'sess-before-reset',
      3600,
      {},
      runtime.config,
    );

    const rawToken = await createResetToken(
      runtime.repos.resetToken,
      userId,
      email,
      runtime.config,
    );

    const app = buildApp(runtime);
    await app.request('/auth/reset-password', json({ token: rawToken, password: 'NewPass99!X' }));

    // Session token should be gone after reset
    const found = await runtime.repos.session.getSession('sess-before-reset', runtime.config);
    expect(found).toBeNull();
  });
});

