const json = (body: Record<string, unknown>) => ({
  method: 'POST' as const,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body),
});

async function waitForCapture(timeout = 200): Promise<void> {
  const deadline = Date.now() + timeout;
  while (captured.length === 0 && Date.now() < deadline) {
    await Bun.sleep(10);
  }
}

describe('SQLite password reset', () => {
  test('forgot password sends reset email', async () => {
    await app.request('/auth/register', json({ email: 'pr@example.com', password: 'password123' }));
    const res = await app.request('/auth/forgot-password', json({ email: 'pr@example.com' }));
    expect(res.status).toBe(200);
    await waitForCapture();
    expect(captured).toHaveLength(1);
    expect(captured[0].email).toBe('pr@example.com');
  });

  test('reset password with valid token works', async () => {
    await app.request(
      '/auth/register',
      json({ email: 'pr2@example.com', password: 'password123' }),
    );
    await app.request('/auth/forgot-password', json({ email: 'pr2@example.com' }));
    await waitForCapture();
    const token = captured[0].token;

    const res = await app.request(
      '/auth/reset-password',
      json({ token, password: 'newpassword456' }),
    );
    expect(res.status).toBe(200);
  });

  test('login with new password succeeds', async () => {
    await app.request(
      '/auth/register',
      json({ email: 'pr3@example.com', password: 'password123' }),
    );
    await app.request('/auth/forgot-password', json({ email: 'pr3@example.com' }));
    await waitForCapture();
    await app.request(
      '/auth/reset-password',
      json({ token: captured[0].token, password: 'newpassword456' }),
    );

    const res = await app.request(
      '/auth/login',
      json({ email: 'pr3@example.com', password: 'newpassword456' }),
    );
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.token).toBeString();
  });

  test('reset with already-used token fails', async () => {
    await app.request(
      '/auth/register',
      json({ email: 'pr4@example.com', password: 'password123' }),
    );
    await app.request('/auth/forgot-password', json({ email: 'pr4@example.com' }));
    await waitForCapture();
    const token = captured[0].token;

    await app.request('/auth/reset-password', json({ token, password: 'newpassword456' }));
    const res = await app.request(
      '/auth/reset-password',
      json({ token, password: 'anotherpassword' }),
    );
    expect(res.status).toBe(400);
  });
});

import type { OpenAPIHono } from '@hono/zod-openapi';
import { beforeEach, describe, expect, test } from 'bun:test';
import { createTestApp } from '../setup';

let app: OpenAPIHono<any>;

beforeEach(async () => {
  // Each createTestApp with ":memory:" creates a fresh SQLite database — no cleanup needed
  app = await createTestApp(
    {
      db: {
        mongo: false,
        redis: false,
        sessions: 'sqlite',
        cache: 'sqlite',
        auth: 'sqlite',
        sqlite: ':memory:',
      },
    },
    {
      auth: {
        enabled: true,
        roles: ['admin', 'user'],
        defaultRole: 'user',
        refreshTokens: {
          accessTokenExpiry: 900,
          refreshTokenExpiry: 86400,
          rotationGraceSeconds: 2,
        },
      },
    },
  );
});

const json = (body: Record<string, unknown>) => ({
  method: 'POST' as const,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(body),
});

describe('SQLite refresh tokens', () => {
  test('register returns refreshToken', async () => {
    const res = await app.request(
      '/auth/register',
      json({ email: 'rt@example.com', password: 'password123' }),
    );
    expect(res.status).toBe(201);
    const body = await res.json();
    expect(body.token).toBeString();
    expect(body.refreshToken).toBeString();
  });

  test('POST /auth/refresh rotates tokens', async () => {
    const reg = await app.request(
      '/auth/register',
      json({ email: 'rt2@example.com', password: 'password123' }),
    );
    const { refreshToken } = await reg.json();

    const res = await app.request('/auth/refresh', json({ refreshToken }));
    expect(res.status).toBe(200);
    const body = await res.json();
    expect(body.token).toBeString();
    expect(body.refreshToken).toBeString();
    expect(body.refreshToken).not.toBe(refreshToken);
  });

  test('grace window: old refresh token still works within window', async () => {
    const reg = await app.request(
      '/auth/register',
      json({ email: 'rt3@example.com', password: 'password123' }),
    );
    const { refreshToken } = await reg.json();

    // Rotate
    const r1 = await app.request('/auth/refresh', json({ refreshToken }));
    expect(r1.status).toBe(200);

    // Old token should still work within grace window
    const r2 = await app.request('/auth/refresh', json({ refreshToken }));
    expect(r2.status).toBe(200);
  });

  test('theft detection: old token after grace window invalidates session', async () => {
    const reg = await app.request(
      '/auth/register',
      json({ email: 'rt4@example.com', password: 'password123' }),
    );
    const { refreshToken } = await reg.json();

    // Rotate
    await app.request('/auth/refresh', json({ refreshToken }));

    // Wait for grace window to expire
    await Bun.sleep(2100);

    // Old token should now fail and invalidate session
    const res = await app.request('/auth/refresh', json({ refreshToken }));
    expect(res.status).toBe(401);
  });

  test('invalid refresh token returns 401', async () => {
    const res = await app.request('/auth/refresh', json({ refreshToken: 'invalid-token' }));
    expect(res.status).toBe(401);
  });
});

import type { OpenAPIHono } from '@hono/zod-openapi';
import { beforeEach, describe, expect, test } from 'bun:test';
import { authHeader, createTestApp } from '../setup';

let app: OpenAPIHono<any>;

beforeEach(async () => {
  app = await createTestApp({
    db: {
      mongo: false,
      redis: false,
