    expect(status.suspended).toBe(false);
  });

  test('setSuspended with reason', async () => {
    const { id } = await memoryAuthAdapter.create('x@example.com', 'hash');
    await setSuspended(memoryAuthAdapter, id, true, 'Fraud detected');
