  const bus: SlingshotEventBus = ctx.bus;
  return {
    server: server as import('../src/testing').E2EServerHandle['server'],
    baseUrl,
    wsUrl,
    url: baseUrl,
    bus,
    stop: async () => {
      await runPluginTeardown([...ctx.plugins]);
      server.stop(true);
    },
    cleanup: async () => {
      await runPluginTeardown([...ctx.plugins]);
      server.stop(true);
