import { describe, expect, it } from 'bun:test';
import { attachContext, createRouter } from '@lastshotlabs/slingshot-core';
import type { CacheAdapter } from '@lastshotlabs/slingshot-core';

/**
 * Documents the defense-in-depth behavior of bustCache/bustCachePattern:
 * both functions delete from ALL four cache backends regardless of which
 * store is configured, because cacheResponse() allows per-route store
 * overrides. Each adapter's isReady() check gates the operation — adapters
 * that aren't ready are skipped gracefully.
 *
 * After Phase 1 singleton elimination, bustCache/bustCachePattern accept an
 * optional `app` parameter for app name resolution. When omitted they
 * default to "Core API".
 */

function createTrackingAdapter(name: string, calledStores: string[], ready = true): CacheAdapter {
  return {
    name,
    async get() {
      return null;
    },
    async set() {},
    async del() {
      calledStores.push(name);
    },
    async delPattern() {
      calledStores.push(name);
    },
    isReady() {
      return ready;
    },
  };
}

describe('bustCache defense-in-depth', () => {
  it('bustCache calls storeDel for all four backends', async () => {
    const calledStores: string[] = [];
    const app = createRouter();
    attachContext(app, {
      app,
      config: { appName: 'Test App' },
      cacheAdapters: new Map([
        ['memory', createTrackingAdapter('memory', calledStores, true)],
        ['redis', createTrackingAdapter('redis', calledStores, false)],
        ['sqlite', createTrackingAdapter('sqlite', calledStores, false)],
        ['mongo', createTrackingAdapter('mongo', calledStores, false)],
      ]),
    } as any);

    const { bustCache } = await import('../../src/framework/middleware/cacheResponse');
    await bustCache('some-key', app);

    expect(calledStores).toContain('memory');
    expect(calledStores).not.toContain('redis');
    expect(calledStores).not.toContain('sqlite');
    expect(calledStores).not.toContain('mongo');
  });

  it('bustCachePattern calls storeDelPattern for all four backends', async () => {
    const calledStores: string[] = [];
    const app = createRouter();
    attachContext(app, {
      app,
      config: { appName: 'Test App' },
      cacheAdapters: new Map([
        ['memory', createTrackingAdapter('memory', calledStores, true)],
        ['redis', createTrackingAdapter('redis', calledStores, false)],
        ['sqlite', createTrackingAdapter('sqlite', calledStores, false)],
        ['mongo', createTrackingAdapter('mongo', calledStores, false)],
      ]),
    } as any);

    const { bustCachePattern } = await import('../../src/framework/middleware/cacheResponse');
    await bustCachePattern('prefix:*', app);

    expect(calledStores).toContain('memory');
    expect(calledStores).not.toContain('redis');
  });
});

/**
 * Tests for boundary cache adapter factories.
 * Covers the Redis adapter methods, the boundaryCacheFactories dispatch map,
 * and the Mongo cache adapter.
 */
import { describe, expect, mock, test } from 'bun:test';
import {
  boundaryCacheFactories,
  createRedisBoundaryCacheAdapter,
} from '../../src/framework/boundaryAdapters/cacheFactories';
import * as realAuth from '../../packages/slingshot-auth/src/index';

// ---------------------------------------------------------------------------
// Redis boundary cache adapter
// ---------------------------------------------------------------------------

function createMockRedisClient() {
  const store = new Map<string, string>();
  const ttls = new Map<string, number>();
  return {
    get: mock(async (key: string) => store.get(key) ?? null),
    set: mock(async (key: string, value: string) => {
      store.set(key, value);
    }),
    setex: mock(async (key: string, ttl: number, value: string) => {
      store.set(key, value);
      ttls.set(key, ttl);
    }),
    del: mock(async (...keys: string[]) => {
      for (const k of keys) store.delete(k);
      return keys.length;
    }),
    scan: mock(async (): Promise<[string, string[]]> => {
      // Simple mock: return all matching keys on first call, '0' cursor to end loop
      return ['0', [...store.keys()]];
    }),
    store,
    ttls,
  };
}

describe('createRedisBoundaryCacheAdapter', () => {
  test('name is redis', () => {
    const redis = createMockRedisClient();
    const adapter = createRedisBoundaryCacheAdapter(redis as any);
    expect(adapter.name).toBe('redis');
  });

  test('isReady always returns true', () => {
    const redis = createMockRedisClient();
    const adapter = createRedisBoundaryCacheAdapter(redis as any);
    expect(adapter.isReady()).toBe(true);
  });

  test('get delegates to redisClient.get', async () => {
    const redis = createMockRedisClient();
    redis.store.set('mykey', 'myvalue');
    const adapter = createRedisBoundaryCacheAdapter(redis as any);
    const result = await adapter.get('mykey');
    expect(result).toBe('myvalue');
    expect(redis.get).toHaveBeenCalledWith('mykey');
  });

  test('get returns null for missing key', async () => {
    const redis = createMockRedisClient();
    const adapter = createRedisBoundaryCacheAdapter(redis as any);
    const result = await adapter.get('nonexistent');
    expect(result).toBeNull();
  });

  test('set without TTL calls redisClient.set', async () => {
    const redis = createMockRedisClient();
    const adapter = createRedisBoundaryCacheAdapter(redis as any);
    await adapter.set('k1', 'v1');
    expect(redis.set).toHaveBeenCalledWith('k1', 'v1');
    expect(redis.setex).not.toHaveBeenCalled();
    expect(redis.store.get('k1')).toBe('v1');
  });

  test('set with TTL calls redisClient.setex', async () => {
    const redis = createMockRedisClient();
    const adapter = createRedisBoundaryCacheAdapter(redis as any);
    await adapter.set('k2', 'v2', 300);
    expect(redis.setex).toHaveBeenCalledWith('k2', 300, 'v2');
    expect(redis.set).not.toHaveBeenCalled();
    expect(redis.ttls.get('k2')).toBe(300);
  });

  test('del calls redisClient.del', async () => {
    const redis = createMockRedisClient();
    redis.store.set('k3', 'v3');
    const adapter = createRedisBoundaryCacheAdapter(redis as any);
    await adapter.del('k3');
    expect(redis.del).toHaveBeenCalledWith('k3');
    expect(redis.store.has('k3')).toBe(false);
  });

  test('delPattern calls scan and del in a loop', async () => {
    const redis = createMockRedisClient();
    redis.store.set('session:a', 'v1');
    redis.store.set('session:b', 'v2');
    redis.store.set('other', 'v3');
    const adapter = createRedisBoundaryCacheAdapter(redis as any);

    await adapter.delPattern('session:*');

    expect(redis.scan).toHaveBeenCalled();
    // del should have been called (with whatever keys scan returned)
    expect(redis.del).toHaveBeenCalled();
  });

  test('delPattern skips del call when scan returns empty keys', async () => {
    const redis = createMockRedisClient();
    // Override scan to return empty keys
    redis.scan = mock(async (): Promise<[string, string[]]> => ['0', []]);
    const adapter = createRedisBoundaryCacheAdapter(redis as any);
    await adapter.delPattern('no-match:*');
    expect(redis.del).not.toHaveBeenCalled();
  });
});

