        return c.json({ ok: true });
      },
    );

    const server = Bun.serve({ port: 0, fetch: testApp.fetch });
    try {
      const url = `http://localhost:${server.port}/sensitive-header-test`;
      await fetch(url); // prime cache (MISS)
