function createRuntime(sqliteDb?: {
  run(sql: string, ...params: unknown[]): void;
  query<T = unknown>(
    sql: string,
  ): {
    get(...args: unknown[]): T | null;
    all(...args: unknown[]): T[];
    run(...args: unknown[]): void;
  };
  prepare<T = unknown>(
    sql: string,
  ): {
    get(...args: unknown[]): T | null;
    all(...args: unknown[]): T[];
    run(...args: unknown[]): { changes: number };
  };
  transaction<T>(fn: () => T): () => T;
  close(): void;
}) {
  const db =
    sqliteDb ??
    ({
      run() {},
      query() {
        return {
          get() {
            return null;
          },
          all() {
            return [];
          },
          run() {},
        };
      },
      prepare() {
        return {
          get() {
            return null;
          },
          all() {
            return [];
          },
          run() {
            return { changes: 0 };
          },
        };
      },
      transaction<T>(fn: () => T) {
        return () => fn();
      },
      close() {},
    } as const);

  return {
    password: {
      hash: async (plain: string) => `hash:${plain}`,
      verify: async () => true,
    },
    sqlite: {
      open: mock(() => db),
    },
    server: {
      listen: () => ({
        port: 0,
        stop() {},
      }),
    },
    fs: {
      write: async () => {},
      readFile: async () => null,
      exists: async () => false,
    },
    glob: {
      scan: async function* () {},
    },
    readFile: async () => null,
    supportsAsyncLocalStorage: true,
  };
}

async function loadCreateInfrastructure() {
  const mod = await import('../../src/framework/createInfrastructure');
  return mod.createInfrastructure;
}

