    });

    it('validates nested $and inside $or', () => {
      const result = validateEntityManifest({
        name: 'Test',
        fields: { id: { type: 'string', primary: true } },
        operations: {
          op1: {
            kind: 'batch',
            action: 'delete',
            filter: {
              $or: [{ $and: [{ status: 'draft' }, { age: { $gt: 30 } }] }, { status: 'expired' }],
