      // Read the original body to lock the stream, then clone will fail
      return res;
    });

    const res = await app.request('/stream', {
      method: 'POST',
      headers: { 'idempotency-key': 'stream-key' },
      body: 'data',
    });

    // Should not crash even if caching is skipped
    expect(res.status).toBe(200);
  });
});

