// Email OTP
// ---------------------------------------------------------------------------

describe('generateEmailOtpCode', () => {
  test('generates a code of the configured length', () => {
    const { code, hash } = generateEmailOtpCode(getRuntime(), 6);
    expect(code).toHaveLength(6);
    expect(/^\d+$/.test(code)).toBe(true);
    expect(hash).toBeTruthy();
  });
});

describe('verifyEmailOtp', () => {
  test('returns true for matching code', () => {
    const { code, hash } = generateEmailOtpCode(getRuntime());
    expect(verifyEmailOtp(hash, code)).toBe(true);
  });

  test('returns false for wrong code', () => {
    const { hash } = generateEmailOtpCode(getRuntime());
    expect(verifyEmailOtp(hash, '000000')).toBe(false);
  });
});

describe('initiateEmailOtp', () => {
  test('emits email_otp delivery event and returns challenge token', async () => {
    const userId = await createUser('emailotp@example.com');
    const setupToken = await initiateEmailOtp(userId, getRuntime());
    expect(typeof setupToken).toBe('string');
    expect(emailOtpCodes).toHaveLength(1);
    expect(emailOtpCodes[0].email).toBe('emailotp@example.com');
    expect(emailOtpCodes[0].code).toBeTruthy();
  });
});

describe('confirmEmailOtp', () => {
  test('enables email OTP method and returns recovery codes', async () => {
    const userId = await createUser('confirm@example.com');
    const setupToken = await initiateEmailOtp(userId, getRuntime());
    const code = emailOtpCodes[0].code;
    const recoveryCodes = await confirmEmailOtp(userId, setupToken, code, getRuntime());
    expect(recoveryCodes).toBeArray();
    expect(recoveryCodes!.length).toBe(10);
    const methods = await adapter.getMfaMethods!(userId);
    expect(methods).toContain('emailOtp');
    expect(await adapter.isMfaEnabled!(userId)).toBe(true);
  });

  test('rejects invalid code', async () => {
    const userId = await createUser('bad@example.com');
    const setupToken = await initiateEmailOtp(userId, getRuntime());
    expect(confirmEmailOtp(userId, setupToken, '000000', getRuntime())).rejects.toThrow(
      'Invalid verification code',
    );
  });

  test('rejects expired/invalid setup token', async () => {
    const userId = await createUser('expired@example.com');
    expect(confirmEmailOtp(userId, 'invalid-token', '123456', getRuntime())).rejects.toThrow(
      'Invalid or expired setup token',
    );
  });
});

describe('disableEmailOtp', () => {
  test('removes email OTP method with password verification', async () => {
    const userId = await createUser('disable@example.com', 'password123');
    const setupToken = await initiateEmailOtp(userId, getRuntime());
    const code = emailOtpCodes[0].code;
    await confirmEmailOtp(userId, setupToken, code, getRuntime());
    await disableEmailOtp(userId, { password: 'password123' }, getRuntime());
    const methods = await adapter.getMfaMethods!(userId);
    expect(methods).not.toContain('emailOtp');
  });

  test('disables MFA entirely when last method removed', async () => {
    const userId = await createUser('lastmethod@example.com', 'password123');
    const setupToken = await initiateEmailOtp(userId, getRuntime());
    const code = emailOtpCodes[0].code;
    await confirmEmailOtp(userId, setupToken, code, getRuntime());
    await disableEmailOtp(userId, { password: 'password123' }, getRuntime());
    expect(await adapter.isMfaEnabled!(userId)).toBe(false);
  });

  test('requires TOTP code when TOTP is also enabled', async () => {
    const userId = await createUser('both@example.com', 'password123');
    // Enable TOTP first
    await setupMfa(userId, getRuntime());
    const totpCode = await getValidTotp(userId);
    await verifySetup(userId, totpCode, getRuntime());
    // Enable email OTP
    const setupToken = await initiateEmailOtp(userId, getRuntime());
    const otpCode = emailOtpCodes[0].code;
    await confirmEmailOtp(userId, setupToken, otpCode, getRuntime());
    // Disable email OTP requires TOTP code
    const disableCode = await getValidTotp(userId);
    await disableEmailOtp(userId, { code: disableCode }, getRuntime());
    const methods = await adapter.getMfaMethods!(userId);
    expect(methods).not.toContain('emailOtp');
    expect(methods).toContain('totp');
  });
});

/**
 * Tests for mountMiddleware.ts covering uncovered lines:
 * - Line 89: throw when metrics enabled without auth in production
 * - Lines 101-123: metricsCollector block
 * - Lines 142, 145: CSP and Permissions-Policy custom headers
 * - Lines 149-154: custom security headers middleware
 * - Lines 162-163: bot protection block
 * - Lines 200-201: mountTenantMiddleware throw in production
 * - Line 204: mountTenantMiddleware console.warn in dev
 * - Lines 239-244: mountCors with custom object options
 * - Lines 248-250: mountCors wildcard warning in production
 */
import { describe, expect, it, spyOn } from 'bun:test';
import { OpenAPIHono } from '@hono/zod-openapi';
import type { AppEnv } from '@lastshotlabs/slingshot-core';
import { createMetricsState } from '../../src/framework/metrics/registry';
import {
  mountCors,
  mountFrameworkMiddleware,
  mountTenantMiddleware,
} from '../../src/framework/mountMiddleware';

function makeApp() {
  return new OpenAPIHono<AppEnv>();
}

const minimalSecurity = {
  rateLimit: { windowMs: 60_000, max: 1000 },
};

describe('mountFrameworkMiddleware', () => {
  it('mounts successfully with minimal config (happy path)', async () => {
    const app = makeApp();
    await expect(
      mountFrameworkMiddleware(app, {
        security: minimalSecurity,
        isProd: false,
        logging: { onLog: () => {} },
      }),
    ).resolves.toBeUndefined();
  });

  it('throws when metrics.enabled=true, auth=none, no unsafePublic, isProd=true (line 89)', async () => {
    const app = makeApp();
    const state = createMetricsState();
    await expect(
      mountFrameworkMiddleware(app, {
        security: minimalSecurity,
        isProd: true,
        metrics: { enabled: true, auth: 'none' },
        metricsState: state,
        logging: { onLog: () => {} },
      }),
    ).rejects.toThrow(
      '[security] metrics.auth is required in production.',
    );
  });

  it('warns when metrics.enabled=true, auth=none, no unsafePublic, isProd=false (lines 108-110)', async () => {
    const app = makeApp();
    const state = createMetricsState();
    const warnSpy = spyOn(console, 'warn').mockImplementation(() => {});
    try {
      await mountFrameworkMiddleware(app, {
        security: minimalSecurity,
        isProd: false,
        metrics: { enabled: true, auth: 'none' },
        metricsState: state,
        logging: { onLog: () => {} },
      });
      expect(warnSpy).toHaveBeenCalledWith(
        expect.stringContaining('[security] /metrics is enabled without auth.'),
      );
    } finally {
      warnSpy.mockRestore();
    }
  });

  it('mounts metricsCollector when metrics.enabled=true with auth (lines 101-123)', async () => {
    const app = makeApp();
    const state = createMetricsState();
    app.get('/test', c => c.json({ ok: true }));
    await mountFrameworkMiddleware(app, {
      security: minimalSecurity,
      isProd: false,
      metrics: {
        enabled: true,
        auth: 'userAuth',
        unsafePublic: false,
      },
      metricsState: state,
      logging: { onLog: () => {} },
    });
    // Should not throw — just verify it mounts
    const res = await app.request('/test');
    expect(res.status).toBe(200);
  });

  it('mounts metricsCollector with unsafePublic=true (lines 101-123)', async () => {
    const app = makeApp();
    const state = createMetricsState();
    app.get('/test', c => c.json({ ok: true }));
    await mountFrameworkMiddleware(app, {
      security: minimalSecurity,
      isProd: true,
      metrics: {
        enabled: true,
        auth: 'none',
        unsafePublic: true,
      },
      metricsState: state,
      logging: { onLog: () => {} },
    });
    const res = await app.request('/test');
    expect(res.status).toBe(200);
  });

  it('sets Content-Security-Policy custom header (lines 142, 149-154)', async () => {
    const app = makeApp();
    app.get('/test', c => c.json({ ok: true }));
    await mountFrameworkMiddleware(app, {
      security: {
        ...minimalSecurity,
        headers: {
          contentSecurityPolicy: "default-src 'self'",
        },
      },
      isProd: false,
      logging: { onLog: () => {} },
    });
    const res = await app.request('/test');
    expect(res.headers.get('Content-Security-Policy')).toBe("default-src 'self'");
  });

  it('sets Permissions-Policy custom header (lines 145, 149-154)', async () => {
    const app = makeApp();
    app.get('/test', c => c.json({ ok: true }));
    await mountFrameworkMiddleware(app, {
      security: {
        ...minimalSecurity,
        headers: {
          permissionsPolicy: 'camera=(), microphone=()',
        },
      },
      isProd: false,
      logging: { onLog: () => {} },
    });
    const res = await app.request('/test');
    expect(res.headers.get('Permissions-Policy')).toBe('camera=(), microphone=()');
  });

  it('mounts bot protection when blockList is non-empty (lines 162-163)', async () => {
    const app = makeApp();
    app.get('/test', c => c.json({ ok: true }));
    await mountFrameworkMiddleware(app, {
      security: {
        ...minimalSecurity,
        botProtection: { blockList: ['1.2.3.4'] },
      },
      isProd: false,
      logging: { onLog: () => {} },
    });
    // App mounts without error; request from non-blocked IP passes
    const res = await app.request('/test');
    expect(res.status).toBe(200);
  });

  it('skips bot protection when blockList is empty', async () => {
    const app = makeApp();
    app.get('/test', c => c.json({ ok: true }));
    await mountFrameworkMiddleware(app, {
      security: {
        ...minimalSecurity,
        botProtection: { blockList: [] },
      },
      isProd: false,
      logging: { onLog: () => {} },
    });
    const res = await app.request('/test');
    expect(res.status).toBe(200);
  });
});

describe('mountTenantMiddleware', () => {
  it('throws in production when tenancy has no onResolve (lines 200-201)', async () => {
    const app = makeApp();
    const tenancy: never = { resolution: 'subdomain' } as never;
    await expect(
      mountTenantMiddleware(app, tenancy, undefined, true),
    ).rejects.toThrow(
      '[security] Tenancy is configured without an onResolve callback.',
    );
  });

  it('warns in development when tenancy has no onResolve (line 204)', async () => {
    const app = makeApp();
    const warnSpy = spyOn(console, 'warn').mockImplementation(() => {});
    try {
      const tenancyDev: never = { resolution: 'subdomain' } as never;
      await mountTenantMiddleware(app, tenancyDev, undefined, false);
      expect(warnSpy).toHaveBeenCalledWith(
        expect.stringContaining('[security] Tenancy is configured without an onResolve callback'),
      );
    } finally {
      warnSpy.mockRestore();
    }
  });

  it('mounts tenant middleware when onResolve is provided', async () => {
    const app = makeApp();
    const tenancyWithResolve: never = {
      resolution: 'subdomain',
      onResolve: () => Promise.resolve(null),
    } as never;
    await expect(
      mountTenantMiddleware(
        app,
        tenancyWithResolve,
        undefined,
        false,
      ),
    ).resolves.toBeUndefined();
  });
});

describe('mountCors', () => {
  it('mounts CORS with wildcard origin (default)', () => {
    const app = makeApp();
    // Should not throw
    mountCors(app, { ...minimalSecurity });
  });

  it('mounts CORS with specific origin string', () => {
    const app = makeApp();
    mountCors(app, { ...minimalSecurity, cors: 'https://example.com' });
  });

  it('mounts CORS with array of origins', () => {
    const app = makeApp();
    mountCors(app, { ...minimalSecurity, cors: ['https://a.com', 'https://b.com'] });
  });

  it('mounts CORS with custom options object (lines 239-244)', () => {
    const app = makeApp();
    mountCors(app, {
      ...minimalSecurity,
      cors: {
        origin: 'https://example.com',
        credentials: true,
        allowHeaders: ['X-Custom-Header'],
        exposeHeaders: ['X-Response-Header'],
        maxAge: 3600,
      },
    });
  });

  it('warns when CORS is wildcard in production (lines 248-250)', () => {
    const app = makeApp();
    const warnSpy = spyOn(console, 'warn').mockImplementation(() => {});
    try {
      mountCors(app, { ...minimalSecurity, cors: '*' }, undefined, true);
      expect(warnSpy).toHaveBeenCalledWith(
        expect.stringContaining('[security] CORS is set to wildcard (*) in production.'),
      );
    } finally {
      warnSpy.mockRestore();
    }
  });

  it('does not warn when CORS has specific origin in production', () => {
    const app = makeApp();
    const warnSpy = spyOn(console, 'warn').mockImplementation(() => {});
    try {
      mountCors(app, { ...minimalSecurity, cors: 'https://example.com' }, undefined, true);
      expect(warnSpy).not.toHaveBeenCalled();
    } finally {
      warnSpy.mockRestore();
    }
  });

  it('includes tenancy header name in CORS allowHeaders when resolution is header', () => {
    const app = makeApp();
    // Should not throw
    mountCors(
      app,
      { ...minimalSecurity },
      { resolution: 'header', headerName: 'x-tenant-id' },
      false,
    );
  });
});

describe('mountFrameworkMiddleware — additional coverage', () => {
  it('mounts OTel request tracing middleware when tracing is enabled (line 89)', async () => {
    const app = makeApp();
    app.get('/test', c => c.json({ ok: true }));
    await mountFrameworkMiddleware(app, {
      security: minimalSecurity,
      isProd: false,
      tracing: { enabled: true },
      logging: { onLog: () => {} },
    });
    const res = await app.request('/test');
    expect(res.status).toBe(200);
  });

  it('throws when metrics.enabled=true but metricsState is not provided (line 117)', async () => {
    const app = makeApp();
    await expect(
      mountFrameworkMiddleware(app, {
        security: minimalSecurity,
        isProd: false,
        metrics: { enabled: true, auth: 'userAuth' },
        // metricsState deliberately omitted
        logging: { onLog: () => {} },
      }),
    ).rejects.toThrow('metricsState is required when metrics are enabled');
  });

  it('exercises the custom security headers middleware path (lines 148-155)', async () => {
    // We can't directly assert the headers due to Hono internals cloning the response,
    // but we verify the middleware mounts and requests succeed when both headers are set.
    const app = makeApp();
    app.get('/combined', c => c.json({ ok: true }));
    await mountFrameworkMiddleware(app, {
      security: {
        ...minimalSecurity,
        headers: {
          contentSecurityPolicy: "default-src 'self'",
          permissionsPolicy: 'camera=()',
        },
      },
      isProd: false,
      logging: { onLog: () => {} },
    });
    const res = await app.request('/combined');
    // The middleware mounted successfully and request passed through without error
    expect(res.status).toBe(200);
  });
});

