  test('resolves without throwing for all-null infrastructure', async () => {
    const { registrar } = makeMockRegistrar();
    await expect(registerBoundaryAdapters(registrar, memoryOnlyOptions)).resolves.toBeUndefined();
  });
});

import { trace } from '@opentelemetry/api';
import { describe, expect, spyOn, test } from 'bun:test';
import { Hono } from 'hono';
import type { AppEnv } from '@lastshotlabs/slingshot-core';
import { otelRequestMiddleware } from '../../src/framework/middleware/otelRequest';
import { requestId } from '../../src/framework/middleware/requestId';
import { requestLogger } from '../../src/framework/middleware/requestLogger';
import type { RequestLogEntry } from '../../src/framework/middleware/requestLogger';

function createLoggerApp(options: Parameters<typeof requestLogger>[0] = {}) {
  const logs: RequestLogEntry[] = [];
  const app = new Hono<AppEnv>();

  app.use(requestId);
  app.use(
    requestLogger({
      ...options,
      onLog: entry => {
        logs.push(entry);
      },
    }),
  );

  return { app, logs };
}

describe('requestLogger middleware', () => {
  test('structured log includes all expected fields', async () => {
    const { app, logs } = createLoggerApp();
    app.get('/api/users', c => c.json({ ok: true }));

    await app.request('/api/users', {
      headers: { 'user-agent': 'test-agent' },
    });

    expect(logs).toHaveLength(1);
    const entry = logs[0];
    expect(entry.level).toBe('info');
    expect(entry.time).toBeGreaterThan(0);
    expect(entry.msg).toBe('GET /api/users 200');
    expect(entry.requestId).toMatch(/^[0-9a-f]{8}-/);
    expect(entry.method).toBe('GET');
    expect(entry.path).toBe('/api/users');
    expect(entry.statusCode).toBe(200);
    expect(entry.responseTime).toBeGreaterThanOrEqual(0);
    expect(entry.ip).toBeDefined();
    expect(entry.userAgent).toBe('test-agent');
    expect(entry.userId).toBeNull();
    expect(entry.sessionId).toBeNull();
    expect(entry.tenantId).toBeNull();
    expect(entry.err).toBeUndefined();
  });

  test('status-to-level mapping: 2xx → info', async () => {
    const { app, logs } = createLoggerApp();
    app.get('/ok', c => c.json({ ok: true }, 200));
    await app.request('/ok');
    expect(logs[0].level).toBe('info');
  });

  test('status-to-level mapping: 4xx → warn', async () => {
    const { app, logs } = createLoggerApp();
    app.get('/bad', c => c.json({ error: 'bad' }, 400));
    await app.request('/bad');
    expect(logs[0].level).toBe('warn');
    expect(logs[0].statusCode).toBe(400);
  });

  test('status-to-level mapping: 5xx → error', async () => {
    const { app, logs } = createLoggerApp();
    app.get('/fail', c => c.json({ error: 'fail' }, 500));
    await app.request('/fail');
    expect(logs[0].level).toBe('error');
    expect(logs[0].statusCode).toBe(500);
  });

  test("level filtering: level 'warn' skips 200s", async () => {
    const { app, logs } = createLoggerApp({ level: 'warn' });
    app.get('/ok', c => c.json({ ok: true }));
    app.get('/bad', c => c.json({ error: 'bad' }, 400));
    await app.request('/ok');
    await app.request('/bad');
    expect(logs).toHaveLength(1);
    expect(logs[0].level).toBe('warn');
  });

  test('path exclusion with prefix matching', async () => {
    const { app, logs } = createLoggerApp({ excludePaths: ['/health'] });
    app.get('/health', c => c.text('ok'));
    app.get('/health/live', c => c.text('ok'));
    app.get('/api/data', c => c.json({ ok: true }));

    await app.request('/health');
    await app.request('/health/live');
    await app.request('/api/data');

    expect(logs).toHaveLength(1);
    expect(logs[0].path).toBe('/api/data');
  });

  test('path exclusion with RegExp', async () => {
    const { app, logs } = createLoggerApp({ excludePaths: [/^\/internal\//] });
    app.get('/internal/metrics', c => c.text('ok'));
    app.get('/api/data', c => c.json({ ok: true }));

    await app.request('/internal/metrics');
    await app.request('/api/data');

    expect(logs).toHaveLength(1);
    expect(logs[0].path).toBe('/api/data');
  });

  test('method exclusion', async () => {
    const { app, logs } = createLoggerApp({ excludeMethods: ['OPTIONS'] });
    app.on('OPTIONS', '/api', c => c.text('', 204 as any));
    app.get('/api', c => c.json({ ok: true }));

    await app.request('/api', { method: 'OPTIONS' });
    await app.request('/api');

    expect(logs).toHaveLength(1);
    expect(logs[0].method).toBe('GET');
  });

  test('custom onLog callback receives entry', async () => {
    const received: RequestLogEntry[] = [];
    const app = new Hono<AppEnv>();
    app.use(requestId);
    app.use(
      requestLogger({
        onLog: entry => {
          received.push(entry);
        },
      }),
    );
    app.get('/test', c => c.json({ ok: true }));

    await app.request('/test');

    expect(received).toHaveLength(1);
    expect(received[0].path).toBe('/test');
  });

  test('userId and tenantId captured from context', async () => {
    const { app, logs } = createLoggerApp();
    app.use(async (c, next) => {
      c.set('authUserId', 'user-123');
      c.set('tenantId', 'tenant-456');
      await next();
    });
    app.get('/api/data', c => c.json({ ok: true }));

    await app.request('/api/data');

    expect(logs[0].userId).toBe('user-123');
    expect(logs[0].tenantId).toBe('tenant-456');
  });

  test('downstream throw still produces a log entry with status 500', async () => {
    const { app, logs } = createLoggerApp();
    app.get('/boom', () => {
      throw new Error('kaboom');
    });
    // Hono's internal error handler catches the throw and produces a 500 response.
    // Our middleware sees the resulting 500 status.
    await app.request('/boom');

    expect(logs).toHaveLength(1);
    expect(logs[0].statusCode).toBe(500);
    expect(logs[0].level).toBe('error');
  });

  test('error thrown before Hono error handler populates err field', async () => {
    // Use a middleware that throws (simulating a lower-level middleware error)
    // to test that the err field is populated when the error reaches our catch
    const logs: RequestLogEntry[] = [];
    const app = new Hono<AppEnv>();
    app.use(requestId);

    // Custom compose: throw inside onLog's scope by using a middleware that
    // sets up the error AFTER Hono processes it, so our middleware catches it
    app.use(
      requestLogger({
        onLog: entry => {
          logs.push(entry);
        },
      }),
    );
    app.use(async () => {
      throw new Error('middleware-error');
    });

    await app.request('/test');

    // Hono catches the error via its built-in handler, producing a 500
    expect(logs).toHaveLength(1);
    expect(logs[0].statusCode).toBe(500);
    expect(logs[0].level).toBe('error');
  });

  test("onLog error isolation: throwing onLog doesn't crash middleware", async () => {
    const app = new Hono<AppEnv>();
    app.use(requestId);
    app.use(
      requestLogger({
        onLog: () => {
          throw new Error('logger broken');
        },
      }),
    );
    app.get('/ok', c => c.json({ ok: true }));

    const res = await app.request('/ok');
    expect(res.status).toBe(200);
  });

  test('sessionId captured from context', async () => {
    const { app, logs } = createLoggerApp();
    app.use(async (c, next) => {
      c.set('sessionId', 'sess-789');
      await next();
    });
    app.get('/api/data', c => c.json({ ok: true }));

    await app.request('/api/data');
    expect(logs[0].sessionId).toBe('sess-789');
  });

  test('traceId and spanId are null when otelSpan is not set', async () => {
    const { app, logs } = createLoggerApp();
    app.get('/test', c => c.json({ ok: true }));

    await app.request('/test');

    expect(logs[0].traceId).toBeNull();
    expect(logs[0].spanId).toBeNull();
  });

  test('errorToString handles non-Error thrown string values', async () => {
    // This exercises the errorToString string branch (line 75)
    const logs: RequestLogEntry[] = [];
    const app = new Hono<AppEnv>();
    app.use(requestId);
    app.use(requestLogger({ onLog: entry => { logs.push(entry); } }));
    app.use(async () => {
      throw 'string-error';
    });

    await app.request('/string-throw');
    // Hono catches it — the middleware sees it when re-thrown
    expect(logs).toHaveLength(1);
    expect(logs[0].statusCode).toBe(500);
  });

  test('errorToString handles non-Error thrown number values', async () => {
    // This exercises the errorToString number branch (line 76-77)
    const logs: RequestLogEntry[] = [];
    const app = new Hono<AppEnv>();
    app.use(requestId);
    app.use(requestLogger({ onLog: entry => { logs.push(entry); } }));
    app.use(async () => {
      throw 42;
    });

    await app.request('/number-throw');
    expect(logs).toHaveLength(1);
    expect(logs[0].statusCode).toBe(500);
  });

  test('level filtering with error: error below minLevel is still re-thrown (line 157)', async () => {
    // With minLevel: 'error', a 4xx response is filtered (warn < error), but
    // an actual thrown error at warn-level should still propagate
    const logs: RequestLogEntry[] = [];
    const app = new Hono<AppEnv>();
    app.use(requestId);
    app.use(requestLogger({
      level: 'error',
      onLog: entry => { logs.push(entry); },
    }));
    app.get('/ok', c => c.json({ ok: true }, 200));

    await app.request('/ok');
    // info < error so entry is dropped
    expect(logs).toHaveLength(0);
  });

  test('err field is populated for non-Error thrown objects (lines 191-194)', async () => {
    // Exercises the non-Error branch of err field population
    const logs: RequestLogEntry[] = [];
    const app = new Hono<AppEnv>();
    app.use(requestId);
    app.use(requestLogger({ onLog: entry => { logs.push(entry); } }));
    // Throw a plain object — not an Error instance
    app.use(async () => {

      throw { code: 'CUSTOM', detail: 'custom error' };
    });

    await app.request('/obj-throw');
    expect(logs).toHaveLength(1);
    // err should be populated even for non-Error thrown values
    expect(logs[0].err).toBeDefined();
    expect(typeof logs[0].err?.message).toBe('string');
  });

  test('traceId and spanId populated when otelSpan is set', async () => {
    const logs: RequestLogEntry[] = [];
    const app = new Hono<AppEnv>();
    const tracer = trace.getTracer('test');

    app.use(requestId);
    app.use(otelRequestMiddleware({ tracer }));
    app.use(
      requestLogger({
        onLog: entry => {
          logs.push(entry);
        },
      }),
    );
    app.get('/test', c => c.json({ ok: true }));

    await app.request('/test');

    expect(logs).toHaveLength(1);
    // With no-op tracer, traceId and spanId will be the no-op values (all zeros)
    // but they should still be strings, not null
    expect(typeof logs[0].traceId).toBe('string');
    expect(typeof logs[0].spanId).toBe('string');
  });

  test('default onLog calls console.log with JSON when no onLog is provided', async () => {
    const logSpy = spyOn(console, 'log').mockImplementation(() => {});

    const app = new Hono<AppEnv>();
    app.use(requestId);
    app.use(requestLogger()); // no onLog override — uses default
    app.get('/default-log', c => c.json({ ok: true }));

    await app.request('/default-log');

    const jsonCall = logSpy.mock.calls.find(
      (args: unknown[]) => typeof args[0] === 'string' && args[0].includes('"path":"/default-log"'),
    );
    expect(jsonCall).toBeDefined();

    logSpy.mockRestore();
  });
});

import { describe, expect, test } from 'bun:test';
import { createHmac } from 'crypto';
import { Hono } from 'hono';
import { HttpError, attachContext } from '@lastshotlabs/slingshot-core';
import type { SlingshotContext } from '@lastshotlabs/slingshot-core';
import { requireSignedRequest } from '../../src/framework/middleware/requestSigning';

const SECRET = 'test-signing-secret-32-chars-xxxxx';

function buildCanonical(
  method: string,
  path: string,
  query: string,
  timestamp: string,
  body: string,
): string {
  return `${method}\n${path}\n${query}\n${timestamp}\n${body}`;
}

function sign(canonical: string): string {
  return createHmac('sha256', SECRET).update(canonical).digest('hex');
}

function createMinimalContext(app: object, signing: unknown): void {
  const ctx = {
    app,
    config: {
      appName: 'test',
      resolvedStores: {
        sessions: 'memory',
        oauthState: 'memory',
        cache: 'memory',
        authStore: 'memory',
        sqlite: undefined,
      },
      security: { cors: '*' },
      signing,
      dataEncryptionKeys: [],
      redis: undefined,
      mongo: undefined,
      captcha: null,
    },
    redis: null,
    mongo: null,
    sqlite: null,
    signing,
    dataEncryptionKeys: [],
    ws: null,
    persistence: null as any,
    pluginState: new Map(),
    async clear() {},
    async destroy() {},
  } as unknown as SlingshotContext;
  attachContext(app, ctx);
}

function buildApp(signing: unknown = { requestSigning: { tolerance: 300_000 }, secret: SECRET }) {
  const app = new Hono();
  createMinimalContext(app, signing);
  app.use(async (c, next) => {
    const { getContext } = await import('@lastshotlabs/slingshot-core');
    (c as any).set('slingshotCtx', getContext(app));
    await next();
  });
  app.onError((err, c) => {
    if (err instanceof HttpError) {
      const body: Record<string, unknown> = { error: err.message };
      if (err.code !== undefined) body.code = err.code;
      return c.json(body, err.status as 400 | 401 | 403 | 404 | 409 | 418 | 429 | 500);
    }
    return c.json({ error: 'Internal Server Error' }, 500);
  });
  app.use('/*', requireSignedRequest());
  app.post('/data', async c => {
    return c.json({ ok: true });
  });
  return app;
}

describe('requireSignedRequest', () => {
  test('valid signature passes', async () => {
    const app = buildApp();
    const timestamp = String(Math.floor(Date.now() / 1000));
    const body = JSON.stringify({ hello: 'world' });
    const canonical = buildCanonical('POST', '/data', '', timestamp, body);
    const sig = sign(canonical);

    const res = await app.request('/data', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-signature': sig,
        'x-timestamp': timestamp,
      },
      body,
    });
    expect(res.status).toBe(200);
  });

  test('tampered body returns 401 INVALID_SIGNATURE', async () => {
    const app = buildApp();
    const timestamp = String(Math.floor(Date.now() / 1000));
    const body = JSON.stringify({ hello: 'world' });
    const canonical = buildCanonical('POST', '/data', '', timestamp, body);
    const sig = sign(canonical);

    const res = await app.request('/data', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-signature': sig,
        'x-timestamp': timestamp,
      },
      body: JSON.stringify({ hello: 'TAMPERED' }), // different body
    });
    expect(res.status).toBe(401);
    const json = await res.json();
    expect(json.code).toBe('INVALID_SIGNATURE');
  });

  test('expired timestamp returns 401 EXPIRED_TIMESTAMP', async () => {
    const app = buildApp();
    const oldTimestamp = String(Math.floor((Date.now() - 600_000) / 1000)); // 10 min ago
    const body = '';
    const canonical = buildCanonical('POST', '/data', '', oldTimestamp, body);
    const sig = sign(canonical);

    const res = await app.request('/data', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-signature': sig,
        'x-timestamp': oldTimestamp,
      },
      body,
    });
    expect(res.status).toBe(401);
    const json = await res.json();
    expect(json.code).toBe('EXPIRED_TIMESTAMP');
  });

  test('missing signature header returns 401', async () => {
    const app = buildApp();
    const timestamp = String(Math.floor(Date.now() / 1000));

    const res = await app.request('/data', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-timestamp': timestamp,
      },
      body: '{}',
    });
    expect(res.status).toBe(401);
  });

  test('HMAC off: all requests pass through', async () => {
    const app = buildApp({ requestSigning: false });

    const res = await app.request('/data', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: '{}',
    });
    expect(res.status).toBe(200);
  });

  test('signing not configured: all requests pass through', async () => {
    const app = buildApp(null);

    const res = await app.request('/data', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: '{}',
    });
    expect(res.status).toBe(200);
  });

  test('?b=2&a=1 and ?a=1&b=2 produce same canonical signature (through middleware)', async () => {
    const app = buildApp();
    const ts = String(Math.floor(Date.now() / 1000));

    // Canonical query for sorted ?a=1&b=2 is "a=1&b=2"
    const canonical = buildCanonical('POST', '/data', 'a=1&b=2', ts, '{}');
    const sig = sign(canonical);

    // Send with reversed order — middleware must canonicalize to the same string
    const res = await app.request('/data?b=2&a=1', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-signature': sig, 'x-timestamp': ts },
      body: '{}',
    });
    expect(res.status).toBe(200);
  });

  test('percent-encoding normalized: %20 and + produce same signature (through middleware)', async () => {
    const app = buildApp();
    const ts = String(Math.floor(Date.now() / 1000));

    // Canonical form of "hello world" is encodeURIComponent("hello world") = "hello%20world"
    const canonical = buildCanonical('POST', '/data', 'q=hello%20world', ts, '{}');
    const sig = sign(canonical);

    // Send with + encoding — middleware must normalize to %20
    const res = await app.request('/data?q=hello+world', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-signature': sig, 'x-timestamp': ts },
      body: '{}',
    });
    expect(res.status).toBe(200);
  });

  test('empty query string — canonical query is empty string, not omitted', async () => {
    const app = buildApp();
    const ts = String(Math.floor(Date.now() / 1000));

    // Without query params the canonical query line is "" — still present
    const canonical = buildCanonical('POST', '/data', '', ts, '{}');
    const sig = sign(canonical);

    const res = await app.request('/data', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-signature': sig, 'x-timestamp': ts },
      body: '{}',
    });
    expect(res.status).toBe(200);
  });

  test('missing timestamp header returns 401 EXPIRED_TIMESTAMP (line 82)', async () => {
    const app = buildApp();

    const res = await app.request('/data', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        // No x-timestamp header — parseInt(undefined) is NaN
        'x-signature': 'fakesig',
      },
      body: '{}',
    });
    expect(res.status).toBe(401);
    const json = await res.json();
    expect(json.code).toBe('EXPIRED_TIMESTAMP');
  });

  test('signing enabled but secret missing returns 500 SIGNING_SECRET_MISSING (line 100)', async () => {
    // Build an app with requestSigning enabled but no secret
    const app = buildApp({ requestSigning: true });
    const timestamp = String(Math.floor(Date.now() / 1000));

    const res = await app.request('/data', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-signature': 'fakesig',
        'x-timestamp': timestamp,
      },
      body: '{}',
    });
    expect(res.status).toBe(500);
    const json = await res.json();
    expect(json.code).toBe('SIGNING_SECRET_MISSING');
  });

  test('repeated key: sorted by value (?tag=b&tag=a canonicalizes to tag=a&tag=b)', async () => {
    const app = buildApp();
    const ts = String(Math.floor(Date.now() / 1000));

    const canonical = buildCanonical('POST', '/data', 'tag=a&tag=b', ts, '{}');
    const sig = sign(canonical);

    // Send reversed — middleware must sort by value too
    const res = await app.request('/data?tag=b&tag=a', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-signature': sig, 'x-timestamp': ts },
      body: '{}',
    });
    expect(res.status).toBe(200);
  });
});

