describe('SSE HTTP endpoint', () => {
  test('SSE endpoint responds with text/event-stream', async () => {
    const ssePlugin = {
      name: 'sse-http-test-plugin',
      async setupPost({ app }: { app: unknown }) {
        const { getContext } = await import('@lastshotlabs/slingshot-core');
        const ctx = getContext(app);
        ctx.bus.registerClientSafeEvents(['test:sse-http']);
      },
    };

    server = await createServer({
      ...baseConfig,
      hostname: '127.0.0.1',
      port: 0,
      plugins: [ssePlugin],
      sse: {
        endpoints: {
          '/__sse/http-test': {
            events: ['test:sse-http' as any],
          },
        },
      },
    });

    // Make an HTTP GET request to the SSE endpoint
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 2_000);
    try {
      const response = await fetch(`http://127.0.0.1:${server.port}/__sse/http-test`, {
        signal: controller.signal,
      });
      expect(response.headers.get('content-type')).toBe('text/event-stream');
      expect(response.headers.get('cache-control')).toBe('no-cache');
      // Close the stream
      controller.abort();
    } catch (e) {
      // AbortError is expected after we get headers
      if (e instanceof Error && e.name !== 'AbortError') throw e;
    } finally {
      clearTimeout(timeout);
    }
  });
});

