        userId,
        registrationToken,
        {
          id: 'cred-fail',
          rawId: 'cred-fail',
          response: { clientDataJSON: '', attestationObject: '' },
          clientExtensionResults: {},
          type: 'public-key',
        },
        getRuntime(),
      ),
    ).rejects.toThrow('WebAuthn registration verification failed');
  });
});

